    // UI language preference. The GitHub release provides three distribution packages.
    // Each package embeds its own first-launch default in
    // AICodingEditor_Default_Language.properties. A user may still change the language later.
    private static final String UI_LANGUAGE_PREFERENCE_KEY = "ui.language";
    private static final String UI_LANGUAGE_DISTRIBUTION_ID_PREFERENCE_KEY = "ui.language.distributionId";
    private static final String UI_LANGUAGE_ZH_TW = "zh-TW";
    private static final String UI_LANGUAGE_EN = "en";
    private static final String UI_LANGUAGE_ZH_CN = "zh-CN";
    private static final String UI_LANGUAGE_DISTRIBUTION_RESOURCE =
            "AICodingEditor_Default_Language.properties";
    private static final String DEFAULT_UI_LANGUAGE = loadDistributionDefaultUiLanguage();
    private static final String UI_LANGUAGE_DISTRIBUTION_ID = loadDistributionLanguageId();

    private static Properties loadDistributionLanguageProperties() {
        Properties properties = new Properties();
        try (InputStream input = AICodingEditor.class.getClassLoader()
                .getResourceAsStream(UI_LANGUAGE_DISTRIBUTION_RESOURCE)) {
            if (input != null) properties.load(input);
        } catch (IOException ignored) {
            // English is the safe public-release fallback when the resource is unavailable.
        }
        return properties;
    }

    private static String normalizeUiLanguage(String rawLanguage) {
        String normalized = rawLanguage == null ? "" : rawLanguage.trim();
        if (UI_LANGUAGE_ZH_TW.equalsIgnoreCase(normalized)) return UI_LANGUAGE_ZH_TW;
        if (UI_LANGUAGE_ZH_CN.equalsIgnoreCase(normalized)) return UI_LANGUAGE_ZH_CN;
        return UI_LANGUAGE_EN;
    }

    private static String loadDistributionDefaultUiLanguage() {
        return normalizeUiLanguage(loadDistributionLanguageProperties()
                .getProperty("default.ui.language", UI_LANGUAGE_EN));
    }

    private static String loadDistributionLanguageId() {
        String configured = loadDistributionLanguageProperties()
                .getProperty("distribution.language.id", "en-default")
                .trim();
        return configured.isBlank() ? "en-default" : configured;
    }

