    /** Converts the main Traditional-Chinese UI phrases to standard Simplified-Chinese UI wording. */
    private String toSimplifiedChinese(String source) {
        if (source == null || source.isEmpty()) return source;
        String result = source;
        for (Map.Entry<String, String> entry : TRADITIONAL_TO_SIMPLIFIED_PHRASES.entrySet()) {
            result = result.replace(entry.getKey(), entry.getValue());
        }
        StringBuilder converted = new StringBuilder(result.length());
        for (int i = 0; i < result.length(); i++) {
            converted.append(traditionalToSimplifiedCharacter(result.charAt(i)));
        }
        return converted.toString();
    }

    private char traditionalToSimplifiedCharacter(char c) {
        return switch (c) {
            case '檔' -> '档'; case '開' -> '开'; case '關' -> '关'; case '儲' -> '储';
            case '編' -> '编'; case '碼' -> '码'; case '轉' -> '转'; case '換' -> '换';
            case '檢' -> '检'; case '視' -> '视'; case '覺' -> '觉'; case '語' -> '语';
            case '體' -> '体'; case '臺' -> '台'; case '灣' -> '湾'; case '設' -> '设';
            case '網' -> '网'; case '頁' -> '页'; case '執' -> '执'; case '暫' -> '暂';
            case '繼' -> '继'; case '續' -> '续'; case '終' -> '终'; case '專' -> '专';
            case '業' -> '业'; case '務' -> '务'; case '項' -> '项'; case '選' -> '选';
            case '擇' -> '择'; case '確' -> '确'; case '認' -> '认'; case '顯' -> '显';
            case '說' -> '说'; case '書' -> '书'; case '圖' -> '图'; case '畫' -> '画';
            case '夾' -> '夹'; case '徑' -> '径'; case '瀏' -> '浏'; case '覽' -> '览';
            case '預' -> '预'; case '範' -> '范'; case '圍' -> '围'; case '於' -> '于';
            case '與' -> '与'; case '為' -> '为'; case '會' -> '会'; case '將' -> '将';
            case '從' -> '从'; case '複' -> '复'; case '製' -> '制'; case '貼' -> '贴';
            case '尋' -> '寻'; case '還' -> '还'; case '讀' -> '读'; case '寫' -> '写';
            case '僅' -> '仅'; case '許' -> '许'; case '輯' -> '辑'; case '啟' -> '启';
            case '動' -> '动'; case '軟' -> '软'; case '資' -> '资'; case '訊' -> '讯';
            case '記' -> '记'; case '錄' -> '录'; case '號' -> '号'; case '個' -> '个';
            case '應' -> '应'; case '當' -> '当'; case '點' -> '点'; case '擊' -> '击';
            case '處' -> '处'; case '雜' -> '杂'; case '錯' -> '错'; case '誤' -> '误';
            case '載' -> '载'; case '請' -> '请'; case '聯' -> '联'; case '絡' -> '络';
            case '發' -> '发'; case '測' -> '测'; case '試' -> '试'; case '權' -> '权';
            case '餘' -> '余'; default -> c;
        };
    }

