    /** Opens the HTML manual matching the current interface language. */
    private void showUserManual() {
        String fileName = UI_LANGUAGE_EN.equals(uiLanguage)
                ? "AICodingEditor_UserManual_en.html"
                : (UI_LANGUAGE_ZH_CN.equals(uiLanguage)
                        ? "AICodingEditor_UserManual_zh-CN.html"
                        : "AICodingEditor_UserManual_zh-TW.html");
        File manual = locateManualFile(fileName);
        if (manual == null || !manual.isFile()) {
            JOptionPane.showMessageDialog(this,
                    tr("找不到 HTML 使用說明書。請重新解壓完整發行包；程式也會自動嘗試使用 JAR 內建的說明書。",
                            "The HTML user manual was not found. Extract the complete release package; the app also attempts to use the manual bundled inside the JAR."),
                    tr("使用說明書", "User's Manual"), JOptionPane.WARNING_MESSAGE);
            return;
        }
        try {
            if (Desktop.isDesktopSupported() && Desktop.getDesktop().isSupported(Desktop.Action.BROWSE)) {
                Desktop.getDesktop().browse(manual.toURI());
            } else {
                throw new IOException("Desktop browser integration is unavailable.");
            }
        } catch (Exception ex) {
            JOptionPane.showMessageDialog(this,
                    tr("無法自動開啟瀏覽器。請直接以瀏覽器開啟：\n", "Unable to open the browser automatically. Open this file directly:\n")
                            + manual.getAbsolutePath() + "\n\n" + ex.getMessage(),
                    tr("使用說明書", "User's Manual"), JOptionPane.INFORMATION_MESSAGE);
        }
    }

    /**
     * Finds the language-specific HTML manual in external folders first, then
     * falls back to the copy bundled inside AICodingEditor.jar.
     */
    private File locateManualFile(String fileName) {
        for (File base : getDistributionBaseDirectories()) {
            if (base == null) continue;
            File parent = base.getParentFile();
            File[] candidates = new File[] {
                    new File(new File(base, BUNDLED_MANUALS_ROOT), fileName),
                    new File(base, fileName),
                    new File(new File(base, "docs"), fileName),
                    parent == null ? null : new File(new File(parent, BUNDLED_MANUALS_ROOT), fileName)
            };
            for (File candidate : candidates) {
                if (candidate != null && candidate.isFile()) return candidate;
            }
        }

        File bundledManuals = extractBundledResourceFolder(BUNDLED_MANUALS_ROOT, BUNDLED_MANUAL_FILES);
        File bundledCandidate = bundledManuals == null ? null : new File(bundledManuals, fileName);
        return bundledCandidate != null && bundledCandidate.isFile() ? bundledCandidate : null;
    }

    /** Returns likely folders containing the EXE/JAR distribution and source checkout. */
    private java.util.List<File> getDistributionBaseDirectories() {
        java.util.List<File> bases = new ArrayList<>();
        try {
            URI codeUri = AICodingEditor.class.getProtectionDomain()
                    .getCodeSource().getLocation().toURI();
            File codeLocation = new File(codeUri);
            File codeBase = codeLocation.isFile() ? codeLocation.getParentFile() : codeLocation;
            addUniqueDirectory(bases, codeBase);
        } catch (Exception ignored) { }
        addUniqueDirectory(bases, new File(System.getProperty("user.dir", ".")));
        return bases;
    }

    private void addUniqueDirectory(java.util.List<File> bases, File candidate) {
        if (candidate == null) return;
        try {
            File normalized = candidate.getCanonicalFile();
            for (File existing : bases) {
                if (existing.getCanonicalFile().equals(normalized)) return;
            }
            bases.add(normalized);
        } catch (IOException ex) {
            bases.add(candidate);
        }
    }

    /**
     * Extracts manual/example resources embedded in the application JAR into a
     * per-user cache.  It is used only when the external distribution folders
     * are absent, and preserves the required HTML-to-images relative paths.
     */
    private File extractBundledResourceFolder(String rootFolder, String[] relativePaths) {
        Path root = Paths.get(System.getProperty("user.home", "."),
                ".aicodingeditor", "bundled-resources", APP_VERSION, rootFolder);
        int extracted = 0;
        for (String relativePath : relativePaths) {
            String resourcePath = "/" + rootFolder + "/" + relativePath.replace('\\', '/');
            try (InputStream input = AICodingEditor.class.getResourceAsStream(resourcePath)) {
                if (input == null) continue;
                Path destination = root.resolve(relativePath.replace('\\', File.separatorChar));
                Files.createDirectories(destination.getParent());
                Files.copy(input, destination, StandardCopyOption.REPLACE_EXISTING);
                extracted++;
            } catch (IOException ignored) {
                // Continue checking the remaining resources. The caller shows a friendly
                // message only when no usable destination can be located.
            }
        }
        return extracted > 0 ? root.toFile() : null;
    }

    /** Opens the external Examples folder or the built-in extracted fallback. */
    private void openExampleFilesFolder() {
        File examples = locateExamplesDirectory();
        if (examples == null || !examples.isDirectory()) {
            JOptionPane.showMessageDialog(this,
                    tr("找不到範例程式資料夾。請確認 Examples 資料夾位於 EXE / JAR 同一個資料夾，或重新解壓完整發行包。",
                            "The example files folder was not found. Keep Examples beside the EXE / JAR or extract the complete release package."),
                    tr("範例程式", "Examples"), JOptionPane.WARNING_MESSAGE);
            return;
        }
        try {
            if (Desktop.isDesktopSupported() && Desktop.getDesktop().isSupported(Desktop.Action.OPEN)) {
                Desktop.getDesktop().open(examples);
            } else {
                throw new IOException("Desktop folder integration is unavailable.");
            }
        } catch (Exception ex) {
            JOptionPane.showMessageDialog(this,
                    tr("無法自動開啟範例資料夾。請手動開啟：\n", "Unable to open the examples folder automatically. Open it manually:\n")
                            + examples.getAbsolutePath() + "\n\n" + ex.getMessage(),
                    tr("範例程式", "Examples"), JOptionPane.INFORMATION_MESSAGE);
        }
    }

    private File locateExamplesDirectory() {
        for (File base : getDistributionBaseDirectories()) {
            if (base == null) continue;
            File parent = base.getParentFile();
            File[] candidates = new File[] {
                    new File(base, BUNDLED_EXAMPLES_ROOT),
                    parent == null ? null : new File(parent, BUNDLED_EXAMPLES_ROOT)
            };
            for (File candidate : candidates) {
                if (candidate != null && candidate.isDirectory()) return candidate;
            }
        }
        return extractBundledResourceFolder(BUNDLED_EXAMPLES_ROOT, BUNDLED_EXAMPLE_FILES);
    }


