    // V0.2.37 AI Assistant: OpenAI + Gemini
    // =====================================================================

    private enum AiAction {
        CHAT("CHAT"),
        EXPLAIN_CODE("EXPLAIN_CODE"),
        FIX_ERROR("FIX_ERROR"),
        GENERATE_CODE("GENERATE_CODE"),
        REVIEW_CODE("REVIEW_CODE");

        private final String id;
        AiAction(String id) { this.id = id; }
    }

    private record AiApiResult(boolean success, String provider, String text, String detail) {}

    private class AiPatchCandidate {
        private final EditorTab targetTab;
        private final String originalText;
        private final String proposedText;
        private final String sourceLabel;
        private final AiAction action;

        AiPatchCandidate(EditorTab targetTab, String originalText, String proposedText,
                         String sourceLabel, AiAction action) {
            this.targetTab = targetTab;
            this.originalText = originalText == null ? "" : originalText;
            this.proposedText = proposedText == null ? "" : proposedText;
            this.sourceLabel = sourceLabel == null ? "untitled" : sourceLabel;
            this.action = action;
        }
    }


    /**
     * A code result that may be written as a new file only after the user has
     * selected a path, reviewed the preview/diff, and explicitly confirmed.
     * The raw result is never written automatically when an AI response arrives.
     */
    private class AiGeneratedFileCandidate {
        private final String rawCode;
        private final String languageHint;
        private final String suggestedFileName;
        private final String sourceLabel;
        private final EditorTab requestTab;

        AiGeneratedFileCandidate(String rawCode, String languageHint, String suggestedFileName,
                                 String sourceLabel, EditorTab requestTab) {
            this.rawCode = rawCode == null ? "" : rawCode;
            this.languageHint = languageHint == null ? "" : languageHint;
            this.suggestedFileName = suggestedFileName == null ? "AI_Generated.txt" : suggestedFileName;
            this.sourceLabel = sourceLabel == null ? "AI response" : sourceLabel;
            this.requestTab = requestTab;
        }
    }

    /** Data prepared for the exact extension selected in the Save dialog. */
    private record AiGeneratedFilePayload(String fileContent, String editorPreviewText,
                                          boolean notebook) {}

    private void loadAiPreferences() {
        String savedMode = preferences.get(AI_PROVIDER_PREFERENCE_KEY, AI_PROVIDER_ASK);
        aiProviderMode = normalizeAiProvider(savedMode);
        aiDefaultAction = normalizeAiAction(preferences.get(AI_DEFAULT_ACTION_PREFERENCE_KEY, AiAction.CHAT.id));
        // A V0.2.37 installation that already has encrypted local keys retains its
        // old behavior until the user deliberately selects Environment Variable.
        aiOpenAiKeySource = loadAiKeySource(AI_PROVIDER_OPENAI);
        aiGeminiKeySource = loadAiKeySource(AI_PROVIDER_GEMINI);
        aiOpenAiEnvironmentVariable = normalizeAiEnvironmentVariable(
                preferences.get(AI_OPENAI_ENVIRONMENT_VARIABLE_PREFERENCE_KEY, DEFAULT_OPENAI_ENVIRONMENT_VARIABLE),
                DEFAULT_OPENAI_ENVIRONMENT_VARIABLE);
        aiGeminiEnvironmentVariable = normalizeAiEnvironmentVariable(
                preferences.get(AI_GEMINI_ENVIRONMENT_VARIABLE_PREFERENCE_KEY, DEFAULT_GEMINI_ENVIRONMENT_VARIABLE),
                DEFAULT_GEMINI_ENVIRONMENT_VARIABLE);
        aiOpenAiModel = normalizeAiModel(preferences.get(AI_OPENAI_MODEL_PREFERENCE_KEY, DEFAULT_OPENAI_MODEL), DEFAULT_OPENAI_MODEL);
        aiGeminiModel = normalizeAiModel(preferences.get(AI_GEMINI_MODEL_PREFERENCE_KEY, DEFAULT_GEMINI_MODEL), DEFAULT_GEMINI_MODEL);
        aiSendSelection = preferences.getBoolean(AI_SEND_SELECTION_PREFERENCE_KEY, true);
        aiSendCurrentFile = preferences.getBoolean(AI_SEND_CURRENT_FILE_PREFERENCE_KEY, true);
        aiSendConsoleError = preferences.getBoolean(AI_SEND_CONSOLE_ERROR_PREFERENCE_KEY, true);
        aiFullProjectScan = preferences.getBoolean(AI_FULL_PROJECT_SCAN_PREFERENCE_KEY, false);
        aiAutoRun = preferences.getBoolean(AI_AUTO_RUN_PREFERENCE_KEY, false);
        aiAutoInstallPackages = preferences.getBoolean(AI_AUTO_INSTALL_PREFERENCE_KEY, false);
        aiDockVisible = preferences.getBoolean(AI_DOCK_VISIBLE_PREFERENCE_KEY, true);
    }

    private String loadAiKeySource(String provider) {
        String saved = preferences.get(aiKeySourcePreferenceKey(provider), "");
        if (saved == null || saved.isBlank()) {
            // Preserve an existing V0.2.37 encrypted key; otherwise default safely to env.
            return hasStoredAiApiKey(provider) ? AI_KEY_SOURCE_ENCRYPTED_PREFERENCES : AI_KEY_SOURCE_ENVIRONMENT;
        }
        return normalizeAiKeySource(saved);
    }

    private String normalizeAiKeySource(String value) {
        if (AI_KEY_SOURCE_ENCRYPTED_PREFERENCES.equalsIgnoreCase(value)) return AI_KEY_SOURCE_ENCRYPTED_PREFERENCES;
        return AI_KEY_SOURCE_ENVIRONMENT;
    }

    private String aiKeySourcePreferenceKey(String provider) {
        return AI_PROVIDER_OPENAI.equals(provider)
                ? AI_OPENAI_KEY_SOURCE_PREFERENCE_KEY : AI_GEMINI_KEY_SOURCE_PREFERENCE_KEY;
    }

    private String aiEnvironmentVariablePreferenceKey(String provider) {
        return AI_PROVIDER_OPENAI.equals(provider)
                ? AI_OPENAI_ENVIRONMENT_VARIABLE_PREFERENCE_KEY : AI_GEMINI_ENVIRONMENT_VARIABLE_PREFERENCE_KEY;
    }

    private String aiKeySourceForProvider(String provider) {
        return AI_PROVIDER_OPENAI.equals(provider) ? aiOpenAiKeySource : aiGeminiKeySource;
    }

    private String aiEnvironmentVariableForProvider(String provider) {
        return AI_PROVIDER_OPENAI.equals(provider) ? aiOpenAiEnvironmentVariable : aiGeminiEnvironmentVariable;
    }

    private String normalizeAiEnvironmentVariable(String value, String fallback) {
        String normalized = value == null ? "" : value.trim();
        return isValidAiEnvironmentVariableName(normalized) ? normalized : fallback;
    }

    private boolean isValidAiEnvironmentVariableName(String value) {
        return value != null && value.matches("[A-Za-z_][A-Za-z0-9_]*");
    }

    private String aiKeySourceDisplay(String source) {
        return AI_KEY_SOURCE_ENCRYPTED_PREFERENCES.equals(normalizeAiKeySource(source))
                ? tr("加密本機儲存（Java Preferences）", "Encrypted local storage (Java Preferences)")
                : tr("環境變數（建議）", "Environment variable (recommended)");
    }

    private String aiKeySourceFromDisplay(Object selected) {
        String text = selected == null ? "" : selected.toString();
        if (text.equals(aiKeySourceDisplay(AI_KEY_SOURCE_ENCRYPTED_PREFERENCES))) {
            return AI_KEY_SOURCE_ENCRYPTED_PREFERENCES;
        }
        return AI_KEY_SOURCE_ENVIRONMENT;
    }

    private boolean isAiEnvironmentKeySource(String source) {
        return AI_KEY_SOURCE_ENVIRONMENT.equals(normalizeAiKeySource(source));
    }

    private boolean hasStoredAiApiKey(String provider) {
        String stored = preferences.get(aiSecretPreferenceKey(provider), "");
        return stored != null && !stored.isBlank();
    }


    private String normalizeAiProvider(String value) {
        if (AI_PROVIDER_OPENAI.equalsIgnoreCase(value)) return AI_PROVIDER_OPENAI;
        if (AI_PROVIDER_GEMINI.equalsIgnoreCase(value)) return AI_PROVIDER_GEMINI;
        return AI_PROVIDER_ASK;
    }

    private String normalizeAiModel(String value, String fallback) {
        String normalized = value == null ? "" : value.trim();
        return normalized.isEmpty() ? fallback : normalized;
    }

    private String aiProviderDisplay(String provider) {
        return switch (normalizeAiProvider(provider)) {
            case AI_PROVIDER_OPENAI -> "OpenAI";
            case AI_PROVIDER_GEMINI -> "Gemini";
            default -> tr("每次詢問", "Ask Every Time");
        };
    }

    private String aiProviderFromDisplay(Object selected) {
        String text = selected == null ? "" : selected.toString();
        if ("OpenAI".equalsIgnoreCase(text)) return AI_PROVIDER_OPENAI;
        if ("Gemini".equalsIgnoreCase(text)) return AI_PROVIDER_GEMINI;
        return AI_PROVIDER_ASK;
    }

    private String aiActionDisplay(AiAction action) {
        return switch (action) {
            case CHAT -> tr("聊天 / 詢問", "Chat / Ask");
            case EXPLAIN_CODE -> tr("解釋程式碼", "Explain Code");
            case FIX_ERROR -> tr("修正錯誤", "Fix Error");
            case GENERATE_CODE -> tr("產生程式碼", "Generate Code");
            case REVIEW_CODE -> tr("程式碼審查", "Review Code");
        };
    }

    private AiAction aiActionFromDisplay(Object selected) {
        String text = selected == null ? "" : selected.toString();
        for (AiAction action : AiAction.values()) {
            if (aiActionDisplay(action).equals(text)) return action;
        }
        return AiAction.CHAT;
    }


    private AiAction normalizeAiAction(String value) {
        if (value != null) {
            for (AiAction action : AiAction.values()) {
                if (action.id.equalsIgnoreCase(value.trim())) return action;
            }
        }
        return AiAction.CHAT;
    }

    private AiAction currentAiAction() {
        Object selected = aiActionComboBox.getSelectedItem();
        return selected == null ? aiDefaultAction : aiActionFromDisplay(selected);
    }

    /** Synchronizes the hidden action model, Settings dialog value, and dock icons. */
    private void selectAiAction(AiAction action, boolean persist) {
        aiDefaultAction = action == null ? AiAction.CHAT : action;
        if (aiActionComboBox.getItemCount() > 0) {
            aiActionComboBox.setSelectedItem(aiActionDisplay(aiDefaultAction));
        }
        updateAiActionButtonVisuals();
        updateAiContextStatus();
        if (persist) saveAiPreferences();
    }

    private JButton createAiActionIconButton(AiAction action, String iconText) {
        JButton button = new JButton(iconText);
        button.setToolTipText(tr("AI 功能：", "AI action: ") + aiActionDisplay(action));
        button.getAccessibleContext().setAccessibleName(aiActionDisplay(action));
        styleAiFunctionIconButton(button);
        button.addActionListener(e -> {
            selectAiAction(action, true);
            if (aiPromptArea.getText().isBlank() && action != AiAction.CHAT) {
                aiPromptArea.setText(defaultAiInstruction(action));
            }
            aiPromptArea.requestFocusInWindow();
        });
        aiActionButtons.put(action, button);
        return button;
    }

    /** Highlights the currently selected AI function without showing a large select list. */
    private void updateAiActionButtonVisuals() {
        for (Map.Entry<AiAction, JButton> entry : aiActionButtons.entrySet()) {
            JButton button = entry.getValue();
            boolean selected = entry.getKey() == aiDefaultAction;
            button.setBackground(selected ? new Color(0, 91, 150) : APP_MENU_ITEM_BACKGROUND);
            button.setForeground(Color.WHITE);
            button.setBorder(BorderFactory.createCompoundBorder(
                    BorderFactory.createLineBorder(selected ? new Color(113, 208, 255) : APP_BORDER_COLOR),
                    BorderFactory.createEmptyBorder(1, 1, 1, 1)));
            button.repaint();
        }
    }

    private JComponent createAiActionSeparator() {
        JSeparator separator = new JSeparator(SwingConstants.VERTICAL);
        separator.setForeground(APP_BORDER_COLOR);
        separator.setBackground(APP_BORDER_COLOR);
        separator.setPreferredSize(new Dimension(1, 22));
        separator.setMaximumSize(new Dimension(1, 22));
        return separator;
    }

    private void saveAiPreferences() {
        preferences.put(AI_PROVIDER_PREFERENCE_KEY, aiProviderMode);
        preferences.put(AI_DEFAULT_ACTION_PREFERENCE_KEY, aiDefaultAction.id);
        preferences.put(AI_OPENAI_KEY_SOURCE_PREFERENCE_KEY, aiOpenAiKeySource);
        preferences.put(AI_GEMINI_KEY_SOURCE_PREFERENCE_KEY, aiGeminiKeySource);
        preferences.put(AI_OPENAI_ENVIRONMENT_VARIABLE_PREFERENCE_KEY, aiOpenAiEnvironmentVariable);
        preferences.put(AI_GEMINI_ENVIRONMENT_VARIABLE_PREFERENCE_KEY, aiGeminiEnvironmentVariable);
        preferences.put(AI_OPENAI_MODEL_PREFERENCE_KEY, aiOpenAiModel);
        preferences.put(AI_GEMINI_MODEL_PREFERENCE_KEY, aiGeminiModel);
        preferences.putBoolean(AI_SEND_SELECTION_PREFERENCE_KEY, aiSendSelection);
        preferences.putBoolean(AI_SEND_CURRENT_FILE_PREFERENCE_KEY, aiSendCurrentFile);
        preferences.putBoolean(AI_SEND_CONSOLE_ERROR_PREFERENCE_KEY, aiSendConsoleError);
        preferences.putBoolean(AI_FULL_PROJECT_SCAN_PREFERENCE_KEY, aiFullProjectScan);
        preferences.putBoolean(AI_AUTO_RUN_PREFERENCE_KEY, aiAutoRun);
        preferences.putBoolean(AI_AUTO_INSTALL_PREFERENCE_KEY, aiAutoInstallPackages);
        preferences.putBoolean(AI_DOCK_VISIBLE_PREFERENCE_KEY, aiDockVisible);
    }

