        JPanel footer = new JPanel(new BorderLayout(5, 3));
        footer.setBackground(APP_MENU_BACKGROUND);
        footer.setBorder(BorderFactory.createEmptyBorder(3, 8, 6, 8));
        JPanel statusPanel = new JPanel();
        statusPanel.setBackground(APP_MENU_BACKGROUND);
        statusPanel.setLayout(new BoxLayout(statusPanel, BoxLayout.Y_AXIS));
        aiContextStatusLabel.setForeground(new Color(185, 215, 255));
        aiSafetyStatusLabel.setForeground(new Color(255, 216, 140));
        aiContextStatusLabel.setFont(aiContextStatusLabel.getFont().deriveFont(10f));
        aiSafetyStatusLabel.setFont(aiSafetyStatusLabel.getFont().deriveFont(10f));
        aiContextStatusLabel.setToolTipText(tr("本次 AI 請求會傳送的 Context。可在 AI Settings 修改。", "Context that will be sent with the next AI request. Change it in AI Settings."));
        aiSafetyStatusLabel.setToolTipText(tr("安全規則：Patch 與新檔均需預覽及明確確認。", "Safety rule: patches and new files require preview and explicit confirmation."));
        statusPanel.add(aiContextStatusLabel);
        statusPanel.add(aiSafetyStatusLabel);
        footer.add(statusPanel, BorderLayout.CENTER);
        aiAssistantPanel.add(footer, BorderLayout.SOUTH);

