    private String currentAiTitleText() {
        String provider = normalizeAiProvider(aiProviderMode);
        if (AI_PROVIDER_ASK.equals(provider) && aiLastRequestProvider != null && !aiLastRequestProvider.isBlank()) {
            provider = normalizeAiProvider(aiLastRequestProvider);
        }
        if (AI_PROVIDER_GEMINI.equals(provider)) {
            return " AI Assistant | Gemini: " + aiGeminiModel;
        }
        if (AI_PROVIDER_OPENAI.equals(provider)) {
            return " AI Assistant | " + openAiDisplayModelName(aiOpenAiModel);
        }
        return tr(" AI Assistant | 每次詢問 Provider", " AI Assistant | Ask Every Time");
    }

    private String currentAiTitleToolTip() {
        return tr("目前 AI Provider / Model；可按齒輪變更。",
                "Current AI provider / model; click the gear to change it.") + " "
                + "OpenAI=" + aiOpenAiModel + ", Gemini=" + aiGeminiModel;
    }

    private String openAiDisplayModelName(String model) {
        String normalized = normalizeAiModel(model, DEFAULT_OPENAI_MODEL);
        String lower = normalized.toLowerCase(Locale.ROOT);
        if (lower.startsWith("gpt-")) {
            return "ChatGPT " + normalized.substring(4).replace('-', ' ');
        }
        return "OpenAI: " + normalized;
    }

