    private void openAiAssistant() {
        setAiAssistantVisible(true);
        aiPromptArea.requestFocusInWindow();
    }

    private void setAiAssistantVisible(boolean visible) {
        if (!visible && aiAssistantDetached) {
            aiDockVisible = false;
            preferences.putBoolean(AI_DOCK_VISIBLE_PREFERENCE_KEY, false);
            reattachFullAiAssistantPanel();
            return;
        }
        if (visible && aiAssistantDetached) {
            if (aiDetachedDialog != null) {
                aiDetachedDialog.toFront();
                aiDetachedDialog.requestFocus();
            }
            return;
        }
        aiDockVisible = visible;
        preferences.putBoolean(AI_DOCK_VISIBLE_PREFERENCE_KEY, visible);
        if (visible) {
            aiWorkspaceSplitPane.setRightComponent(aiAssistantPanel);
            aiAssistantPanel.setVisible(true);
            SwingUtilities.invokeLater(() -> aiWorkspaceSplitPane.setDividerLocation(
                    Math.max(500, getWidth() - Math.max(350, getWidth() / 4))));
        } else {
            aiAssistantPanel.setVisible(false);
            aiWorkspaceSplitPane.setRightComponent(aiDockPlaceholder);
            SwingUtilities.invokeLater(() -> aiWorkspaceSplitPane.setDividerLocation(1.0));
        }
        aiWorkspaceSplitPane.revalidate();
        aiWorkspaceSplitPane.repaint();
    }

    private void runAiMenuAction(AiAction action) {
        openAiAssistant();
        selectAiAction(action, true);
        if (aiPromptArea.getText().isBlank()) {
            aiPromptArea.setText(defaultAiInstruction(action));
        }
        if (action != AiAction.CHAT) sendAiRequestFromPanel();
        else aiPromptArea.requestFocusInWindow();
    }

    private String defaultAiInstruction(AiAction action) {
        return switch (action) {
            case EXPLAIN_CODE -> tr("請解釋目前程式碼的功能、資料流程與可能風險。", "Explain the selected/current code, its data flow, and potential risks.");
            case FIX_ERROR -> tr("請根據 Console Error 找出根本原因並提出最小、安全的修正。", "Use the console error to identify the root cause and propose the smallest safe fix.");
            case GENERATE_CODE -> tr("請產生符合目前檔案語言與架構的程式碼。", "Generate code that fits the language and structure of the current file.");
            case REVIEW_CODE -> tr("請審查目前程式碼的正確性、可維護性、安全性與效能。", "Review the current code for correctness, maintainability, safety, and performance.");
            default -> "";
        };
    }

