    private void installAiPromptEditingSupport() {
        // V0.2.37-24: install explicit clipboard actions.  A custom TransferHandler
        // is used for file/folder drops, so relying only on DefaultEditorKit can fail
        // on some Windows Look & Feel / IME combinations.  These actions keep normal
        // text copy/paste independent from the file-drop handler.
        Action cutAction = new AbstractAction() {
            @Override public void actionPerformed(ActionEvent e) { aiPromptCutToClipboard(); }
        };
        Action copyAction = new AbstractAction() {
            @Override public void actionPerformed(ActionEvent e) { aiPromptCopyToClipboard(); }
        };
        Action pasteAction = new AbstractAction() {
            @Override public void actionPerformed(ActionEvent e) { aiPromptPasteFromClipboard(); }
        };
        Action selectAllAction = new AbstractAction() {
            @Override public void actionPerformed(ActionEvent e) { aiPromptArea.requestFocusInWindow(); aiPromptArea.selectAll(); }
        };
        aiPromptArea.getActionMap().put("aice-prompt-cut", cutAction);
        aiPromptArea.getActionMap().put("aice-prompt-copy", copyAction);
        aiPromptArea.getActionMap().put("aice-prompt-paste", pasteAction);
        aiPromptArea.getActionMap().put("aice-prompt-select-all", selectAllAction);
        InputMap im = aiPromptArea.getInputMap(JComponent.WHEN_FOCUSED);
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_X, InputEvent.CTRL_DOWN_MASK), "aice-prompt-cut");
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_C, InputEvent.CTRL_DOWN_MASK), "aice-prompt-copy");
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_V, InputEvent.CTRL_DOWN_MASK), "aice-prompt-paste");
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_A, InputEvent.CTRL_DOWN_MASK), "aice-prompt-select-all");
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_INSERT, InputEvent.SHIFT_DOWN_MASK), "aice-prompt-paste");
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_INSERT, InputEvent.CTRL_DOWN_MASK), "aice-prompt-copy");
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_DELETE, InputEvent.SHIFT_DOWN_MASK), "aice-prompt-cut");

        JPopupMenu menu = new JPopupMenu();
        JMenuItem cut = new JMenuItem(tr("剪下", "Cut"));
        JMenuItem copy = new JMenuItem(tr("複製", "Copy"));
        JMenuItem paste = new JMenuItem(tr("貼上", "Paste"));
        JMenuItem selectAll = new JMenuItem(tr("全選", "Select All"));
        cut.addActionListener(cutAction);
        copy.addActionListener(copyAction);
        paste.addActionListener(pasteAction);
        selectAll.addActionListener(selectAllAction);
        for (JMenuItem item : java.util.List.of(cut, copy, paste, selectAll)) menu.add(item);
        styleNavigationTreePopupMenu(menu);
        aiPromptArea.setComponentPopupMenu(menu);
    }

    private void aiPromptCopyToClipboard() {
        String selected = aiPromptArea.getSelectedText();
        if (selected == null) selected = "";
        Toolkit.getDefaultToolkit().getSystemClipboard().setContents(
                new java.awt.datatransfer.StringSelection(selected), null);
    }

    private void aiPromptCutToClipboard() {
        aiPromptCopyToClipboard();
        aiPromptArea.replaceSelection("");
    }

    private void aiPromptPasteFromClipboard() {
        try {
            Transferable t = Toolkit.getDefaultToolkit().getSystemClipboard().getContents(null);
            if (t == null) return;
            if (t.isDataFlavorSupported(DataFlavor.imageFlavor)) {
                Object imageObject = t.getTransferData(DataFlavor.imageFlavor);
                File imageFile = saveClipboardImageForAiAttachment(imageObject);
                if (imageFile != null) {
                    attachFilesToAi(java.util.List.of(imageFile));
                    aiSafetyStatusLabel.setText(tr("已從剪貼簿貼上圖片並加入 AI 附件；按送出時才讀取。",
                            "Pasted an image from the clipboard into AI attachments; it will be read only when Send is clicked."));
                    return;
                }
            }
            if (t.isDataFlavorSupported(DataFlavor.stringFlavor)) {
                String text = (String) t.getTransferData(DataFlavor.stringFlavor);
                aiPromptArea.replaceSelection(text == null ? "" : text);
            }
        } catch (Exception ex) {
            Toolkit.getDefaultToolkit().beep();
            aiSafetyStatusLabel.setText(tr("剪貼簿貼上失敗：", "Clipboard paste failed: ") + cleanAiExceptionMessage(ex));
        }
    }

    /** Saves a clipboard image as a temporary PNG so the existing AI image-attachment pipeline can send it safely. */
    private File saveClipboardImageForAiAttachment(Object imageObject) throws IOException {
        if (!(imageObject instanceof Image image)) return null;
        BufferedImage buffered;
        if (image instanceof BufferedImage bi) {
            buffered = bi;
        } else {
            int w = Math.max(1, image.getWidth(null));
            int h = Math.max(1, image.getHeight(null));
            buffered = new BufferedImage(w, h, BufferedImage.TYPE_INT_ARGB);
            Graphics2D g = buffered.createGraphics();
            try {
                g.drawImage(image, 0, 0, null);
            } finally {
                g.dispose();
            }
        }
        File dir = new File(System.getProperty("java.io.tmpdir"), "AICodingEditor_AI_Clipboard_Images");
        if (!dir.exists() && !dir.mkdirs()) throw new IOException("Cannot create clipboard image temp folder: " + dir);
        File file = new File(dir, "clipboard_image_" + System.currentTimeMillis() + "_" + Math.abs(new SecureRandom().nextInt()) + ".png");
        ImageIO.write(buffered, "png", file);
        file.deleteOnExit();
        return file;
    }

    private void showAiPopOutWindow() {
        // V0.2.37-25: This is a true detach of the full AI Assistant panel.
        // The same Swing components are moved into a floating dialog, so the
        // user keeps all AI actions, attachment controls, generated-file list,
        // settings gear, context indicators, and prompt copy/paste behavior.
        if (aiAssistantDetached && aiDetachedDialog != null && aiDetachedDialog.isDisplayable()) {
            aiDetachedDialog.setTitle(currentAiTitleText().trim());
            aiDetachedDialog.setVisible(true);
            aiDetachedDialog.toFront();
            aiDetachedDialog.requestFocus();
            aiPromptArea.requestFocusInWindow();
            return;
        }
        detachFullAiAssistantPanel();
    }

    private void detachFullAiAssistantPanel() {
        aiDockVisible = true;
        preferences.putBoolean(AI_DOCK_VISIBLE_PREFERENCE_KEY, true);

        aiAssistantDetached = true;
        aiWorkspaceSplitPane.setRightComponent(aiDockPlaceholder);
        aiDockPlaceholder.setPreferredSize(new Dimension(0, 0));
        aiDockPlaceholder.setMinimumSize(new Dimension(0, 0));
        aiWorkspaceSplitPane.revalidate();
        aiWorkspaceSplitPane.repaint();
        SwingUtilities.invokeLater(() -> aiWorkspaceSplitPane.setDividerLocation(1.0));

        JDialog dialog = new JDialog(this, currentAiTitleText().trim(), false);
        aiDetachedDialog = dialog;
        dialog.setDefaultCloseOperation(WindowConstants.DO_NOTHING_ON_CLOSE);
        dialog.setLayout(new BorderLayout(6, 6));
        int w = Math.max(640, Math.min(980, Math.max(1, getWidth()) * 2 / 3));
        int h = Math.max(620, Math.min(980, Math.max(1, getHeight()) - 70));
        dialog.setSize(w, h);
        dialog.setLocationRelativeTo(this);
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        dialog.add(aiAssistantPanel, BorderLayout.CENTER);
        applyDarkContainerTheme(dialog.getContentPane());
        restoreAiAssistantControlStyles();
        dialog.addWindowListener(new WindowAdapter() {
            @Override public void windowClosing(WindowEvent e) {
                reattachFullAiAssistantPanel();
            }
            @Override public void windowClosed(WindowEvent e) {
                if (aiAssistantDetached) reattachFullAiAssistantPanel();
            }
        });
        dialog.setVisible(true);
        aiAssistantPanel.revalidate();
        aiAssistantPanel.repaint();
        aiPromptArea.requestFocusInWindow();
    }

    private void reattachFullAiAssistantPanel() {
        JDialog dialog = aiDetachedDialog;
        aiDetachedDialog = null;
        aiAssistantDetached = false;
        if (dialog != null) {
            dialog.getContentPane().remove(aiAssistantPanel);
            dialog.dispose();
        }
        if (aiDockVisible) {
            aiWorkspaceSplitPane.setRightComponent(aiAssistantPanel);
            aiAssistantPanel.setVisible(true);
            SwingUtilities.invokeLater(() -> aiWorkspaceSplitPane.setDividerLocation(
                    Math.max(500, getWidth() - Math.max(350, getWidth() / 4))));
        } else {
            aiWorkspaceSplitPane.setRightComponent(aiDockPlaceholder);
            aiAssistantPanel.setVisible(false);
            SwingUtilities.invokeLater(() -> aiWorkspaceSplitPane.setDividerLocation(1.0));
        }
        aiWorkspaceSplitPane.revalidate();
        aiWorkspaceSplitPane.repaint();
        aiAssistantPanel.revalidate();
        aiAssistantPanel.repaint();
    }


