    private void clearAiGeneratedFileCandidates() {
        aiGeneratedFileCandidates.clear();
        aiGeneratedFileCandidate = null;
        refreshAiGeneratedFilesPanel();
    }

    private void refreshAiGeneratedFilesPanel() {
        if (aiGeneratedFilesPanel == null) return;
        aiGeneratedFilesPanel.removeAll();
        if (aiGeneratedFileCandidates.isEmpty()) {
            aiGeneratedFilesPanel.setVisible(false);
        } else {
            aiGeneratedFilesPanel.setLayout(new BorderLayout(3, 2));
            JPanel header = new JPanel(new BorderLayout(3, 0));
            header.setOpaque(true);
            header.setBackground(APP_MENU_BACKGROUND);
            JLabel label = new JLabel(tr("AI 可建立檔案（勾選即建立）：", "AI creatable files (tick to create):"));
            label.setForeground(new Color(255, 230, 145));
            label.setFont(label.getFont().deriveFont(Font.BOLD));
            header.add(label, BorderLayout.WEST);
            File folder = defaultAiGeneratedFileDirectory(aiGeneratedFileCandidates.get(0));
            JLabel target = new JLabel(tr("目標：", "Target: ") + folder.getAbsolutePath());
            target.setForeground(new Color(190, 220, 255));
            target.setToolTipText(folder.getAbsolutePath());
            header.add(target, BorderLayout.CENTER);
            aiGeneratedFilesPanel.add(header, BorderLayout.NORTH);

            JPanel list = new JPanel(new FlowLayout(FlowLayout.LEFT, 5, 1));
            list.setOpaque(true);
            list.setBackground(APP_MENU_BACKGROUND);
            for (AiGeneratedFileCandidate candidate : aiGeneratedFileCandidates) {
                JCheckBox box = new JCheckBox("☐ " + candidate.suggestedFileName);
                box.setOpaque(true);
                box.setBackground(new Color(28, 28, 28));
                box.setForeground(Color.WHITE);
                box.setBorder(BorderFactory.createCompoundBorder(
                        BorderFactory.createLineBorder(new Color(80, 120, 160)),
                        BorderFactory.createEmptyBorder(2, 4, 2, 4)));
                box.setToolTipText(tr("勾選後直接建立到目前目錄：", "Tick to create directly in the current folder: ") + candidate.suggestedFileName);
                box.addActionListener(e -> {
                    if (box.isSelected()) createAiGeneratedFileInCurrentDirectory(candidate, box);
                });
                list.add(box);
            }
            aiGeneratedFilesPanel.add(list, BorderLayout.CENTER);
            aiGeneratedFilesPanel.setVisible(true);
        }
        aiGeneratedFilesPanel.revalidate();
        aiGeneratedFilesPanel.repaint();
    }

    private void createAiGeneratedFileInCurrentDirectory(AiGeneratedFileCandidate candidate, JCheckBox sourceBox) {
        if (candidate == null) return;
        if (!requireTrialWriteBuildAccess("Create AI Generated File")) {
            if (sourceBox != null) sourceBox.setSelected(false);
            return;
        }
        File folder = defaultAiGeneratedFileDirectory(candidate);
        File target = new File(folder, candidate.suggestedFileName);
        try {
            AiGeneratedFilePayload payload = prepareAiGeneratedFilePayload(candidate, target);
            File canonical = target.getCanonicalFile();
            if (canonical.exists()) {
                if (sourceBox != null) sourceBox.setSelected(false);
                showAiGeneratedFilePreview(canonical, payload);
                return;
            }
            File parent = canonical.getParentFile();
            if (parent != null) Files.createDirectories(parent.toPath());
            Files.writeString(canonical.toPath(), payload.fileContent(), StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE_NEW, StandardOpenOption.WRITE);
            updateOrOpenAiGeneratedFile(canonical, payload);
            if (sourceBox != null) {
                sourceBox.setEnabled(false);
                sourceBox.setText("✓ " + candidate.suggestedFileName);
            }
            appendAiConversation("SYSTEM", tr("AI 新檔已建立於目前目錄：", "AI-generated file created in the current folder: ")
                    + canonical.getAbsolutePath() + tr("\n檔案未自動執行或安裝套件。", "\nThe file was not automatically run and no packages were installed."));
            aiSafetyStatusLabel.setText(tr("AI 新檔已建立並開啟；請自行檢查後再執行。", "AI-generated file created and opened; review it before running."));
        } catch (IOException ex) {
            if (sourceBox != null) sourceBox.setSelected(false);
            JOptionPane.showMessageDialog(this,
                    tr("建立 AI 新檔失敗：\n", "Failed to create the AI-generated file:\n") + ex.getMessage(),
                    tr("建立 AI 新檔", "Create AI New File"), JOptionPane.ERROR_MESSAGE);
        }
    }

    private void sendAiRequestFromPanel() {
        if (aiRequestInProgress) return;
        // Sending a prompt is a read-only network request. It must remain usable
        // even if the editor itself is read-only; only Apply Patch and writing a
        // generated file require write/build access.
        AiAction action = currentAiAction();
        String instruction = aiPromptArea.getText() == null ? "" : aiPromptArea.getText().trim();
        if (instruction.isBlank() && action == AiAction.CHAT) {
            JOptionPane.showMessageDialog(this,
                    tr("請先輸入要問 AI 的問題。", "Enter a question for the AI first."),
                    "AI Assistant", JOptionPane.WARNING_MESSAGE);
            aiPromptArea.requestFocusInWindow();
            return;
        }
        if (instruction.isBlank()) instruction = defaultAiInstruction(action);
        final String requestInstruction = instruction;
        final String provider = chooseAiProviderForRequest();
        if (provider == null) return;
        aiLastRequestProvider = provider;
        updateAiTitleLabel();
        final String apiKey = getAiApiKey(provider);
        if (apiKey.isBlank()) {
            JOptionPane.showMessageDialog(this,
                    aiApiKeyMissingMessage(provider),
                    "AI Provider", JOptionPane.WARNING_MESSAGE);
            showAiProviderSettingsDialog();
            return;
        }

        final EditorTab requestTab = currentTab();
        final String originalText = requestTab == null ? "" : requestTab.textPane.getText();
        final String sourceLabel = requestTab == null || requestTab.file == null
                ? tr("未儲存檔案", "Unsaved file") : requestTab.file.getAbsolutePath();
        final boolean fullFileAvailable = requestTab == null || originalText.length() <= AI_MAX_CURRENT_FILE_CHARS;
        // Attachments are explicit user selections. Image bytes are collected only
        // immediately before the request and remain only in this local request object.
        final AiImageAttachmentCollection imageAttachmentCollection = collectAiImageAttachments();
        final java.util.List<AiImageAttachment> attachedImages = imageAttachmentCollection.images();
        final String prompt = buildAiRequestPrompt(action, requestInstruction, requestTab, originalText, fullFileAvailable);
        String attachmentSummary = attachedImages.isEmpty() ? ""
                : tr("\n[已附加圖片：", "\n[Attached image(s): ") + attachedImages.size() + "]";
        appendAiConversation("USER", "[" + aiProviderDisplay(provider) + " | " + aiActionDisplay(action) + "]\n" + requestInstruction + attachmentSummary);
        aiPromptArea.setText("");
        aiRequestInProgress = true;
        updateAiSendButtonState();
        aiSafetyStatusLabel.setText(tr("正在安全送出請求；不會執行或修改任何程式碼。", "Request is being sent safely; no code will run or be changed."));

        new SwingWorker<AiApiResult, Void>() {
            @Override protected AiApiResult doInBackground() {
                return callAiProvider(provider, apiKey, prompt, attachedImages);
            }

            @Override protected void done() {
                aiRequestInProgress = false;
                updateAiSendButtonState();
                try {
                    AiApiResult result = get();
                    if (!result.success()) {
                        appendAiConversation("SYSTEM", tr("AI 呼叫失敗：", "AI request failed: ") + localizeAiErrorDetail(result.detail()));
                        aiSafetyStatusLabel.setText(tr("請檢查 API Key、模型名稱、網路或額度。", "Check API key, model name, network, or account limits."));
                        return;
                    }
                    aiLastResponseText = result.text();
                    appendAiConversation(aiProviderDisplay(result.provider()), result.text());
                    String proposed = extractAiPatch(result.text());
                    if (proposed != null && !proposed.isBlank()) {
                        if (requestTab != null && !fullFileAvailable) {
                            aiPatchCandidate = null;
                            aiPreviewDiffButton.setEnabled(true);
                            aiApplyPatchButton.setEnabled(false);
                            appendAiConversation("SYSTEM", tr(
                                    "偵測到 Patch，但目前檔案超過安全完整內容上限，為避免以不完整內容覆蓋檔案，已停用套用。請縮小選取範圍後再要求建議。",
                                    "A patch was detected, but the current file exceeded the safe complete-content limit. Applying is disabled to prevent overwriting from incomplete context. Use a smaller selection and request a suggestion."));
                        } else {
                            aiPatchCandidate = new AiPatchCandidate(requestTab, originalText, proposed, sourceLabel, action);
                            aiPreviewDiffButton.setEnabled(true);
                            aiApplyPatchButton.setEnabled(true);
                            aiSafetyStatusLabel.setText(tr("已偵測到 Patch：請先按 Diff 預覽，確認後才可套用。", "Patch detected: preview its diff, then confirm before applying."));
                        }
                    } else {
                        aiPatchCandidate = null;
                        aiPreviewDiffButton.setEnabled(true);
                        aiApplyPatchButton.setEnabled(false);
                        aiSafetyStatusLabel.setText(tr("AI 回覆僅供檢視；尚未偵測到可套用的 Patch。", "Response is for review only; no applicable patch was detected."));
                    }
                    aiGeneratedFileCandidates.clear();
                    aiGeneratedFileCandidates.addAll(extractAiGeneratedFileCandidates(result.text(), action, requestInstruction, requestTab, sourceLabel));
                    aiGeneratedFileCandidate = aiGeneratedFileCandidates.isEmpty() ? null : aiGeneratedFileCandidates.get(0);
                    aiCreateFileButton.setEnabled(aiGeneratedFileCandidate != null);
                    refreshAiGeneratedFilesPanel();
                    if (aiGeneratedFileCandidate != null) {
                        appendAiConversation("SYSTEM", tr(
                                "已偵測到可建立的新程式碼檔。可按「建立新檔...」手動選擇路徑，或勾選 Prompt 下方的檔案清單，直接建立到目前目錄。",
                                "AI-generated file candidate(s) detected. Click Create New File... to choose a path manually, or tick the generated-file list below the prompt to create directly in the current folder."));
                        aiSafetyStatusLabel.setText(tr(
                                "AI 程式碼尚未寫入磁碟；勾選檔案清單才會建立到目前目錄。",
                                "AI code has not been written to disk; tick a file item to create it in the current folder."));
                    }
                    updateAiContextStatus();
                } catch (Exception ex) {
                    appendAiConversation("SYSTEM", tr("AI 工作失敗：", "AI task failed: ") + cleanAiExceptionMessage(ex));
                    aiSafetyStatusLabel.setText(tr("AI 工作失敗；檔案完全沒有被修改。", "AI task failed; no file was changed."));
                }
            }
        }.execute();
    }

    private String localizeAiErrorDetail(String detail) {
        String raw = detail == null ? "" : detail.trim();
        String lower = raw.toLowerCase(Locale.ROOT);
        if (lower.contains("insufficient_quota") || lower.contains("exceeded your current quota")) {
            return tr(
                    "HTTP 429：您的目前 API 額度已用完，或 API 帳單／付款／專案用量限制尚未啟用。請到 API 平台檢查 Plan、Billing、Usage limit、Project 與 API Key 所屬帳號。錯誤代碼：insufficient_quota。",
                    "HTTP 429: You exceeded your current API quota, or API billing/payment/project usage limits are not enabled. Check the API platform plan, billing, usage limit, project, and the account that owns this API key. Error code: insufficient_quota.");
        }
        if (lower.contains("rate_limit") || lower.contains("too many requests")) {
            return tr(
                    "HTTP 429：目前請求太頻繁或超過速率限制。請稍後再試，或降低請求頻率／檢查模型與專案限制。",
                    "HTTP 429: Requests are too frequent or the rate limit was exceeded. Try again later, reduce request frequency, or check model/project limits.");
        }
        if (lower.contains("invalid_api_key") || lower.contains("api key") && lower.contains("invalid")) {
            return tr(
                    "API Key 無效或不屬於目前專案。請檢查 AI Provider Settings 中的環境變數名稱、Key 來源、模型與帳號專案。",
                    "The API key is invalid or does not belong to the current project. Check the environment-variable name, key source, model, and account/project in AI Provider Settings.");
        }
        return raw;
    }

    private String chooseAiProviderForRequest() {
        String mode = normalizeAiProvider(aiProviderMode);
        if (!AI_PROVIDER_ASK.equals(mode)) return mode;
        Object choice = JOptionPane.showInputDialog(this,
                tr("本次要使用哪一個 AI Provider？", "Which AI provider should be used for this request?"),
                tr("選擇 AI Provider", "Choose AI Provider"),
                JOptionPane.QUESTION_MESSAGE, null,
                new Object[]{"OpenAI", "Gemini"}, "OpenAI");
        if (choice == null) return null;
        return aiProviderFromDisplay(choice);
    }

    private String buildAiRequestPrompt(AiAction action, String instruction, EditorTab tab,
                                        String originalText, boolean fullFileAvailable) {
        String language = tab == null || tab.file == null ? "text" : detectLanguageType(getFileExtension(tab.file.getName()));
        StringBuilder prompt = new StringBuilder();
        prompt.append("You are an AI coding assistant embedded in AICodingEditor " + APP_VERSION + ".\n")
                .append("The user chose action: ").append(action.id).append(".\n")
                .append("User instruction:\n").append(instruction).append("\n\n")
                .append("Safety contract: Do not execute programs, install packages, access files outside the supplied context, or claim that you did. ")
                .append("Do not modify a file directly. The user must inspect a diff and explicitly confirm before the IDE applies anything.\n");
        if (action == AiAction.GENERATE_CODE) {
            prompt.append("The user is asking to generate code. For a NEW file, return exactly one complete program in one Markdown fenced code block with an accurate language tag (for example ```python or ```java), and do not include explanations inside or after that block. ")
                    .append("AICodingEditor will let the user choose a file name/path, preview the result, and explicitly confirm before it creates the file. ")
                    .append("Only when the user explicitly asks to replace the current file, return the complete replacement between ")
                    .append(AI_PATCH_BEGIN).append(" and ").append(AI_PATCH_END).append(" instead. Do not put a Markdown code fence around a patch marker block.\n");
        } else if (action == AiAction.FIX_ERROR || action == AiAction.REVIEW_CODE) {
            prompt.append("When a complete replacement of the current file is appropriate, return exactly one complete proposed file between ")
                    .append(AI_PATCH_BEGIN).append(" and ").append(AI_PATCH_END).append(". ")
                    .append("Do not put a Markdown code fence around this marker block. The patch content must contain only the complete proposed file content. ")
                    .append("If no file replacement is appropriate, do not emit these markers.\n");
        } else {
            prompt.append("This is an explanation/chat request. Do not return patch markers unless the user explicitly asks for a full file replacement.\n");
        }
        prompt.append("\nLanguage / file type: ").append(language).append("\n");

        if (aiSendSelection && tab != null) {
            String selected = tab.textPane.getSelectedText();
            if (selected != null && !selected.isBlank()) {
                prompt.append("\n[CURRENT SELECTION]\n").append(limitAiText(selected, AI_MAX_SELECTION_CHARS)).append("\n[END CURRENT SELECTION]\n");
            }
        }
        if (aiSendCurrentFile && tab != null) {
            prompt.append("\n[CURRENT FILE: ").append(tab.file == null ? "unsaved" : tab.file.getAbsolutePath()).append("]\n");
            prompt.append(limitAiText(originalText, AI_MAX_CURRENT_FILE_CHARS));
            if (!fullFileAvailable) prompt.append("\n[CURRENT FILE TRUNCATED: do not create a full-file patch]\n");
            prompt.append("\n[END CURRENT FILE]\n");
        }
        if (aiSendConsoleError) {
            String console = extractConsoleErrorContext();
            if (!console.isBlank()) prompt.append("\n[CONSOLE ERROR / OUTPUT]\n").append(console).append("\n[END CONSOLE ERROR / OUTPUT]\n");
        }
        if (aiFullProjectScan) {
            prompt.append(buildFullProjectAiContext(tab));
            prompt.append("\n[PROJECT-CONTEXT INSTRUCTION] The Workbench project context above may include a project map and bounded source files. For Generate Code, produce code that fits this project structure and naming style. For Chat/Ask, you may propose a project plan, file layout, or implementation steps based on the supplied Workbench context. Do not claim access to files that were not supplied.\n");
        }
        // Attachments are user-selected by drag-and-drop and intentionally have
        // their own bounded, exclusion-aware context. They do not turn on the
        // general Full Project Scan preference.
        prompt.append(buildAiAttachmentContext());
        return prompt.toString();
    }

    /**
     * Builds context only for files/folders that the user explicitly dropped on
     * the AI prompt. The drop itself sends no data. At Send time, only bounded
     * UTF-8 source/config/document text is included. Generated folders, .venv,
     * VCS metadata, likely secret material, and unsupported/binary files are
     * deliberately excluded.
     */
    private String buildAiAttachmentContext() {
        if (aiAttachedPaths.isEmpty()) return "";
        StringBuilder context = new StringBuilder("\n[USER-ATTACHED FILES / PROJECT FOLDERS]\n")
                .append("Each attachment was explicitly dragged by the user. This is read-only context; do not execute anything. ")
                .append("Excluded: .venv, .git, node_modules, build output, likely secrets, and non-text files.\n");
        AiAttachmentBudget budget = new AiAttachmentBudget();
        int attachmentNumber = 0;
        for (File attachment : new ArrayList<>(aiAttachedPaths.values())) {
            attachmentNumber++;
            if (attachment == null || !attachment.exists()) {
                context.append("[ATTACHMENT ").append(attachmentNumber).append(" UNAVAILABLE] ")
                        .append(attachment == null ? "" : attachment.getAbsolutePath()).append("\n");
                continue;
            }
            if (attachment.isDirectory()) {
                appendAiAttachedFolderContext(context, attachment, budget);
            } else {
                appendAiAttachedFileContext(context, attachment.toPath(), attachment.getName(), budget, "ATTACHED FILE");
            }
            if (budget.contextChars >= AI_MAX_ATTACHMENT_CONTEXT_CHARS || budget.fileCount >= AI_MAX_ATTACHMENT_FILES) {
                context.append("[ATTACHMENT CONTEXT LIMIT REACHED]\n");
                break;
            }
        }
        context.append("[END USER-ATTACHED CONTEXT: ").append(budget.fileCount).append(" readable file(s)]\n");
        return context.toString();
    }

    /** Adds a bounded manifest and readable files from an explicitly attached folder. */
    private void appendAiAttachedFolderContext(StringBuilder context, File folder, AiAttachmentBudget budget) {
        Path root = folder.toPath();
        context.append("\n[ATTACHED FOLDER: ").append(folder.getAbsolutePath()).append("]\n")
                .append("This folder was explicitly selected by the user for analysis. It is not executed.\n");
        java.util.List<Path> readableFiles = new ArrayList<>();
        StringBuilder manifest = new StringBuilder();
        final int[] visitedEntries = {0};
        final int[] excludedEntries = {0};
        final boolean[] scanLimitReached = {false};
        try {
            Files.walkFileTree(root, EnumSet.noneOf(FileVisitOption.class), AI_MAX_ATTACHMENT_DEPTH,
                    new SimpleFileVisitor<Path>() {
                        @Override public FileVisitResult preVisitDirectory(Path directory, BasicFileAttributes attrs) {
                            if (!directory.equals(root) && isAiAttachmentIgnoredDirectory(directory.getFileName().toString())) {
                                excludedEntries[0]++;
                                return FileVisitResult.SKIP_SUBTREE;
                            }
                            return FileVisitResult.CONTINUE;
                        }

                        @Override public FileVisitResult visitFile(Path path, BasicFileAttributes attrs) {
                            visitedEntries[0]++;
                            if (visitedEntries[0] > AI_MAX_ATTACHMENT_DIRECTORY_ENTRIES) {
                                scanLimitReached[0] = true;
                                return FileVisitResult.TERMINATE;
                            }
                            String relative = safeRelativePath(root, path);
                            if (isAiAttachmentSensitivePath(path)) {
                                excludedEntries[0]++;
                                return FileVisitResult.CONTINUE;
                            }
                            if (isAiTextProjectFile(path) || isAiSupportedImageFile(path)) {
                                if (readableFiles.size() < AI_MAX_ATTACHMENT_FILES * 2) readableFiles.add(path);
                                if (manifest.length() < 12_000) {
                                    manifest.append("- ").append(relative);
                                    if (isAiSupportedImageFile(path)) manifest.append("  [image]");
                                    manifest.append('\n');
                                }
                            }
                            return FileVisitResult.CONTINUE;
                        }
                    });
        } catch (Exception ex) {
            context.append("Attachment scan note: ").append(cleanAiExceptionMessage(ex)).append('\n');
        }

        readableFiles.sort(Comparator
                .comparingInt(this::aiAttachmentPathPriority)
                .thenComparing(path -> safeRelativePath(root, path), String.CASE_INSENSITIVE_ORDER));
        if (!manifest.isEmpty()) {
            context.append("[ATTACHED FOLDER MANIFEST: readable source/config files]\n")
                    .append(manifest).append("[END ATTACHED FOLDER MANIFEST]\n");
        }
        for (Path path : readableFiles) {
            if (budget.fileCount >= AI_MAX_ATTACHMENT_FILES || budget.contextChars >= AI_MAX_ATTACHMENT_CONTEXT_CHARS) break;
            appendAiAttachedFileContext(context, path, safeRelativePath(root, path), budget, "ATTACHED PROJECT FILE");
        }
        context.append("[END ATTACHED FOLDER: scanned ").append(visitedEntries[0])
                .append(" entries; excluded ").append(excludedEntries[0]);
        if (scanLimitReached[0]) context.append("; scan entry limit reached");
        context.append("]\n");
    }

    /** Adds one supported text file to the user-approved attachment payload. */
    private void appendAiAttachedFileContext(StringBuilder context, Path path, String label,
                                             AiAttachmentBudget budget, String marker) {
        if (path == null || !Files.isRegularFile(path, LinkOption.NOFOLLOW_LINKS)) {
            context.append("[SKIPPED ").append(marker).append(": unavailable] ").append(label).append('\n');
            return;
        }
        if (isAiAttachmentSensitivePath(path)) {
            context.append("[SKIPPED ").append(marker).append(": protected name] ").append(label).append('\n');
            return;
        }
        if (isAiSupportedImageFile(path)) {
            context.append("[ATTACHED IMAGE: ").append(label).append("]\n")
                    .append("This explicitly selected image is sent separately as a visual request input when the chosen model supports image analysis.\n")
                    .append("[END ATTACHED IMAGE]\n");
            return;
        }
        if (!isAiTextProjectFile(path)) {
            context.append("[SKIPPED ").append(marker).append(": unsupported or binary type] ").append(label).append('\n');
            return;
        }
        try {
            long byteSize = Files.size(path);
            if (byteSize > 1_500_000L) {
                context.append("[SKIPPED ").append(marker).append(": file exceeds 1.5 MB safety limit] ").append(label).append('\n');
                return;
            }
            String text = Files.readString(path, StandardCharsets.UTF_8);
            if (text.indexOf('\0') >= 0) {
                context.append("[SKIPPED ").append(marker).append(": binary content] ").append(label).append('\n');
                return;
            }
            int remaining = AI_MAX_ATTACHMENT_CONTEXT_CHARS - budget.contextChars;
            if (remaining <= 0 || budget.fileCount >= AI_MAX_ATTACHMENT_FILES) return;
            int perFileLimit = Math.min(AI_MAX_ATTACHMENT_FILE_CHARS, remaining);
            String clipped = limitAiText(text, perFileLimit);
            context.append("[ ").append(marker).append(": ").append(label).append(" ]\n")
                    .append(clipped).append("\n[END ").append(marker).append("]\n");
            budget.fileCount++;
            budget.contextChars += clipped.length();
        } catch (Exception ex) {
            context.append("[SKIPPED ").append(marker).append(": ").append(cleanAiExceptionMessage(ex)).append("] ")
                    .append(label).append('\n');
        }
    }

    private String safeRelativePath(Path root, Path path) {
        try { return root.relativize(path).toString().replace('\\', '/'); }
        catch (Exception ex) { return path.getFileName() == null ? path.toString() : path.getFileName().toString(); }
    }

    private int aiAttachmentPathPriority(Path path) {
        String name = path == null || path.getFileName() == null ? "" : path.getFileName().toString().toLowerCase(Locale.ROOT);
        if (name.equals("pyproject.toml") || name.equals("requirements.txt") || name.equals("uv.lock")
                || name.equals("package.json") || name.equals("pom.xml") || name.equals("build.gradle")) return 0;
        if (name.equals("readme.md") || name.equals("readme.txt") || name.equals("main.py")
                || name.equals("app.py") || name.equals("main.java")) return 1;
        return 2;
    }

    private boolean isAiAttachmentIgnoredDirectory(String name) {
        String normalized = name == null ? "" : name.trim().toLowerCase(Locale.ROOT);
        return normalized.equals(".git") || normalized.equals(".venv") || normalized.equals("venv")
                || normalized.equals("env") || normalized.equals("node_modules") || normalized.equals("__pycache__")
                || normalized.equals("target") || normalized.equals("build") || normalized.equals("dist")
                || normalized.equals(".idea") || normalized.equals(".gradle") || normalized.equals(".pytest_cache")
                || normalized.equals(".mypy_cache") || normalized.equals(".tox");
    }

    private boolean isAiAttachmentSensitivePath(Path path) {
        String name = path == null || path.getFileName() == null ? "" : path.getFileName().toString().toLowerCase(Locale.ROOT);
        return name.equals(".env") || name.startsWith(".env.") || name.endsWith(".pem") || name.endsWith(".key")
                || name.endsWith(".p12") || name.endsWith(".pfx") || name.endsWith(".jks") || name.endsWith(".kdb")
                || name.equals("id_rsa") || name.equals("id_ed25519") || name.equals("credentials.json")
                || name.contains("secret") || name.contains("credential") || name.contains("password");
    }

    private static final class AiAttachmentBudget {
        private int fileCount;
        private int contextChars;
    }

    private String limitAiText(String text, int maxChars) {
        if (text == null) return "";
        if (text.length() <= maxChars) return text;
        int front = Math.max(1, (int) (maxChars * 0.70));
        int back = Math.max(1, maxChars - front);
        return text.substring(0, front) + "\n\n[... content truncated by AICodingEditor safety limit ...]\n\n" + text.substring(text.length() - back);
    }

    private String extractConsoleErrorContext() {
        String output = embeddedConsoleArea.getText();
        if (output == null || output.isBlank()) return "";
        String lower = output.toLowerCase(Locale.ROOT);
        int from = Math.max(Math.max(lower.lastIndexOf("traceback"), lower.lastIndexOf("exception")),
                Math.max(lower.lastIndexOf("error"), lower.lastIndexOf("failed")));
        String relevant = from >= 0 ? output.substring(from) : output;
        if (relevant.length() > AI_MAX_CONSOLE_CHARS) relevant = relevant.substring(relevant.length() - AI_MAX_CONSOLE_CHARS);
        return relevant;
    }

    private String buildFullProjectAiContext(EditorTab tab) {
        File root = resolveActiveWorkbenchProjectRoot(tab);
        if (root == null && fileBrowserRootDirectory != null) root = fileBrowserRootDirectory;
        if (root == null) root = currentDirectory;
        if (root == null || !root.isDirectory()) return "\n[FULL PROJECT SCAN]\nNo readable project folder was available.\n";
        StringBuilder context = new StringBuilder("\n[FULL PROJECT SCAN: user explicitly enabled]\nRoot: ")
                .append(root.getAbsolutePath()).append('\n');
        final Path rootPath = root.toPath();
        final int[] fileCount = {0};
        final int[] chars = {0};
        try (Stream<Path> stream = Files.walk(rootPath, 8)) {
            Iterator<Path> iterator = stream.filter(Files::isRegularFile).iterator();
            while (iterator.hasNext() && fileCount[0] < AI_MAX_PROJECT_FILES && chars[0] < AI_MAX_PROJECT_CONTEXT_CHARS) {
                Path path = iterator.next();
                String normalized = path.toString().replace('\\', '/').toLowerCase(Locale.ROOT);
                if (normalized.contains("/.git/") || normalized.contains("/.venv/") || normalized.contains("/node_modules/")
                        || normalized.contains("/target/") || normalized.contains("/build/") || normalized.contains("/dist/")) continue;
                if (!isAiTextProjectFile(path)) continue;
                try {
                    long size = Files.size(path);
                    if (size > 150_000L) continue;
                    String fileText = Files.readString(path, StandardCharsets.UTF_8);
                    int remaining = AI_MAX_PROJECT_CONTEXT_CHARS - chars[0];
                    if (remaining <= 0) break;
                    String clipped = limitAiText(fileText, Math.min(100_000, remaining));
                    context.append("\n[PROJECT FILE: ").append(rootPath.relativize(path)).append("]\n")
                            .append(clipped).append("\n[END PROJECT FILE]\n");
                    fileCount[0]++;
                    chars[0] += clipped.length();
                } catch (Exception ignored) {
                    // A project scan is best-effort; inaccessible files are skipped.
                }
            }
        } catch (Exception ex) {
            context.append("Project scan note: ").append(cleanAiExceptionMessage(ex)).append('\n');
        }
        context.append("[END FULL PROJECT SCAN: ").append(fileCount[0]).append(" files]\n");
        return context.toString();
    }

    /**
     * Resolves the active Workbench project root for AI project context.
     * Preference order: current editor file's containing Workbench root, current
     * Workbench selection's root, File Browser root, then currentDirectory.
     */
    private File resolveActiveWorkbenchProjectRoot(EditorTab tab) {
        File currentFile = tab != null ? tab.file : null;
        if (currentFile != null) {
            File matched = findWorkbenchRootContaining(currentFile);
            if (matched != null) return matched;
        }
        File selected = getSelectedTreeFile(workbenchTree);
        if (selected != null) {
            File matched = findWorkbenchRootContaining(selected);
            if (matched != null) return matched;
            if (selected.isDirectory()) return selected;
        }
        if (fileBrowserRootDirectory != null) {
            File matched = findWorkbenchRootContaining(fileBrowserRootDirectory);
            if (matched != null) return matched;
            if (fileBrowserRootDirectory.isDirectory()) return fileBrowserRootDirectory;
        }
        return currentDirectory != null && currentDirectory.isDirectory() ? currentDirectory : null;
    }

    private File findWorkbenchRootContaining(File file) {
        if (file == null) return null;
        Path target;
        try {
            target = file.getCanonicalFile().toPath();
        } catch (IOException ex) {
            target = file.toPath().toAbsolutePath().normalize();
        }
        File best = null;
        int bestNameCount = -1;
        for (int i = 0; i < workbenchRootNode.getChildCount(); i++) {
            Object child = workbenchRootNode.getChildAt(i);
            if (!(child instanceof FileTreeNode node) || node.file == null || !node.file.isDirectory()) continue;
            Path rootPath;
            try {
                rootPath = node.file.getCanonicalFile().toPath();
            } catch (IOException ex) {
                rootPath = node.file.toPath().toAbsolutePath().normalize();
            }
            if (target.startsWith(rootPath) && rootPath.getNameCount() > bestNameCount) {
                best = node.file;
                bestNameCount = rootPath.getNameCount();
            }
        }
        return best;
    }

    private boolean isAiTextProjectFile(Path path) {
        String name = path.getFileName().toString().toLowerCase(Locale.ROOT);
        return name.endsWith(".java") || name.endsWith(".py") || name.endsWith(".ipynb") || name.endsWith(".js")
                || name.endsWith(".ts") || name.endsWith(".tsx") || name.endsWith(".jsx") || name.endsWith(".c")
                || name.endsWith(".h") || name.endsWith(".cpp") || name.endsWith(".hpp") || name.endsWith(".cs")
                || name.endsWith(".php") || name.endsWith(".rs") || name.endsWith(".sql") || name.endsWith(".html")
                || name.endsWith(".css") || name.endsWith(".json") || name.endsWith(".yaml") || name.endsWith(".yml")
                || name.endsWith(".md") || name.endsWith(".txt") || name.endsWith(".xml") || name.endsWith(".gradle")
                || name.endsWith(".toml") || name.endsWith(".lock") || name.endsWith(".csv") || name.endsWith(".tsv")
                || name.endsWith(".log") || name.endsWith(".ini") || name.endsWith(".cfg") || name.endsWith(".conf")
                || name.endsWith(".properties") || name.endsWith(".rst") || name.endsWith(".sh") || name.endsWith(".bat")
                || name.endsWith(".ps1") || name.endsWith(".r") || name.endsWith(".m")
                || name.equals("pom.xml") || name.equals("build.gradle") || name.equals("requirements.txt")
                || name.equals("pyproject.toml") || name.equals("uv.lock") || name.equals("package.json");
    }

    /** Common visual file types accepted by the + menu and supported by the two AI request builders. */
    private boolean isAiSupportedImageFile(Path path) {
        if (path == null || path.getFileName() == null) return false;
        String name = path.getFileName().toString().toLowerCase(Locale.ROOT);
        return name.endsWith(".png") || name.endsWith(".jpg") || name.endsWith(".jpeg")
                || name.endsWith(".gif") || name.endsWith(".webp");
    }

    private String aiImageMimeType(Path path) {
        String name = path == null || path.getFileName() == null ? "" : path.getFileName().toString().toLowerCase(Locale.ROOT);
        if (name.endsWith(".png")) return "image/png";
        if (name.endsWith(".jpg") || name.endsWith(".jpeg")) return "image/jpeg";
        if (name.endsWith(".gif")) return "image/gif";
        if (name.endsWith(".webp")) return "image/webp";
        return "application/octet-stream";
    }

    /**
     * Collects supported image attachments immediately before an AI request. This
     * runs only after the user presses Send; images are never persisted and only
     * bounded, explicit user selections are read.
     */
    private AiImageAttachmentCollection collectAiImageAttachments() {
        if (aiAttachedPaths.isEmpty()) return new AiImageAttachmentCollection(java.util.List.of(), 0);
        java.util.List<AiImageAttachment> images = new ArrayList<>();
        AiImageAttachmentBudget budget = new AiImageAttachmentBudget();
        Set<String> seen = new HashSet<>();
        for (File attachment : new ArrayList<>(aiAttachedPaths.values())) {
            if (attachment == null || !attachment.exists()) continue;
            if (attachment.isDirectory()) {
                collectAiImagesFromFolder(attachment.toPath(), images, budget, seen);
            } else {
                tryAddAiImageAttachment(attachment.toPath(), images, budget, seen);
            }
            if (images.size() >= AI_MAX_ATTACHMENT_IMAGES || budget.totalBytes >= AI_MAX_ATTACHMENT_IMAGE_BYTES_TOTAL) break;
        }
        return new AiImageAttachmentCollection(java.util.List.copyOf(images), budget.skipped);
    }

    private void collectAiImagesFromFolder(Path root, java.util.List<AiImageAttachment> images,
                                           AiImageAttachmentBudget budget, Set<String> seen) {
        if (root == null || !Files.isDirectory(root, LinkOption.NOFOLLOW_LINKS)) return;
        final int[] entries = {0};
        try {
            Files.walkFileTree(root, EnumSet.noneOf(FileVisitOption.class), AI_MAX_ATTACHMENT_DEPTH,
                    new SimpleFileVisitor<Path>() {
                        @Override public FileVisitResult preVisitDirectory(Path directory, BasicFileAttributes attrs) {
                            if (!directory.equals(root) && isAiAttachmentIgnoredDirectory(directory.getFileName().toString())) {
                                return FileVisitResult.SKIP_SUBTREE;
                            }
                            return FileVisitResult.CONTINUE;
                        }

                        @Override public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) {
                            entries[0]++;
                            if (entries[0] > AI_MAX_ATTACHMENT_DIRECTORY_ENTRIES
                                    || images.size() >= AI_MAX_ATTACHMENT_IMAGES
                                    || budget.totalBytes >= AI_MAX_ATTACHMENT_IMAGE_BYTES_TOTAL) {
                                return FileVisitResult.TERMINATE;
                            }
                            tryAddAiImageAttachment(file, images, budget, seen);
                            return FileVisitResult.CONTINUE;
                        }
                    });
        } catch (Exception ignored) {
            // Image candidates are optional. Text attachment context will report any readable source files separately.
        }
    }

    private void tryAddAiImageAttachment(Path path, java.util.List<AiImageAttachment> images,
                                         AiImageAttachmentBudget budget, Set<String> seen) {
        if (path == null || images.size() >= AI_MAX_ATTACHMENT_IMAGES || !Files.isRegularFile(path, LinkOption.NOFOLLOW_LINKS)) return;
        if (isAiAttachmentSensitivePath(path) || !isAiSupportedImageFile(path)) return;
        String unique;
        try { unique = path.toRealPath(LinkOption.NOFOLLOW_LINKS).toString(); }
        catch (Exception ex) { unique = path.toAbsolutePath().normalize().toString(); }
        if (!seen.add(unique)) return;
        try {
            long size = Files.size(path);
            if (size <= 0 || size > AI_MAX_ATTACHMENT_IMAGE_BYTES_PER_FILE
                    || budget.totalBytes + size > AI_MAX_ATTACHMENT_IMAGE_BYTES_TOTAL) {
                budget.skipped++;
                return;
            }
            byte[] bytes = Files.readAllBytes(path);
            if (bytes.length != size) { budget.skipped++; return; }
            String filename = path.getFileName() == null ? "image" : path.getFileName().toString();
            images.add(new AiImageAttachment(filename, aiImageMimeType(path), Base64.getEncoder().encodeToString(bytes)));
            budget.totalBytes += bytes.length;
        } catch (Exception ex) {
            budget.skipped++;
        }
    }

    private record AiImageAttachment(String filename, String mimeType, String base64Data) {}
    private record AiImageAttachmentCollection(java.util.List<AiImageAttachment> images, int skipped) {}
    private static final class AiImageAttachmentBudget {
        private long totalBytes;
        private int skipped;
    }

    /** Converts one text prompt plus optional images into a Responses API input JSON fragment. */
    private String buildOpenAiInputJson(String prompt, java.util.List<AiImageAttachment> images) {
        if (images == null || images.isEmpty()) return "\"input\":\"" + jsonEscape(prompt) + "\"";
        StringBuilder content = new StringBuilder("[{\"type\":\"input_text\",\"text\":\"")
                .append(jsonEscape(prompt)).append("\"}");
        for (AiImageAttachment image : images) {
            content.append(",{\"type\":\"input_image\",\"image_url\":\"data:")
                    .append(jsonEscape(image.mimeType())).append(";base64,")
                    .append(jsonEscape(image.base64Data())).append("\"}");
        }
        content.append(']');
        return "\"input\":[{\"role\":\"user\",\"content\":" + content + "}]";
    }

    /** Builds the parts array used by Gemini generateContent with optional inline image data. */
    private String buildGeminiPartsJson(String prompt, java.util.List<AiImageAttachment> images) {
        StringBuilder parts = new StringBuilder("[{\"text\":\"").append(jsonEscape(prompt)).append("\"}");
        if (images != null) {
            for (AiImageAttachment image : images) {
                parts.append(",{\"inlineData\":{\"mimeType\":\"")
                        .append(jsonEscape(image.mimeType())).append("\",\"data\":\"")
                        .append(jsonEscape(image.base64Data())).append("\"}}");
            }
        }
        return parts.append(']').toString();
    }

    private AiApiResult callAiProvider(String provider, String apiKey, String prompt, java.util.List<AiImageAttachment> images) {
        try {
            if (AI_PROVIDER_OPENAI.equals(provider)) return callOpenAiApi(apiKey, prompt, images);
            if (AI_PROVIDER_GEMINI.equals(provider)) return callGeminiApi(apiKey, prompt, images);
            return new AiApiResult(false, provider, "", "Unsupported provider.");
        } catch (Exception ex) {
            return new AiApiResult(false, provider, "", cleanAiExceptionMessage(ex));
        }
    }

    private AiApiResult callOpenAiApi(String apiKey, String prompt, java.util.List<AiImageAttachment> images) throws IOException {
        String body = "{\"model\":\"" + jsonEscape(aiOpenAiModel) + "\","
                + buildOpenAiInputJson(prompt, images) + ","
                + "\"store\":false,\"max_output_tokens\":16384}";
        HttpURLConnection connection = (HttpURLConnection) new URL(OPENAI_RESPONSES_ENDPOINT).openConnection();
        connection.setRequestMethod("POST");
        connection.setConnectTimeout(AI_CONNECT_TIMEOUT_MS);
        connection.setReadTimeout(AI_READ_TIMEOUT_MS);
        connection.setDoOutput(true);
        connection.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
        connection.setRequestProperty("Authorization", "Bearer " + apiKey);
        connection.setRequestProperty("User-Agent", APP_NAME + "/" + APP_VERSION);
        try (OutputStream output = connection.getOutputStream()) {
            output.write(body.getBytes(StandardCharsets.UTF_8));
        }
        int status = connection.getResponseCode();
        String response = readHttpText(status >= 200 && status < 300 ? connection.getInputStream() : connection.getErrorStream());
        if (status < 200 || status >= 300) {
            return new AiApiResult(false, AI_PROVIDER_OPENAI, "", "HTTP " + status + ": " + limitAiText(response, 8_000));
        }
        String outputText = extractOpenAiOutputText(response);
        if (outputText.isBlank()) outputText = tr("OpenAI 未回傳可讀文字。原始回覆：", "OpenAI returned no readable text. Raw response: ") + limitAiText(response, 8_000);
        return new AiApiResult(true, AI_PROVIDER_OPENAI, outputText, "");
    }

    private AiApiResult callGeminiApi(String apiKey, String prompt, java.util.List<AiImageAttachment> images) throws IOException {
        String endpoint = GEMINI_GENERATE_CONTENT_ENDPOINT + urlPathSegment(aiGeminiModel) + ":generateContent";
        String body = "{\"systemInstruction\":{\"parts\":[{\"text\":\""
                + jsonEscape("You are AICodingEditor " + APP_VERSION + "'s careful coding assistant. Follow the user's supplied safety and patch rules.")
                + "\"}]},\"contents\":[{\"role\":\"user\",\"parts\":"
                + buildGeminiPartsJson(prompt, images) + "}],\"generationConfig\":{\"maxOutputTokens\":16384}}";
        HttpURLConnection connection = (HttpURLConnection) new URL(endpoint).openConnection();
        connection.setRequestMethod("POST");
        connection.setConnectTimeout(AI_CONNECT_TIMEOUT_MS);
        connection.setReadTimeout(AI_READ_TIMEOUT_MS);
        connection.setDoOutput(true);
        connection.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
        connection.setRequestProperty("x-goog-api-key", apiKey);
        connection.setRequestProperty("User-Agent", APP_NAME + "/" + APP_VERSION);
        try (OutputStream output = connection.getOutputStream()) {
            output.write(body.getBytes(StandardCharsets.UTF_8));
        }
        int status = connection.getResponseCode();
        String response = readHttpText(status >= 200 && status < 300 ? connection.getInputStream() : connection.getErrorStream());
        if (status < 200 || status >= 300) {
            return new AiApiResult(false, AI_PROVIDER_GEMINI, "", "HTTP " + status + ": " + limitAiText(response, 8_000));
        }
        String outputText = extractGeminiOutputText(response);
        if (outputText.isBlank()) outputText = tr("Gemini 未回傳可讀文字。原始回覆：", "Gemini returned no readable text. Raw response: ") + limitAiText(response, 8_000);
        return new AiApiResult(true, AI_PROVIDER_GEMINI, outputText, "");
    }

    private String readHttpText(InputStream stream) throws IOException {
        if (stream == null) return "";
        try (InputStream in = stream) {
            return new String(in.readAllBytes(), StandardCharsets.UTF_8);
        }
    }

    private String urlPathSegment(String value) {
        return URLEncoder.encode(value == null ? "" : value, StandardCharsets.UTF_8).replace("+", "%20");
    }

    private String jsonEscape(String value) {
        if (value == null) return "";
        StringBuilder escaped = new StringBuilder(value.length() + 32);
        for (int i = 0; i < value.length(); i++) {
            char c = value.charAt(i);
            switch (c) {
                case '\\' -> escaped.append("\\\\");
                case '"' -> escaped.append("\\\"");
                case '\n' -> escaped.append("\\n");
                case '\r' -> escaped.append("\\r");
                case '\t' -> escaped.append("\\t");
                case '\b' -> escaped.append("\\b");
                case '\f' -> escaped.append("\\f");
                default -> {
                    if (c < 0x20) escaped.append(String.format("\\u%04x", (int) c));
                    else escaped.append(c);
                }
            }
        }
        return escaped.toString();
    }

    private String extractOpenAiOutputText(String json) {
        if (json == null || json.isBlank()) return "";
        StringBuilder text = new StringBuilder();
        int cursor = 0;
        while (true) {
            int typeIndex = json.indexOf("\"type\":\"output_text\"", cursor);
            if (typeIndex < 0) typeIndex = json.indexOf("\"type\" : \"output_text\"", cursor);
            if (typeIndex < 0) break;
            int textIndex = json.indexOf("\"text\"", typeIndex);
            if (textIndex < 0) break;
            JsonStringValue parsed = readJsonStringValue(json, textIndex);
            if (parsed == null) break;
            if (!text.isEmpty()) text.append('\n');
            text.append(parsed.value);
            cursor = parsed.nextIndex;
        }
        // Some compatible endpoints return a direct output_text string.
        if (text.isEmpty()) {
            int direct = json.indexOf("\"output_text\"");
            if (direct >= 0) {
                JsonStringValue parsed = readJsonStringValue(json, direct);
                if (parsed != null) text.append(parsed.value);
            }
        }
        return text.toString().trim();
    }

    private String extractGeminiOutputText(String json) {
        if (json == null || json.isBlank()) return "";
        int candidates = json.indexOf("\"candidates\"");
        String candidateJson = candidates >= 0 ? json.substring(candidates) : json;
        StringBuilder text = new StringBuilder();
        int cursor = 0;
        while (true) {
            int textIndex = candidateJson.indexOf("\"text\"", cursor);
            if (textIndex < 0) break;
            JsonStringValue parsed = readJsonStringValue(candidateJson, textIndex);
            if (parsed == null) break;
            if (!text.isEmpty()) text.append('\n');
            text.append(parsed.value);
            cursor = parsed.nextIndex;
        }
        return text.toString().trim();
    }

    private record JsonStringValue(String value, int nextIndex) {}

    /** Reads a JSON string value after a property name without adding a JSON library dependency. */
    private JsonStringValue readJsonStringValue(String json, int propertyIndex) {
        if (json == null || propertyIndex < 0) return null;
        int colon = json.indexOf(':', propertyIndex);
        if (colon < 0) return null;
        int quote = colon + 1;
        while (quote < json.length() && Character.isWhitespace(json.charAt(quote))) quote++;
        if (quote >= json.length() || json.charAt(quote) != '"') return null;
        StringBuilder value = new StringBuilder();
        int i = quote + 1;
        while (i < json.length()) {
            char c = json.charAt(i++);
            if (c == '"') return new JsonStringValue(value.toString(), i);
            if (c != '\\') { value.append(c); continue; }
            if (i >= json.length()) return null;
            char escaped = json.charAt(i++);
            switch (escaped) {
                case '"' -> value.append('"');
                case '\\' -> value.append('\\');
                case '/' -> value.append('/');
                case 'b' -> value.append('\b');
                case 'f' -> value.append('\f');
                case 'n' -> value.append('\n');
                case 'r' -> value.append('\r');
                case 't' -> value.append('\t');
                case 'u' -> {
                    if (i + 4 > json.length()) return null;
                    try {
                        value.append((char) Integer.parseInt(json.substring(i, i + 4), 16));
                        i += 4;
                    } catch (NumberFormatException ex) { return null; }
                }
                default -> value.append(escaped);
            }
        }
        return null;
    }

    /**
     * Extracts a complete code payload without writing or modifying anything.
     * Any AI action may expose the longest complete Markdown code fence. Generate
     * Code also accepts an unfenced code-only response. The user still chooses the
     * target path, reviews the content, and confirms before any file is written.
     */

    private java.util.List<AiGeneratedFileCandidate> extractAiGeneratedFileCandidates(String response, AiAction action,
                                                                                       String instruction, EditorTab requestTab,
                                                                                       String sourceLabel) {
        java.util.List<AiGeneratedFileCandidate> result = new ArrayList<>();
        String text = response == null ? "" : response;
        String patch = extractAiPatch(text);
        if (patch != null && !patch.isBlank()) {
            String languageHint = inferAiGeneratedLanguageHint("", instruction, requestTab, patch);
            result.add(new AiGeneratedFileCandidate(patch, languageHint,
                    suggestAiGeneratedFileName(languageHint, instruction, patch, requestTab), sourceLabel, requestTab));
            return result;
        }
        Pattern fences = Pattern.compile("(?s)```\\s*([A-Za-z0-9_+.\\-#]*)\\s*\\R(.*?)```");
        Matcher matcher = fences.matcher(text);
        Map<String, Integer> usedNames = new HashMap<>();
        while (matcher.find()) {
            String rawCode = matcher.group(2) == null ? "" : matcher.group(2).trim();
            if (rawCode.isBlank() || rawCode.length() < 6) continue;
            String languageHint = inferAiGeneratedLanguageHint(matcher.group(1), instruction, requestTab, rawCode);
            String name = uniqueAiGeneratedFileName(suggestAiGeneratedFileName(languageHint, instruction, rawCode, requestTab), usedNames);
            result.add(new AiGeneratedFileCandidate(rawCode, languageHint, name, sourceLabel, requestTab));
            if (result.size() >= 12) break;
        }
        if (result.isEmpty() && action == AiAction.GENERATE_CODE && looksLikeStandaloneSource(text)) {
            String languageHint = inferAiGeneratedLanguageHint("", instruction, requestTab, text);
            String name = uniqueAiGeneratedFileName(suggestAiGeneratedFileName(languageHint, instruction, text, requestTab), usedNames);
            result.add(new AiGeneratedFileCandidate(text.trim(), languageHint, name, sourceLabel, requestTab));
        }
        return result;
    }

    private String uniqueAiGeneratedFileName(String suggested, Map<String, Integer> usedNames) {
        String safe = suggested == null || suggested.isBlank() ? "AI_Generated.txt" : suggested;
        String key = safe.toLowerCase(Locale.ROOT);
        int count = usedNames.getOrDefault(key, 0);
        usedNames.put(key, count + 1);
        if (count == 0) return safe;
        int dot = safe.lastIndexOf('.');
        if (dot <= 0) return safe + "_" + (count + 1);
        return safe.substring(0, dot) + "_" + (count + 1) + safe.substring(dot);
    }

    private AiGeneratedFileCandidate extractAiGeneratedFileCandidate(String response, AiAction action,
                                                                       String instruction, EditorTab requestTab,
                                                                       String sourceLabel) {
        String patch = extractAiPatch(response);
        String rawCode = null;
        String languageHint = "";
        if (patch != null && !patch.isBlank()) {
            rawCode = patch;
            languageHint = inferAiGeneratedLanguageHint("", instruction, requestTab, patch);
        } else {
            // A Chat / Explain / Fix response may still contain a complete fenced
            // program. Offering it as a candidate is safe because this release
            // never writes anything until the user selects a path, reviews a
            // preview/diff, and explicitly confirms.
            Pattern fences = Pattern.compile("(?s)```\\s*([A-Za-z0-9_+.\\-#]*)\\s*\\R(.*?)```");
            Matcher matcher = fences.matcher(response == null ? "" : response);
            int bestLength = -1;
            while (matcher.find()) {
                String candidate = matcher.group(2) == null ? "" : matcher.group(2).trim();
                if (!candidate.isBlank() && candidate.length() > bestLength) {
                    rawCode = candidate;
                    languageHint = matcher.group(1) == null ? "" : matcher.group(1).trim();
                    bestLength = candidate.length();
                }
            }
            // Only Generate Code may accept a non-fenced code-only reply. Other
            // actions require a fence or a full patch so prose is not mistaken for
            // a source file.
            if ((rawCode == null || rawCode.isBlank()) && action == AiAction.GENERATE_CODE
                    && looksLikeStandaloneSource(response)) {
                rawCode = response.trim();
                languageHint = inferAiGeneratedLanguageHint("", instruction, requestTab, rawCode);
            }
        }
        if (rawCode == null || rawCode.isBlank()) return null;
        languageHint = inferAiGeneratedLanguageHint(languageHint, instruction, requestTab, rawCode);
        String suggestedName = suggestAiGeneratedFileName(languageHint, instruction, rawCode, requestTab);
        return new AiGeneratedFileCandidate(rawCode, languageHint, suggestedName, sourceLabel, requestTab);
    }

    private boolean looksLikeStandaloneSource(String text) {
        if (text == null || text.isBlank()) return false;
        String trimmed = text.trim();
        if (trimmed.length() < 12) return false;
        return trimmed.contains("\n") && (trimmed.startsWith("import ") || trimmed.startsWith("from ")
                || trimmed.startsWith("#") || trimmed.startsWith("public class ")
                || trimmed.startsWith("class ") || trimmed.startsWith("def ")
                || trimmed.startsWith("function ") || trimmed.startsWith("using ")
                || trimmed.startsWith("{") || trimmed.startsWith("SELECT "));
    }

    private String inferAiGeneratedLanguageHint(String suppliedHint, String instruction,
                                                 EditorTab requestTab, String rawCode) {
        String hint = suppliedHint == null ? "" : suppliedHint.trim().toLowerCase(Locale.ROOT);
        String lowerInstruction = instruction == null ? "" : instruction.toLowerCase(Locale.ROOT);
        String lowerCode = rawCode == null ? "" : rawCode.trim().toLowerCase(Locale.ROOT);
        if (lowerInstruction.contains("jupyter") || lowerInstruction.contains("notebook")
                || lowerInstruction.contains("ipynb") || lowerInstruction.contains("筆記本")
                || lowerCode.startsWith("# %%") || (lowerCode.startsWith("{") && lowerCode.contains("\"cells\""))) {
            return "ipynb";
        }
        if (!hint.isBlank()) return hint;
        if (requestTab != null && requestTab.file != null) {
            String extension = getFileExtension(requestTab.file.getName()).toLowerCase(Locale.ROOT);
            if (!"txt".equals(extension)) return extension;
        }
        if (lowerCode.startsWith("import ") || lowerCode.startsWith("from ") || lowerCode.startsWith("def ")) return "python";
        if (lowerCode.contains("public static void main") || lowerCode.startsWith("public class ")) return "java";
        if (lowerCode.startsWith("#include")) return "cpp";
        if (lowerCode.startsWith("select ") || lowerCode.startsWith("with ")) return "sql";
        return "text";
    }

    private String suggestAiGeneratedFileName(String languageHint, String instruction, String rawCode, EditorTab requestTab) {
        String extension = aiExtensionForLanguageHint(languageHint, instruction, rawCode, requestTab);
        String lowerInstruction = instruction == null ? "" : instruction.toLowerCase(Locale.ROOT);
        String lowerCode = rawCode == null ? "" : rawCode.toLowerCase(Locale.ROOT);
        String baseName = "AI_Generated_" + DateTimeFormatter.ofPattern("yyyyMMdd_HHmmss").format(LocalDateTime.now());

        Matcher explicitName = Pattern.compile("(?i)\\b([A-Za-z0-9_][A-Za-z0-9_.\\-]{1,80}\\." + Pattern.quote(extension) + ")\\b")
                .matcher(instruction == null ? "" : instruction);
        if (explicitName.find()) {
            String file = explicitName.group(1);
            int dot = file.lastIndexOf('.');
            if (dot > 0) baseName = file.substring(0, dot);
        } else if ("py".equals(extension)) {
            boolean mentionsSin = lowerInstruction.contains("sin") || lowerInstruction.contains("sine")
                    || lowerInstruction.contains("sin(") || lowerInstruction.contains("正弦");
            boolean mentionsCos = lowerInstruction.contains("cos") || lowerInstruction.contains("cosin")
                    || lowerInstruction.contains("cos(") || lowerInstruction.contains("餘弦") || lowerInstruction.contains("余弦");
            if (lowerInstruction.contains("streamlit") || lowerCode.contains("import streamlit") || lowerCode.contains(" st.")) {
                baseName = (mentionsSin && mentionsCos) ? "streamlit_sin_cos_live" : "streamlit_app";
            } else if (mentionsSin && mentionsCos) {
                baseName = "sin_cos_live";
            } else if (lowerCode.contains("if __name__ ==") || lowerCode.contains("argparse") || lowerInstruction.contains("main")) {
                baseName = "main";
            }
        }
        if ("java".equals(extension)) {
            Matcher javaClass = Pattern.compile("(?m)\\bpublic\\s+class\\s+([A-Za-z_$][A-Za-z0-9_$]*)").matcher(rawCode == null ? "" : rawCode);
            if (javaClass.find()) baseName = javaClass.group(1);
        }
        return sanitizeAiGeneratedFileBaseName(baseName) + "." + extension;
    }

    private String sanitizeAiGeneratedFileBaseName(String value) {
        String safe = value == null ? "AI_Generated" : value.replaceAll("[\\\\/:*?\"<>|]+", "_").trim();
        return safe.isBlank() ? "AI_Generated" : safe;
    }

    private String aiExtensionForLanguageHint(String languageHint, String instruction, String rawCode, EditorTab requestTab) {
        String hint = languageHint == null ? "" : languageHint.trim().toLowerCase(Locale.ROOT);
        if ("ipynb".equals(hint) || "jupyter".equals(hint) || "notebook".equals(hint)) return "ipynb";
        return switch (hint) {
            case "py", "python", "python3" -> "py";
            case "java" -> "java";
            case "c" -> "c";
            case "cpp", "c++", "cxx", "cc" -> "cpp";
            case "c#", "csharp", "cs" -> "cs";
            case "javascript", "js", "node", "nodejs" -> "js";
            case "typescript", "ts" -> "ts";
            case "html", "htm" -> "html";
            case "css" -> "css";
            case "json" -> "json";
            case "sql" -> "sql";
            case "php" -> "php";
            case "rust", "rs" -> "rs";
            case "arduino", "ino" -> "ino";
            case "r" -> "r";
            case "markdown", "md" -> "md";
            case "xml" -> "xml";
            case "yaml", "yml" -> "yaml";
            default -> {
                if (requestTab != null && requestTab.file != null) {
                    String currentExtension = getFileExtension(requestTab.file.getName()).toLowerCase(Locale.ROOT);
                    if (!"txt".equals(currentExtension)) yield currentExtension;
                }
                yield "txt";
            }
        };
    }

    private void showAiCreateGeneratedFileDialog() {
        if (aiGeneratedFileCandidate == null) {
            JOptionPane.showMessageDialog(this,
                    tr("目前沒有可建立成檔案的 AI 程式碼。請讓 AI 回覆完整的 Markdown 程式碼區塊或完整 Patch；建議使用 Generate Code。",
                            "There is no AI code ready to create as a file. Ask the AI for a complete Markdown code block or a complete patch; Generate Code is recommended."),
                    tr("建立 AI 新檔", "Create AI New File"), JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        if (!requireTrialWriteBuildAccess("Create AI Generated File")) return;
        AiGeneratedFileCandidate candidate = aiGeneratedFileCandidate;
        File folder = defaultAiGeneratedFileDirectory(candidate);
        File suggested = new File(folder, candidate.suggestedFileName);
        File target = showPathFileDialog(tr("建立 AI 產生的新檔", "Create AI Generated File"), FileDialog.SAVE, suggested);
        if (target == null) return;
        if (!target.getName().contains(".")) {
            String extension = getFileExtension(candidate.suggestedFileName);
            target = new File(target.getParentFile() == null ? folder : target.getParentFile(), target.getName() + "." + extension);
        }
        try {
            AiGeneratedFilePayload payload = prepareAiGeneratedFilePayload(candidate, target);
            showAiGeneratedFilePreview(target.getCanonicalFile(), payload);
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                    tr("無法準備 AI 產生的新檔：\n", "Could not prepare the AI-generated file:\n") + ex.getMessage(),
                    tr("建立 AI 新檔", "Create AI New File"), JOptionPane.ERROR_MESSAGE);
        }
    }

    private File defaultAiGeneratedFileDirectory(AiGeneratedFileCandidate candidate) {
        if (candidate != null && candidate.requestTab != null && candidate.requestTab.file != null
                && candidate.requestTab.file.getParentFile() != null) return candidate.requestTab.file.getParentFile();
        if (currentDirectory != null && currentDirectory.isDirectory()) return currentDirectory;
        if (fileBrowserRootDirectory != null && fileBrowserRootDirectory.isDirectory()) return fileBrowserRootDirectory;
        return new File(System.getProperty("user.home", "."));
    }

    private AiGeneratedFilePayload prepareAiGeneratedFilePayload(AiGeneratedFileCandidate candidate, File target) throws IOException {
        String raw = candidate == null ? "" : candidate.rawCode.replace("\r\n", "\n").replace('\r', '\n');
        boolean isNotebook = "ipynb".equalsIgnoreCase(getFileExtension(target.getName()));
        if (!isNotebook) return new AiGeneratedFilePayload(raw, raw, false);
        String trimmed = raw.trim();
        if (trimmed.startsWith("{") && trimmed.contains("\"cells\"")) {
            try {
                NotebookModel model = NotebookModel.fromJson(trimmed);
                return new AiGeneratedFilePayload(model.toPrettyJson(), model.toCellText(), true);
            } catch (IOException invalidNotebook) {
                throw new IOException(tr("AI 回覆看似 Notebook JSON，但格式無法解析：", "The AI response looks like Notebook JSON but could not be parsed: ")
                        + " " + invalidNotebook.getMessage());
            }
        }
        String cellText = raw.startsWith("# %%") ? raw : "# %%\n" + raw;
        NotebookModel model = NotebookModel.createEmpty();
        model.updateFromCellText(cellText);
        return new AiGeneratedFilePayload(model.toPrettyJson(), model.toCellText(), true);
    }

    /** Shows a preview first; any disk write requires a separate final confirmation. */
    private void showAiGeneratedFilePreview(File target, AiGeneratedFilePayload payload) {
        boolean exists = target.exists();
        String original = "";
        try {
            if (exists) {
                byte[] bytes = Files.readAllBytes(target.toPath());
                original = new String(bytes, "ipynb".equalsIgnoreCase(getFileExtension(target.getName()))
                        ? StandardCharsets.UTF_8 : detectCharset(bytes));
            }
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                    tr("無法讀取既有檔案以建立 Diff：\n", "Could not read the existing file for a diff:\n") + ex.getMessage(),
                    tr("建立 AI 新檔", "Create AI New File"), JOptionPane.ERROR_MESSAGE);
            return;
        }
        JDialog dialog = new JDialog(this,
                exists ? tr("AI 新檔 Diff 預覽（尚未覆寫）", "AI File Diff Preview (not overwritten)")
                        : tr("AI 新檔預覽（尚未建立）", "AI New File Preview (not created)"), true);
        dialog.setLayout(new BorderLayout(6, 6));
        dialog.setSize(1120, 720);
        dialog.setLocationRelativeTo(this);
        JPanel header = new JPanel(new BorderLayout());
        header.setBackground(APP_MENU_BACKGROUND);
        JLabel message = new JLabel(" " + (exists
                ? tr("目標檔案已存在。請檢查 Diff；按下覆寫後仍會再次詢問確認。", "The target file already exists. Review the diff; overwrite will still ask for final confirmation.")
                : tr("尚未建立檔案。請檢查程式碼與路徑；建立後不會自動執行。", "No file has been created. Review the code and path; creation will not auto-run it.")));
        message.setForeground(new Color(255, 216, 140));
        header.add(message, BorderLayout.NORTH);
        JLabel path = new JLabel(" " + target.getAbsolutePath());
        path.setForeground(new Color(185, 215, 255));
        header.add(path, BorderLayout.SOUTH);
        dialog.add(header, BorderLayout.NORTH);

        JTextArea previewArea = new JTextArea(payload.editorPreviewText());
        previewArea.setEditable(false);
        previewArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
        previewArea.setCaretPosition(0);
        JTabbedPane tabs = new JTabbedPane();
        tabs.addTab(payload.notebook() ? tr("Notebook 儲存格預覽", "Notebook Cell Preview") : tr("建議內容", "Proposed Content"), new JScrollPane(previewArea));
        if (payload.notebook()) {
            JTextArea jsonArea = new JTextArea(payload.fileContent());
            jsonArea.setEditable(false);
            jsonArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
            jsonArea.setCaretPosition(0);
            tabs.addTab(tr("實際 .ipynb JSON", "Written .ipynb JSON"), new JScrollPane(jsonArea));
        }
        if (exists) {
            JTextArea diffArea = new JTextArea(buildAiDiffSummary(original, payload.fileContent(), target.getAbsolutePath()));
            diffArea.setEditable(false);
            diffArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
            diffArea.setCaretPosition(0);
            JTextArea originalArea = new JTextArea(original);
            originalArea.setEditable(false);
            originalArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
            JTextArea proposedArea = new JTextArea(payload.fileContent());
            proposedArea.setEditable(false);
            proposedArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
            tabs.addTab(tr("Unified Diff", "Unified Diff"), new JScrollPane(diffArea));
            JSplitPane compare = new JSplitPane(JSplitPane.HORIZONTAL_SPLIT, new JScrollPane(originalArea), new JScrollPane(proposedArea));
            compare.setResizeWeight(0.5);
            tabs.addTab(tr("目前內容 vs 建議內容", "Current vs Proposed"), compare);
        }
        dialog.add(tabs, BorderLayout.CENTER);

        JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT));
        buttons.setBackground(APP_MENU_BACKGROUND);
        JButton copyButton = new JButton(tr("複製程式碼", "Copy Code"));
        JButton writeButton = new JButton(exists ? tr("覆寫檔案...", "Overwrite File...") : tr("建立檔案...", "Create File..."));
        JButton cancelButton = new JButton(tr("取消", "Cancel"));
        copyButton.addActionListener(e -> {
            Toolkit.getDefaultToolkit().getSystemClipboard().setContents(
                    new java.awt.datatransfer.StringSelection(payload.editorPreviewText()), null);
            JOptionPane.showMessageDialog(dialog, tr("程式碼已複製到剪貼簿。", "Code copied to the clipboard."));
        });
        writeButton.addActionListener(e -> {
            if (writeAiGeneratedFileAfterConfirmation(target, payload, exists)) dialog.dispose();
        });
        cancelButton.addActionListener(e -> dialog.dispose());
        for (JButton button : java.util.List.of(copyButton, writeButton, cancelButton)) { styleDarkButton(button); buttons.add(button); }
        dialog.add(buttons, BorderLayout.SOUTH);
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        applyDarkContainerTheme(dialog.getContentPane());
        dialog.setVisible(true);
    }

    private boolean writeAiGeneratedFileAfterConfirmation(File target, AiGeneratedFilePayload payload, boolean exists) {
        if (!requireTrialWriteBuildAccess("Write AI Generated File")) return false;
        String action = exists ? tr("覆寫", "overwrite") : tr("建立", "create");
        int choice = JOptionPane.showConfirmDialog(this,
                tr("確認要", "Confirm that you want to ") + action + tr("此檔案嗎？\n\n", " this file?\n\n")
                        + target.getAbsolutePath() + "\n\n"
                        + tr("只會寫入並在編輯器中開啟檔案；不會自動執行程式或安裝套件。",
                                "This only writes and opens the file in the editor. It will not run code or install packages automatically."),
                exists ? tr("確認覆寫 AI 新檔", "Confirm AI File Overwrite") : tr("確認建立 AI 新檔", "Confirm AI File Creation"),
                JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE);
        if (choice != JOptionPane.YES_OPTION) return false;
        try {
            File parent = target.getParentFile();
            if (parent != null) Files.createDirectories(parent.toPath());
            Files.writeString(target.toPath(), payload.fileContent(), StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING, StandardOpenOption.WRITE);
            updateOrOpenAiGeneratedFile(target, payload);
            appendAiConversation("SYSTEM", tr("AI 新檔已建立：", "AI-generated file created: ") + target.getAbsolutePath()
                    + tr("\n檔案未自動執行或安裝套件。", "\nThe file was not automatically run and no packages were installed."));
            aiSafetyStatusLabel.setText(tr("AI 新檔已建立並開啟；請自行檢查、儲存或手動執行。", "AI-generated file created and opened; review, save, or run it manually."));
            return true;
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                    tr("建立 AI 新檔失敗：\n", "Failed to create the AI-generated file:\n") + ex.getMessage(),
                    tr("建立 AI 新檔", "Create AI New File"), JOptionPane.ERROR_MESSAGE);
            return false;
        }
    }

    private void updateOrOpenAiGeneratedFile(File target, AiGeneratedFilePayload payload) throws IOException {
        EditorTab openTab = findOpenEditorTab(target);
        if (openTab == null) {
            openFile(target);
            return;
        }
        if (payload.notebook()) {
            NotebookModel model = NotebookModel.fromJson(payload.fileContent());
            openTab.notebookModel = model;
            openTab.charset = StandardCharsets.UTF_8;
            openTab.textPane.setText(model.toCellText());
        } else {
            openTab.notebookModel = null;
            openTab.charset = StandardCharsets.UTF_8;
            openTab.textPane.setText(payload.fileContent());
        }
        openTab.file = target.getCanonicalFile();
        openTab.suggestedFileName = target.getName();
        openTab.modified = false;
        tabbedPane.setSelectedComponent(openTab.scrollPane);
        currentDirectory = target.getParentFile();
        addRecentFile(target);
        updateTabTitle(openTab);
        updateStatus();
        SwingUtilities.invokeLater(this::syncActiveEditorFileToNavigationTrees);
    }

    private EditorTab findOpenEditorTab(File target) {
        if (target == null) return null;
        for (int i = 0; i < tabbedPane.getTabCount(); i++) {
            Component component = tabbedPane.getComponentAt(i);
            if (component instanceof JScrollPane scrollPane) {
                Object value = scrollPane.getClientProperty("editorTab");
                if (value instanceof EditorTab tab && sameCanonicalFile(tab.file, target)) return tab;
            }
        }
        return null;
    }

    private String extractAiPatch(String response) {
        if (response == null) return null;
        int start = response.indexOf(AI_PATCH_BEGIN);
        if (start < 0) return null;
        start += AI_PATCH_BEGIN.length();
        int end = response.indexOf(AI_PATCH_END, start);
        if (end < 0) return null;
        String patch = response.substring(start, end);
        if (patch.startsWith("\r\n")) patch = patch.substring(2);
        else if (patch.startsWith("\n")) patch = patch.substring(1);
        if (patch.endsWith("\r\n")) patch = patch.substring(0, patch.length() - 2);
        else if (patch.endsWith("\n")) patch = patch.substring(0, patch.length() - 1);
        return patch;
    }

    private void appendAiConversation(String speaker, String message) {
        String safeMessage = message == null ? "" : message.trim();
        if (!aiConversationArea.getText().isBlank()) aiConversationArea.append("\n\n");
        aiConversationArea.append("[" + speaker + "]\n" + safeMessage);
        aiConversationArea.setCaretPosition(aiConversationArea.getDocument().getLength());
    }

    private void updateAiContextStatus() {
        EditorTab tab = currentTab();
        String selection = tab == null ? "" : tab.textPane.getSelectedText();
        int selectionChars = selection == null ? 0 : selection.length();
        String fileLabel = tab == null ? tr("無目前檔案", "no current file")
                : (tab.file == null ? tr("未儲存檔案", "unsaved file") : tab.file.getName());
        StringBuilder enabledContext = new StringBuilder();
        if (aiSendSelection) enabledContext.append(tr("選取 ", "selection ")).append(selectionChars).append(tr(" 字元", " chars"));
        if (aiSendCurrentFile) {
            if (enabledContext.length() > 0) enabledContext.append(" | ");
            enabledContext.append(tr("檔案 ", "file ")).append(fileLabel);
        }
        if (aiSendConsoleError) {
            if (enabledContext.length() > 0) enabledContext.append(" | ");
            enabledContext.append(tr("Console", "Console"));
        }
        if (aiFullProjectScan) {
            if (enabledContext.length() > 0) enabledContext.append(" | ");
            enabledContext.append(tr("Workbench 專案 Context ON", "Workbench Project Context ON"));
        }
        if (!aiAttachedPaths.isEmpty()) {
            if (enabledContext.length() > 0) enabledContext.append(" | ");
            enabledContext.append(tr("附件 ", "attachments ")).append(aiAttachedPaths.size());
        }
        if (enabledContext.length() == 0) enabledContext.append(tr("未選擇 Context", "no context selected"));
        String selectedSummary = aiProviderDisplay(aiProviderMode) + " | " + aiActionDisplay(currentAiAction());
        aiContextStatusLabel.setText(tr("AI：", "AI: ") + selectedSummary + " | "
                + tr("Context：", "Context: ") + enabledContext);
        aiSafetyStatusLabel.setText(aiAttachedPaths.isEmpty()
                ? tr("安全：Patch／新檔需預覽 + 確認；AI 不會自動執行或安裝。",
                        "Safety: patches/new files need preview + confirmation; AI never auto-runs or installs.")
                : tr("安全：附件僅在按送出時讀取；.venv／密鑰會排除；PNG/JPG/GIF/WebP 圖片最多 4 張會作為視覺輸入。",
                        "Safety: attachments are read only on Send; .venv and secrets are excluded; up to 4 PNG/JPG/GIF/WebP images are sent as visual inputs."));
    }

