    private void chooseAiFiles(boolean imagesOnly) {
        JFileChooser chooser = new JFileChooser(currentDirectory != null ? currentDirectory : new File(System.getProperty("user.home", ".")));
        chooser.setDialogTitle(imagesOnly ? tr("選擇要附加的圖片", "Choose image(s) to attach")
                : tr("選擇要附加的資料或檔案", "Choose data or file(s) to attach"));
        chooser.setFileSelectionMode(JFileChooser.FILES_ONLY);
        chooser.setMultiSelectionEnabled(true);
        if (imagesOnly) {
            chooser.setAcceptAllFileFilterUsed(false);
            chooser.addChoosableFileFilter(new javax.swing.filechooser.FileNameExtensionFilter(
                    tr("圖片檔（PNG、JPG、GIF、WebP）", "Image files (PNG, JPG, GIF, WebP)"),
                    "png", "jpg", "jpeg", "gif", "webp"));
        }
        styleDarkFileChooser(chooser);
        if (chooser.showOpenDialog(this) == JFileChooser.APPROVE_OPTION) {
            File[] selected = chooser.getSelectedFiles();
            if (selected != null && selected.length > 0) attachFilesToAi(Arrays.asList(selected));
        }
    }

    private void chooseAiFolder() {
        File folder = chooseDirectory(tr("選擇要附加給 AI 的資料夾／uv 專案", "Choose folder / uv project to attach to AI"), currentDirectory);
        if (folder != null) attachFilesToAi(java.util.List.of(folder));
    }

    private void attachCurrentEditorFileToAi() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !tab.file.exists()) {
            JOptionPane.showMessageDialog(this,
                    tr("目前沒有可附加的已儲存檔案。請先儲存目前內容，或使用左側檔案樹／+ 選擇檔案。", "There is no saved current file to attach. Save it first, or choose a file from the left tree / + menu."),
                    tr("AI 附件", "AI Attachments"), JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        attachFilesToAi(java.util.List.of(tab.file));
    }

    private void attachSelectedNavigationItemToAi() {
        File selected = null;
        if (workbenchTree != null && workbenchTree.isFocusOwner()) selected = getSelectedTreeFile(workbenchTree);
        if (selected == null && fileTree != null && fileTree.isFocusOwner()) selected = getSelectedTreeFile(fileTree);
        if (selected == null) selected = getSelectedTreeFile(workbenchTree);
        if (selected == null && fileTree != null) selected = getSelectedTreeFile(fileTree);
        if (selected == null || !selected.exists()) {
            JOptionPane.showMessageDialog(this,
                    tr("請先在左側 Workbench 或檔案瀏覽器選取檔案或資料夾。", "Select a file or folder in the left Workbench or File Browser first."),
                    tr("AI 附件", "AI Attachments"), JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        attachFilesToAi(java.util.List.of(selected));
    }

    /** Rebuilds compact attachment chips below the Prompt text area. */
    private void refreshAiAttachmentStrip() {
        aiAttachmentStrip.removeAll();
        JLabel hint = new JLabel(aiAttachedPaths.isEmpty()
                ? tr("拖放左側檔案／uv 專案資料夾到此處附加", "Drop a left-tree file / uv project folder here to attach")
                : tr("已附加（按 × 移除）：", "Attached (click × to remove):"));
        hint.setForeground(aiAttachedPaths.isEmpty() ? new Color(185, 215, 255) : new Color(255, 216, 140));
        hint.setFont(new Font("Microsoft JhengHei UI", Font.PLAIN, 11));
        aiAttachmentStrip.add(hint);
        for (Map.Entry<String, File> entry : new ArrayList<>(aiAttachedPaths.entrySet())) {
            File file = entry.getValue();
            JPanel chip = new JPanel(new FlowLayout(FlowLayout.LEFT, 2, 0));
            chip.setOpaque(true);
            chip.setBackground(new Color(38, 67, 92));
            chip.setBorder(BorderFactory.createLineBorder(new Color(74, 132, 170)));
            String attachmentIcon = file != null && file.isDirectory() ? "▣ "
                    : (file != null && isAiSupportedImageFile(file.toPath()) ? "▧ " : "▤ ");
            JLabel name = new JLabel(attachmentIcon
                    + abbreviateAiAttachmentName(file == null ? "" : file.getName(), 19));
            name.setForeground(Color.WHITE);
            name.setFont(new Font("Microsoft JhengHei UI", Font.PLAIN, 11));
            name.setToolTipText(file == null ? "" : file.getAbsolutePath());
            JButton remove = new JButton("×");
            remove.setToolTipText(tr("移除此 AI 附件", "Remove this AI attachment"));
            remove.getAccessibleContext().setAccessibleName(tr("移除附件", "Remove attachment"));
            remove.setUI(new BasicButtonUI());
            remove.setOpaque(true);
            remove.setContentAreaFilled(true);
            remove.setBorderPainted(false);
            remove.setFocusPainted(false);
            remove.setMargin(new Insets(0, 2, 0, 2));
            remove.setForeground(Color.WHITE);
            remove.setBackground(new Color(88, 50, 50));
            remove.setFont(new Font(Font.DIALOG, Font.BOLD, 13));
            String key = entry.getKey();
            remove.addActionListener(e -> {
                aiAttachedPaths.remove(key);
                refreshAiAttachmentStrip();
                updateAiContextStatus();
            });
            chip.add(name);
            chip.add(remove);
            aiAttachmentStrip.add(chip);
        }
        aiAttachmentStrip.revalidate();
        aiAttachmentStrip.repaint();
    }

    private String abbreviateAiAttachmentName(String name, int maxChars) {
        if (name == null || name.isBlank()) return tr("未命名項目", "unnamed item");
        if (name.length() <= maxChars) return name;
        return name.substring(0, Math.max(1, maxChars - 1)) + "…";
    }

    /** Records an explicit user-selected attachment; no disk read and no network request occurs here. */
    private void attachFilesToAi(java.util.List<File> droppedFiles) {
        if (droppedFiles == null || droppedFiles.isEmpty()) return;
        int added = 0;
        int duplicate = 0;
        int unavailable = 0;
        for (File raw : droppedFiles) {
            if (raw == null || !raw.exists()) { unavailable++; continue; }
            if (aiAttachedPaths.size() >= AI_MAX_ATTACHMENT_ROOTS) break;
            File normalized;
            String key;
            try {
                normalized = raw.getCanonicalFile();
                key = normalized.getPath();
            } catch (IOException ex) {
                normalized = raw.getAbsoluteFile();
                key = normalized.toPath().normalize().toString();
            }
            if (aiAttachedPaths.containsKey(key)) { duplicate++; continue; }
            aiAttachedPaths.put(key, normalized);
            added++;
        }
        refreshAiAttachmentStrip();
        updateAiContextStatus();
        if (added > 0) {
            aiSafetyStatusLabel.setText(tr("已附加 ", "Attached ") + added
                    + tr(" 個項目；尚未讀取或傳送，請按送出 AI 問題。", " item(s); nothing has been read or sent yet. Click Send to AI when ready."));
        } else if (aiAttachedPaths.size() >= AI_MAX_ATTACHMENT_ROOTS) {
            JOptionPane.showMessageDialog(this,
                    tr("AI 附件上限為 ", "The AI attachment limit is ") + AI_MAX_ATTACHMENT_ROOTS
                            + tr(" 個檔案或資料夾。請先按 × 移除不需要的附件。", " files or folders. Remove an attachment with × first."),
                    tr("AI 附件", "AI Attachments"), JOptionPane.INFORMATION_MESSAGE);
        } else if (unavailable > 0 || duplicate > 0) {
            aiSafetyStatusLabel.setText(tr("附件未變更：項目可能已不存在或已附加。", "Attachments unchanged: an item may be unavailable or already attached."));
        }
    }

    private void showAiDiffPreview() {
        if (aiPatchCandidate == null) {
            JOptionPane.showMessageDialog(this,
                    tr("沒有可套用的 AI Patch。請先取得含有完整 Patch 標記的 AI 回覆。", "There is no applicable AI patch. First obtain an AI response containing a complete patch marker block."),
                    "Patch Diff Preview", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        String diff = buildAiDiffSummary(aiPatchCandidate.originalText, aiPatchCandidate.proposedText, aiPatchCandidate.sourceLabel);
        JDialog dialog = new JDialog(this, tr("AI Patch Diff Preview（尚未修改檔案）", "AI Patch Diff Preview (file not changed)"), true);
        dialog.setLayout(new BorderLayout(6, 6));
        dialog.setSize(1120, 720);
        dialog.setLocationRelativeTo(this);
        JPanel header = new JPanel(new BorderLayout());
        header.setBackground(APP_MENU_BACKGROUND);
        JLabel headerLabel = new JLabel(" " + tr("請先檢查所有差異。按下 Apply Patch 後仍會再次詢問確認。",
                "Review all differences. Apply Patch will still ask for a final confirmation."));
        headerLabel.setForeground(new Color(255, 216, 140));
        header.add(headerLabel, BorderLayout.CENTER);
        dialog.add(header, BorderLayout.NORTH);

        JTextArea diffArea = new JTextArea(diff);
        diffArea.setEditable(false);
        diffArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
        diffArea.setCaretPosition(0);
        JTextArea originalArea = new JTextArea(aiPatchCandidate.originalText);
        originalArea.setEditable(false);
        originalArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
        JTextArea proposedArea = new JTextArea(aiPatchCandidate.proposedText);
        proposedArea.setEditable(false);
        proposedArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
        JTabbedPane tabs = new JTabbedPane();
        tabs.addTab(tr("Unified Diff", "Unified Diff"), new JScrollPane(diffArea));
        JSplitPane comparison = new JSplitPane(JSplitPane.HORIZONTAL_SPLIT, new JScrollPane(originalArea), new JScrollPane(proposedArea));
        comparison.setResizeWeight(0.5);
        tabs.addTab(tr("目前內容 vs 建議內容", "Current vs Proposed"), comparison);
        dialog.add(tabs, BorderLayout.CENTER);

        JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT));
        buttons.setBackground(APP_MENU_BACKGROUND);
        JButton copyButton = new JButton(tr("複製建議內容", "Copy Proposed Content"));
        JButton applyButton = new JButton(tr("Apply Patch...", "Apply Patch..."));
        JButton closeButton = new JButton(tr("取消", "Cancel"));
        copyButton.addActionListener(e -> {
            Toolkit.getDefaultToolkit().getSystemClipboard().setContents(new java.awt.datatransfer.StringSelection(aiPatchCandidate.proposedText), null);
            JOptionPane.showMessageDialog(dialog, tr("建議內容已複製到剪貼簿。", "Proposed content copied to the clipboard."));
        });
        applyButton.addActionListener(e -> {
            if (applyAiPatchAfterConfirmation()) dialog.dispose();
        });
        closeButton.addActionListener(e -> dialog.dispose());
        for (JButton button : java.util.List.of(copyButton, applyButton, closeButton)) { styleDarkButton(button); buttons.add(button); }
        dialog.add(buttons, BorderLayout.SOUTH);
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        applyDarkContainerTheme(dialog.getContentPane());
        dialog.setVisible(true);
    }

    private boolean applyAiPatchAfterConfirmation() {
        if (aiPatchCandidate == null) return false;
        if (!requireTrialWriteBuildAccess("Apply AI Patch")) return false;
        EditorTab target = aiPatchCandidate.targetTab;
        if (target != null && !Objects.equals(target.textPane.getText(), aiPatchCandidate.originalText)) {
            JOptionPane.showMessageDialog(this,
                    tr("目前檔案在 AI 回覆後已被修改。為避免覆蓋新內容，請重新取得 AI Patch。", "The file changed after the AI response. To avoid overwriting newer content, request a new AI patch."),
                    "Apply Patch", JOptionPane.WARNING_MESSAGE);
            return false;
        }
        int choice = JOptionPane.showConfirmDialog(this,
                tr("確認要將已預覽的 AI Patch 套用到 " + aiPatchCandidate.sourceLabel + " 嗎？\n\n"
                                + "此動作只會更新編輯器內容；不會自動儲存、執行程式或安裝套件。",
                        "Apply the previewed AI patch to " + aiPatchCandidate.sourceLabel + "?\n\n"
                                + "This updates editor content only. It will not auto-save, run code, or install packages."),
                "Apply AI Patch", JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE);
        if (choice != JOptionPane.YES_OPTION) return false;
        if (target == null) {
            createUntitledTab();
            target = currentTab();
        }
        if (target == null) return false;
        tabbedPane.setSelectedComponent(target.scrollPane);
        target.textPane.setText(aiPatchCandidate.proposedText);
        target.modified = true;
        updateTabTitle(target);
        updateStatus();
        aiSafetyStatusLabel.setText(tr("Patch 已套用到編輯器；請自行檢查、儲存，並使用 Run 功能手動執行。",
                "Patch applied to the editor. Review and save it, then use Run manually if desired."));
        appendAiConversation("SYSTEM", tr("Patch 已套用；檔案尚未自動儲存或執行。", "Patch applied; the file was not auto-saved or run."));
        return true;
    }

    private String buildAiDiffSummary(String original, String proposed, String label) {
        List<String> oldLines = Arrays.asList((original == null ? "" : original).split("\\R", -1));
        List<String> newLines = Arrays.asList((proposed == null ? "" : proposed).split("\\R", -1));
        int prefix = 0;
        while (prefix < oldLines.size() && prefix < newLines.size() && oldLines.get(prefix).equals(newLines.get(prefix))) prefix++;
        int suffix = 0;
        while (suffix < oldLines.size() - prefix && suffix < newLines.size() - prefix
                && oldLines.get(oldLines.size() - 1 - suffix).equals(newLines.get(newLines.size() - 1 - suffix))) suffix++;
        StringBuilder diff = new StringBuilder();
        diff.append("--- ").append(label).append("\n+++ AI proposed version\n");
        if (prefix == oldLines.size() && prefix == newLines.size()) {
            return diff.append("(No text differences detected.)\n").toString();
        }
        int oldChangedEnd = oldLines.size() - suffix;
        int newChangedEnd = newLines.size() - suffix;
        diff.append("@@ -").append(prefix + 1).append(',').append(Math.max(0, oldChangedEnd - prefix))
                .append(" +").append(prefix + 1).append(',').append(Math.max(0, newChangedEnd - prefix)).append(" @@\n");
        int contextBefore = Math.max(0, prefix - 3);
        for (int i = contextBefore; i < prefix; i++) diff.append(" ").append(oldLines.get(i)).append('\n');
        if (oldChangedEnd - prefix > 2_000 || newChangedEnd - prefix > 2_000) {
            diff.append("# Large change: use the 'Current vs Proposed' tab to inspect every line.\n");
            for (int i = prefix; i < Math.min(oldChangedEnd, prefix + 60); i++) diff.append("-").append(oldLines.get(i)).append('\n');
            if (oldChangedEnd - prefix > 120) diff.append("-... ").append(oldChangedEnd - prefix - 120).append(" old lines omitted here\n");
            for (int i = Math.max(prefix + 60, oldChangedEnd - 60); i < oldChangedEnd; i++) diff.append("-").append(oldLines.get(i)).append('\n');
            for (int i = prefix; i < Math.min(newChangedEnd, prefix + 60); i++) diff.append("+").append(newLines.get(i)).append('\n');
            if (newChangedEnd - prefix > 120) diff.append("+... ").append(newChangedEnd - prefix - 120).append(" proposed lines omitted here\n");
            for (int i = Math.max(prefix + 60, newChangedEnd - 60); i < newChangedEnd; i++) diff.append("+").append(newLines.get(i)).append('\n');
        } else {
            for (int i = prefix; i < oldChangedEnd; i++) diff.append("-").append(oldLines.get(i)).append('\n');
            for (int i = prefix; i < newChangedEnd; i++) diff.append("+").append(newLines.get(i)).append('\n');
        }
        for (int i = oldChangedEnd; i < Math.min(oldLines.size(), oldChangedEnd + 3); i++) diff.append(" ").append(oldLines.get(i)).append('\n');
        return diff.toString();
    }

