        JButton batchUtf8ToolbarButton = addToolbarIconButton(toolbarRow, "⇄", tr("大量轉檔（UTF-8）", "Batch UTF-8"),
                tr("批次將資料夾檔案轉換為 UTF-8", "Batch convert files in a folder to UTF-8"), e -> showBatchConvertUtf8Dialog());
        addToolbarSeparator(toolbarRow);
