        configureRunControlButton(runControlPlayButton, tr("執行", "Play"), "▶", tr("執行目前檔案（F5）", "Run Current (F5)"), e -> runCurrentFileAuto());
        configureRunControlButton(runControlPauseButton, tr("暫停 / 繼續", "Pause / Resume"), "||", tr("暫停或繼續正在執行的程式", "Pause or resume the running program"), e -> toggleEmbeddedProcessPauseResume());
        configureRunControlButton(runControlStopButton, tr("停止", "Stop"), "■", tr("強制停止執行中的程式及其子程序", "Force-stop the running program and its child processes"), e -> stopEmbeddedProcess(true));
        toolbarRow.add(runControlPlayButton);
