        toolbarPanel.add(toolbarRow, BorderLayout.CENTER);
        Dimension preferred = toolbarRow.getPreferredSize();
        toolbarPanel.setPreferredSize(new Dimension(preferred.width + 3, 30));
        toolbarPanel.setMinimumSize(new Dimension(Math.min(preferred.width + 3, 420), 30));
