    private JPanel createToolbarWrapRow() {
        // The compact tools begin immediately beside the ? menu.  The row itself
        // remains a single non-wrapping line, so the workspace keeps its height.
        JPanel row = new JPanel(new FlowLayout(FlowLayout.LEFT, 1, 2));
        row.setOpaque(true);
        row.setBackground(APP_MENU_BACKGROUND);
        row.setAlignmentX(Component.LEFT_ALIGNMENT);
        row.setBorder(BorderFactory.createEmptyBorder(0, 1, 0, 1));
        return row;
    }

    private void addToolbarSeparator(JPanel row) {
        JSeparator separator = new JSeparator(SwingConstants.VERTICAL);
        separator.setForeground(APP_BORDER_COLOR);
        separator.setBackground(APP_BORDER_COLOR);
        separator.setPreferredSize(new Dimension(1, 21));
        row.add(separator);
    }

    /** Icon-only IDE control; full function remains available through tooltip and accessibility name. */
    private JButton addToolbarIconButton(JPanel row, String iconText, String accessibleName,
                                         String tooltip, ActionListener listener) {
        JButton button = new JButton(iconText);
        button.addActionListener(listener);
        button.setToolTipText(tooltip);
        button.getAccessibleContext().setAccessibleName(accessibleName);
        button.setFocusable(false);
        styleToolbarIconButton(button);
        row.add(button);
        return button;
    }

    private void styleToolbarIconButton(JButton button) {
        if (button == null) return;
        button.setUI(new BasicButtonUI());
        button.setOpaque(true);
        button.setContentAreaFilled(true);
        button.setBorderPainted(true);
        button.setFocusPainted(false);
        button.setRolloverEnabled(true);
        button.setBackground(APP_MENU_ITEM_BACKGROUND);
        button.setForeground(APP_MENU_FOREGROUND);
        button.setFont(new Font("Dialog", Font.BOLD, 13));
        button.setMargin(new Insets(0, 0, 0, 0));
        button.setHorizontalAlignment(SwingConstants.CENTER);
        button.setPreferredSize(new Dimension(25, 24));
        button.setMinimumSize(new Dimension(25, 24));
        button.setMaximumSize(new Dimension(25, 24));
        button.setBorder(BorderFactory.createCompoundBorder(
                BorderFactory.createLineBorder(APP_BORDER_COLOR),
                BorderFactory.createEmptyBorder(1, 1, 1, 1)));
        button.addMouseListener(new MouseAdapter() {
            @Override public void mouseEntered(MouseEvent e) {
                if (button.isEnabled()) button.setBackground(APP_MENU_HOVER_BACKGROUND);
            }
            @Override public void mouseExited(MouseEvent e) {
                if (button.isEnabled()) button.setBackground(APP_MENU_ITEM_BACKGROUND);
            }
        });
    }

    private void styleToolbarIconToggle(JCheckBox button) {
        button.setOpaque(true);
        button.setBackground(APP_MENU_ITEM_BACKGROUND);
        button.setForeground(APP_MENU_FOREGROUND);
        button.setFocusPainted(false);
        button.setFont(new Font("Dialog", Font.BOLD, 13));
        button.setHorizontalAlignment(SwingConstants.CENTER);
        button.setMargin(new Insets(0, 0, 0, 0));
        button.setPreferredSize(new Dimension(25, 24));
        button.setMinimumSize(new Dimension(25, 24));
        button.setMaximumSize(new Dimension(25, 24));
        button.setBorder(BorderFactory.createCompoundBorder(
                BorderFactory.createLineBorder(APP_BORDER_COLOR),
                BorderFactory.createEmptyBorder(1, 1, 1, 1)));
    }

    /** Compact colored ▶ / || / ■ run-state controls; no text label consumes toolbar width. */
    private void configureRunControlButton(JButton button, String text, String symbol,
                                           String tooltip, ActionListener listener) {
        button.setText("");
        button.getAccessibleContext().setAccessibleName(text);
        button.addActionListener(listener);
        button.setToolTipText(tooltip);
        button.setFocusable(false);
        button.setIconTextGap(0);
        styleToolbarIconButton(button);
        setRunControlVisual(button, text, symbol, new Color(245, 85, 85), false, tooltip);
    }

    private void newUntitledTab() {
        if (!requireTrialWriteBuildAccess("Create New File")) return;
        createUntitledTab();
    }

    // ---------------------------------------------------------------------
    // V0.2.37-08: high-contrast, independently closable lower execution tabs
    // ---------------------------------------------------------------------

    /**
     * Configure the lower execution tabs independently from the editor-file tabs.
     * Both lower tabs have × controls. When both are removed, the right editor
     * pane occupies the full vertical area until the terminal or variable-toolbar
     * icon is used to reopen a panel.
     */
    private void configureExecutionBottomTabs() {
        executionBottomTabs.setOpaque(true);
        executionBottomTabs.setTabPlacement(JTabbedPane.TOP);
        executionBottomTabs.setTabLayoutPolicy(JTabbedPane.SCROLL_TAB_LAYOUT);
        executionBottomTabs.setBackground(APP_MENU_BACKGROUND);
        executionBottomTabs.setForeground(Color.WHITE);
        executionBottomTabs.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        executionBottomTabs.addChangeListener(e -> updateExecutionBottomTabStyles());
    }

    /** Adds one lower execution tab once, then refreshes the custom header style. */
    private void addExecutionBottomTab(Component content, String title, String tooltip) {
        if (executionBottomTabs.indexOfComponent(content) >= 0) return;
        executionBottomTabs.addTab(title, content);
        int index = executionBottomTabs.indexOfComponent(content);
        ExecutionBottomTabHeader header = new ExecutionBottomTabHeader(content, title, tooltip);
        executionBottomTabs.setTabComponentAt(index, header);
        executionBottomTabs.setToolTipTextAt(index, tooltip);
        if (content == embeddedConsolePanel) embeddedConsoleTabOpen = true;
        if (content == variableMonitorPanel) variableMonitorTabOpen = true;
        updateExecutionBottomTabStyles();
    }

    private boolean isExecutionBottomTabOpen(Component content) {
        return executionBottomTabs.indexOfComponent(content) >= 0;
    }

    /** Reattach the lower tab container after it was fully collapsed. */
    private void ensureExecutionBottomTabsAttached() {
        if (rightVerticalSplitPane.getBottomComponent() != executionBottomTabs) {
            rightVerticalSplitPane.setBottomComponent(executionBottomTabs);
        }
        executionBottomTabs.setVisible(true);
    }

    /** Expands the lower area only after a user action or a program execution needs it. */
    private void expandExecutionBottomArea(Component select) {
        ensureExecutionBottomTabsAttached();
        if (select != null && isExecutionBottomTabOpen(select)) {
            executionBottomTabs.setSelectedComponent(select);
        }
        rightVerticalSplitPane.revalidate();
        rightVerticalSplitPane.repaint();
        SwingUtilities.invokeLater(() -> rightVerticalSplitPane.setDividerLocation(0.70));
    }

    /** Collapses the lower split pane completely when neither lower tab remains. */
    private void collapseExecutionBottomAreaIfEmpty() {
        if (executionBottomTabs.getTabCount() > 0) return;
        executionBottomTabs.setVisible(false);
        rightVerticalSplitPane.setBottomComponent(null);
        rightVerticalSplitPane.revalidate();
        rightVerticalSplitPane.repaint();
        SwingUtilities.invokeLater(() -> rightVerticalSplitPane.setDividerLocation(1.0));
    }

    /** Opens/reselects the embedded console from the toolbar or a run action. */
    private void showEmbeddedConsolePanel() {
        if (!isExecutionBottomTabOpen(embeddedConsolePanel)) {
            addExecutionBottomTab(
                    embeddedConsolePanel,
                    tr("嵌入式控制台", "Embedded Console"),
                    tr("顯示程式輸出、輸入與 Streamlit 服務訊息", "Show program output, input, and Streamlit service messages"));
        }
        embeddedConsoleTabOpen = true;
        expandExecutionBottomArea(embeddedConsolePanel);
    }

    /** Opens/reselects the variable monitor from the toolbar or View/Data Capture menu. */
    private void reopenVariableMonitorPanel() {
        if (!isExecutionBottomTabOpen(variableMonitorPanel)) {
            addExecutionBottomTab(
                    variableMonitorPanel,
                    tr("變數監測", "Variable Monitor"),
                    tr("顯示即時變數資料表與波型圖", "Show live variable data table and waveform"));
        }
        variableMonitorTabOpen = true;
        expandExecutionBottomArea(variableMonitorPanel);
    }

    /**
     * Closes one lower tab. Closing the console during a running child process
     * explicitly asks whether to stop that process first, so no hidden execution
     * continues after the panel disappears.
     */
    private boolean closeExecutionBottomTab(Component target) {
        if (target == null || !isExecutionBottomTabOpen(target)) return true;
        if (target == embeddedConsolePanel && isEmbeddedProgramRunning()) {
            int choice = JOptionPane.showConfirmDialog(this,
                    tr("目前仍有程式在嵌入式控制台執行。要先停止程序，再關閉控制台分頁嗎？",
                            "A program is still running in the Embedded Console. Stop it before closing the console tab?"),
                    tr("關閉嵌入式控制台", "Close Embedded Console"),
                    JOptionPane.YES_NO_OPTION,
                    JOptionPane.WARNING_MESSAGE);
            if (choice != JOptionPane.YES_OPTION) return false;
            stopEmbeddedProcess(true);
        }
        executionBottomTabs.remove(target);
        if (target == embeddedConsolePanel) embeddedConsoleTabOpen = false;
        if (target == variableMonitorPanel) variableMonitorTabOpen = false;
        updateExecutionBottomTabStyles();
        collapseExecutionBottomAreaIfEmpty();
        return true;
    }

    /** Repaints selected / normal / hover states for every lower tab header. */
    private void updateExecutionBottomTabStyles() {
        Component selected = executionBottomTabs.getSelectedComponent();
        for (int i = 0; i < executionBottomTabs.getTabCount(); i++) {
            Component content = executionBottomTabs.getComponentAt(i);
            Component headerComponent = executionBottomTabs.getTabComponentAt(i);
            if (headerComponent instanceof ExecutionBottomTabHeader header) {
                boolean isSelected = content == selected;
                header.applyState(isSelected);
                executionBottomTabs.setBackgroundAt(i,
                        isSelected ? EXECUTION_TAB_SELECTED_BACKGROUND : EXECUTION_TAB_BACKGROUND);
                executionBottomTabs.setForegroundAt(i, Color.WHITE);
            }
        }
        executionBottomTabs.revalidate();
        executionBottomTabs.repaint();
    }

    /** Custom lower-tab header with a compact × close control. */
    private final class ExecutionBottomTabHeader extends JPanel {
        private final Component target;
        private final JLabel titleLabel = new JLabel();
        private final JButton closeButton = new JButton("×");
        private boolean hovered;
        private boolean closeHovered;

        ExecutionBottomTabHeader(Component target, String title, String tooltip) {
            super(new BorderLayout(2, 0));
            this.target = target;
            setOpaque(true);
            setToolTipText(tooltip);
            setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
            setBorder(BorderFactory.createEmptyBorder(0, 7, 0, 3));

            titleLabel.setText(" " + title + " ");
            titleLabel.setOpaque(false);
            titleLabel.setForeground(Color.WHITE);
            titleLabel.setFont(new Font("Microsoft JhengHei UI", Font.BOLD, 13));
            titleLabel.setToolTipText(tooltip);
            add(titleLabel, BorderLayout.CENTER);

            closeButton.setText("×");
            closeButton.setToolTipText(tr("關閉此分頁", "Close this tab"));
            closeButton.getAccessibleContext().setAccessibleName(tr("關閉 ", "Close ") + title);
            closeButton.setUI(new BasicButtonUI());
            closeButton.setOpaque(true);
            closeButton.setContentAreaFilled(true);
            closeButton.setBorderPainted(false);
            closeButton.setFocusPainted(false);
            closeButton.setFocusable(false);
            closeButton.setForeground(Color.WHITE);
            closeButton.setFont(new Font("Dialog", Font.BOLD, 16));
            closeButton.setMargin(new Insets(0, 0, 0, 0));
            closeButton.setPreferredSize(new Dimension(22, EXECUTION_TAB_HEADER_HEIGHT - 4));
            closeButton.setMinimumSize(new Dimension(22, EXECUTION_TAB_HEADER_HEIGHT - 4));
            closeButton.addActionListener(e -> closeExecutionBottomTab(this.target));
            closeButton.addMouseListener(new MouseAdapter() {
                @Override public void mouseEntered(MouseEvent e) { closeHovered = true; updateExecutionBottomTabStyles(); }
                @Override public void mouseExited(MouseEvent e) { closeHovered = false; updateExecutionBottomTabStyles(); }
            });
            add(closeButton, BorderLayout.EAST);

            MouseAdapter mouseAdapter = new MouseAdapter() {
                @Override public void mousePressed(MouseEvent e) {
                    if (isExecutionBottomTabOpen(ExecutionBottomTabHeader.this.target)) {
                        executionBottomTabs.setSelectedComponent(ExecutionBottomTabHeader.this.target);
                    }
                }
                @Override public void mouseEntered(MouseEvent e) {
                    hovered = true;
                    updateExecutionBottomTabStyles();
                }
                @Override public void mouseExited(MouseEvent e) {
                    Point p = SwingUtilities.convertPoint(e.getComponent(), e.getPoint(), ExecutionBottomTabHeader.this);
                    if (!ExecutionBottomTabHeader.this.contains(p)) {
                        hovered = false;
                        updateExecutionBottomTabStyles();
                    }
                }
            };
            addMouseListener(mouseAdapter);
            titleLabel.addMouseListener(mouseAdapter);
        }

        void applyState(boolean selected) {
            Color background = selected
                    ? EXECUTION_TAB_SELECTED_BACKGROUND
                    : (hovered ? EXECUTION_TAB_HOVER_BACKGROUND : EXECUTION_TAB_BACKGROUND);
            setBackground(background);
            titleLabel.setForeground(Color.WHITE);
            closeButton.setText("×");
            closeButton.setForeground(Color.WHITE);
            closeButton.setBackground(closeHovered ? new Color(151, 35, 35) : background);
            closeButton.setVisible(true);
            setBorder(selected
                    ? BorderFactory.createCompoundBorder(
                            BorderFactory.createMatteBorder(0, 0, 2, 0, EXECUTION_TAB_SELECTED_BORDER),
                            BorderFactory.createEmptyBorder(0, 7, 0, 3))
                    : BorderFactory.createCompoundBorder(
                            BorderFactory.createLineBorder(APP_BORDER_COLOR),
                            BorderFactory.createEmptyBorder(0, 7, 0, 3)));
            int titleWidth = Math.min(190, Math.max(70, titleLabel.getPreferredSize().width));
            Dimension preferred = new Dimension(titleWidth + 28, EXECUTION_TAB_HEADER_HEIGHT);
            setPreferredSize(preferred);
            setMinimumSize(new Dimension(96, EXECUTION_TAB_HEADER_HEIGHT));
            setMaximumSize(new Dimension(260, EXECUTION_TAB_HEADER_HEIGHT));
        }
    }

    /** Internal helper used only when the current trial mode permits a new tab. */
    private void createUntitledTab() {
        EditorTab tab = new EditorTab(null, StandardCharsets.UTF_8, "");
        addEditorTab(tab, tr("未命名", "untitled"));
        tab.modified = false;
        updateTabTitle(tab);
    }

    /** Creates a new editable Jupyter Notebook in AICodingEditor's cell-text mode. */
    private void newJupyterNotebook() {
        if (!requireTrialWriteBuildAccess("Create Jupyter Notebook")) return;
        NotebookModel model = NotebookModel.createEmpty();
        EditorTab tab = new EditorTab(null, StandardCharsets.UTF_8, model.toCellText());
        tab.notebookModel = model;
        tab.suggestedFileName = "Untitled_Notebook.ipynb";
        addEditorTab(tab, tr("未命名 Notebook", "untitled notebook"));
        tab.modified = false;
        updateTabTitle(tab);
        JOptionPane.showMessageDialog(this,
                tr("Notebook 已建立為儲存格文字模式。\n\n# %% 代表 Python 程式碼儲存格。\n# %% [markdown] 代表 Markdown 儲存格。\n儲存時會自動寫回標準 .ipynb JSON 格式。",
                        "The notebook opens in cell-text mode.\n\n# %% starts a Python code cell.\n# %% [markdown] starts a Markdown cell.\nSaving writes a standard .ipynb JSON file."),
                "Jupyter Notebook", JOptionPane.INFORMATION_MESSAGE);
    }

    private void addEditorTab(EditorTab tab, String title) {
        tabbedPane.addTab(title, tab.scrollPane);
        int index = tabbedPane.indexOfComponent(tab.scrollPane);
        tabbedPane.setSelectedIndex(index);
        tab.scrollPane.putClientProperty("editorTab", tab);

        configureTabHeader(tab);
        tabbedPane.setTabComponentAt(index, tab.tabHeader);

        applyEditorTheme(tab);
        tab.textPane.setEditable(hasTrialWriteBuildAccess());
        updateTabTitle(tab);
        updateTabHeaderStyles();
        // Force the custom header, including its visible × button, to be laid out
        // after the tab becomes part of the platform-specific JTabbedPane.
        SwingUtilities.invokeLater(() -> {
            tab.tabHeader.revalidate();
            tab.tabHeader.doLayout();
            tab.tabHeader.repaint();
            tabbedPane.revalidate();
            tabbedPane.repaint();
            syncActiveEditorFileToNavigationTrees();
        });
        updateStatus();
    }

    private void configureTabHeader(EditorTab tab) {
        tab.tabHeader.removeAll();
        // BorderLayout permanently reserves an EAST column for the close control.
        // FlowLayout can clip the final child at some Windows DPI scaling levels.
        tab.tabHeader.setLayout(new BorderLayout(2, 0));
        tab.tabHeader.setOpaque(true);
        tab.tabHeader.setBackground(TAB_BACKGROUND);

        // A fixed tab width prevents long filenames from making the tab row uneven.
        // The full file name remains available from the tooltip.
        Dimension tabSize = new Dimension(TAB_HEADER_WIDTH, TAB_HEADER_HEIGHT);
        tab.tabHeader.setPreferredSize(tabSize);
        tab.tabHeader.setMinimumSize(tabSize);
        tab.tabHeader.setMaximumSize(tabSize);

        tab.tabTitleLabel.setOpaque(false);
        tab.tabTitleLabel.setForeground(Color.WHITE);
        tab.tabTitleLabel.setFont(new Font("Microsoft JhengHei UI", Font.BOLD, 13));
        tab.tabTitleLabel.setHorizontalAlignment(SwingConstants.LEFT);
        tab.tabTitleLabel.setBorder(BorderFactory.createEmptyBorder(0, 2, 0, 0));
        tab.tabTitleLabel.setMinimumSize(new Dimension(0, TAB_HEADER_HEIGHT - 4));
        tab.tabHeader.add(tab.tabTitleLabel, BorderLayout.CENTER);

        tab.tabCloseButton.setText("×");
        tab.tabCloseButton.setVisible(true);
        tab.tabCloseButton.setToolTipText(tr("關閉此程式碼分頁", "Close this editor tab"));
        tab.tabCloseButton.getAccessibleContext().setAccessibleName(tr("關閉程式碼分頁", "Close editor tab"));
        tab.tabCloseButton.setUI(new BasicButtonUI());
        tab.tabCloseButton.setOpaque(true);
        tab.tabCloseButton.setContentAreaFilled(true);
        tab.tabCloseButton.setBorderPainted(true);
        tab.tabCloseButton.setFocusPainted(false);
        tab.tabCloseButton.setFocusable(false);
        tab.tabCloseButton.setForeground(Color.WHITE);
        tab.tabCloseButton.setFont(new Font("Dialog", Font.BOLD, 17));
        tab.tabCloseButton.setMargin(new Insets(0, 0, 1, 0));
        tab.tabCloseButton.setHorizontalAlignment(SwingConstants.CENTER);
        tab.tabCloseButton.setVerticalAlignment(SwingConstants.CENTER);
        Dimension closeSize = new Dimension(26, TAB_HEADER_HEIGHT - 4);
        tab.tabCloseButton.setPreferredSize(closeSize);
        tab.tabCloseButton.setMinimumSize(closeSize);
        tab.tabCloseButton.setMaximumSize(closeSize);
        for (ActionListener listener : tab.tabCloseButton.getActionListeners()) {
            tab.tabCloseButton.removeActionListener(listener);
        }
        tab.tabCloseButton.addActionListener(e -> closeEditorTabFromHeader(tab));
        tab.tabCloseButton.addMouseListener(new MouseAdapter() {
            @Override public void mouseEntered(MouseEvent e) { tab.tabCloseHovered = true; updateTabHeaderStyles(); }
            @Override public void mouseExited(MouseEvent e) { tab.tabCloseHovered = false; updateTabHeaderStyles(); }
        });
        tab.tabHeader.add(tab.tabCloseButton, BorderLayout.EAST);

        MouseAdapter tabMouseAdapter = new MouseAdapter() {
            @Override public void mousePressed(MouseEvent e) {
                tabbedPane.setSelectedComponent(tab.scrollPane);
            }

            @Override public void mouseEntered(MouseEvent e) {
                tab.tabHeaderHovered = true;
                updateTabHeaderStyles();
            }

            @Override public void mouseExited(MouseEvent e) {
                // Do not clear hover when moving between the header and its text label.
                Point p = SwingUtilities.convertPoint(e.getComponent(), e.getPoint(), tab.tabHeader);
                if (!tab.tabHeader.contains(p)) {
                    tab.tabHeaderHovered = false;
                    updateTabHeaderStyles();
                }
            }
        };
        tab.tabHeader.addMouseListener(tabMouseAdapter);
        tab.tabTitleLabel.addMouseListener(tabMouseAdapter);
    }

    /** Header × action; retains the normal unsaved-change confirmation. */
    private void closeEditorTabFromHeader(EditorTab tab) {
        if (tab == null) return;
        tabbedPane.setSelectedComponent(tab.scrollPane);
        if (closeTab(tab, true) && tabbedPane.getTabCount() == 0 && hasTrialWriteBuildAccess()) {
            createUntitledTab();
        }
    }

    private void updateTabHeaderStyles() {
        Component selected = tabbedPane.getSelectedComponent();
        for (int i = 0; i < tabbedPane.getTabCount(); i++) {
            Component component = tabbedPane.getComponentAt(i);
            if (component instanceof JScrollPane scrollPane
                    && scrollPane.getClientProperty("editorTab") instanceof EditorTab tab) {
                boolean isSelected = component == selected;
                Color bg = isSelected
                        ? TAB_SELECTED_BACKGROUND
                        : (tab.tabHeaderHovered ? TAB_HOVER_BACKGROUND : TAB_BACKGROUND);
                tab.tabHeader.setBackground(bg);
                tab.tabHeader.setBorder(isSelected
                        ? BorderFactory.createCompoundBorder(
                                BorderFactory.createMatteBorder(0, 0, 2, 0, TAB_SELECTED_BORDER),
                                BorderFactory.createEmptyBorder(3, 9, 1, 9))
                        : BorderFactory.createCompoundBorder(
                                BorderFactory.createLineBorder(APP_BORDER_COLOR),
                                BorderFactory.createEmptyBorder(3, 9, 3, 9)));
                tab.tabTitleLabel.setForeground(Color.WHITE);
                tab.tabCloseButton.setForeground(Color.WHITE);
                Color closeBackground = tab.tabCloseHovered ? new Color(151, 35, 35) : bg;
                tab.tabCloseButton.setBackground(closeBackground);
                tab.tabCloseButton.setBorder(BorderFactory.createLineBorder(
                        tab.tabCloseHovered ? new Color(255, 130, 130) : new Color(130, 130, 130)));
                tab.tabCloseButton.setVisible(true);
                tabbedPane.setBackgroundAt(i, bg);
                tabbedPane.setForegroundAt(i, Color.WHITE);
            }
        }
        tabbedPane.revalidate();
        tabbedPane.repaint();
    }

    private EditorTab currentTab() {
        Component comp = tabbedPane.getSelectedComponent();
        if (comp instanceof JScrollPane sp) {
            Object o = sp.getClientProperty("editorTab");
            if (o instanceof EditorTab tab) return tab;
        }
        return null;
    }

    private JTextPane currentTextPane() {
        EditorTab tab = currentTab();
        return tab == null ? null : tab.textPane;
    }

    // ---------------------------------------------------------------------
    // V0.1.16: safe play / pause-resume / force-stop execution controls
    // ---------------------------------------------------------------------

    private void registerRunActionControl(AbstractButton control) {
        if (control != null && !runActionControls.contains(control)) {
            runActionControls.add(control);
        }
    }

    /** Registers controls disabled whenever trial expiry/unverified time makes the IDE read-only. */
    private void registerTrialRestrictedControl(AbstractButton control) {
        if (control != null && !trialRestrictedControls.contains(control)) {
            trialRestrictedControls.add(control);
        }
    }

    private boolean isEmbeddedProgramRunning() {
        Process process = embeddedProcess;
        return process != null && process.isAlive();
    }

    /** Guards keyboard shortcuts and direct method calls as well as toolbar/menu controls. */
    private boolean blockNewBuildOrRunWhileProgramActive(String actionName) {
        if (!requireTrialWriteBuildAccess(actionName)) return true;
        if (streamlitBootstrapInProgress || jupyterBootstrapInProgress) {
            String preparation = streamlitBootstrapInProgress ? "Streamlit" : "Jupyter";
            appendConsoleText(embeddedConsoleArea,
                    "\n[" + actionName + " blocked] " + preparation + " dependency setup is in progress. Please wait.\n");
            Toolkit.getDefaultToolkit().beep();
            return true;
        }
        if (!isEmbeddedProgramRunning()) return false;
        appendConsoleText(embeddedConsoleArea,
                "\n[" + actionName + " blocked] A program is still running. Use Pause / Resume or Stop first.\n");
        Toolkit.getDefaultToolkit().beep();
        return true;
    }

    private void updateEmbeddedExecutionControls() {
        Runnable refresh = () -> {
            boolean alive = isEmbeddedProgramRunning();
            boolean streamlitPreparing = streamlitBootstrapInProgress || jupyterBootstrapInProgress;
            EmbeddedExecutionState state = alive ? embeddedExecutionState : EmbeddedExecutionState.IDLE;
            boolean running = state == EmbeddedExecutionState.RUNNING;
            boolean paused = state == EmbeddedExecutionState.PAUSED;
            boolean stopping = state == EmbeddedExecutionState.STOPPING;

            boolean trialAllowsBuildRun = hasTrialWriteBuildAccess();
            for (AbstractButton control : runActionControls) control.setEnabled(!alive && !streamlitPreparing && trialAllowsBuildRun);

            // Green: action available. Red: currently unavailable or active/paused/stopping state.
            setRunControlVisual(runControlPlayButton, tr("執行", "Play"), "▶",
                    (!alive && !streamlitPreparing && trialAllowsBuildRun) ? new Color(65, 220, 110) : new Color(245, 85, 85),
                    !alive && !streamlitPreparing && trialAllowsBuildRun,
                    !trialAllowsBuildRun ? "Trial read-only mode: build and run are locked"
                            : (streamlitPreparing ? "Python dependency setup is in progress"
                            : (alive ? "A program is already running" : "Run Current (F5)")));
            setRunControlVisual(runControlPauseButton, tr("暫停 / 繼續", "Pause / Resume"), "||",
                    paused ? new Color(245, 85, 85) : (running ? new Color(65, 220, 110) : new Color(245, 85, 85)),
                    running || paused,
                    paused ? "Paused. Click || to resume" : (running ? "Click || to pause" : "No program is running"));
            setRunControlVisual(runControlStopButton, tr("停止", "Stop"), "■",
                    (running || paused) ? new Color(65, 220, 110) : new Color(245, 85, 85),
                    running || paused,
                    stopping ? "Stopping the program..." : ((running || paused) ? "Force-stop running program" : "No program is running"));

            // In command mode the dedicated Close-stdin button is not useful and
            // used to consume most of the lower input bar width.  Hide it until a
            // child program is actually running and waiting for stdin.
            embeddedConsoleCloseInputButton.setVisible(alive);
            if (alive) {
                embeddedConsoleStopButton.setText(stopping ? tr("停止中...", "Stopping...") : tr("停止程序", "Stop Process"));
                embeddedConsoleStopButton.setEnabled(!stopping);
            } else {
                embeddedConsoleStopButton.setText(tr("隱藏控制台", "Hide Console"));
                embeddedConsoleStopButton.setEnabled(true);
            }
            if (embeddedConsolePanel != null) {
                embeddedConsolePanel.revalidate();
                embeddedConsolePanel.repaint();
            }
        };
        if (SwingUtilities.isEventDispatchThread()) refresh.run();
        else SwingUtilities.invokeLater(refresh);
    }

    private void setRunControlVisual(JButton button, String text, String symbol, Color symbolColor,
                                     boolean enabled, String tooltip) {
        if (button == null) return;
        RunControlSymbolIcon icon = new RunControlSymbolIcon(symbol, symbolColor);
        button.setText("");
        button.getAccessibleContext().setAccessibleName(text);
        button.setIcon(icon);
        button.setDisabledIcon(icon); // Preserve the requested green/red symbol even when disabled.
        button.setToolTipText(tooltip);
        button.setEnabled(enabled);
    }

    /** Small colored symbol icon: ▶ = play, || = pause/resume, ■ = force stop. */
    private static final class RunControlSymbolIcon implements Icon {
        private final String symbol;
        private final Color color;

        RunControlSymbolIcon(String symbol, Color color) {
            this.symbol = symbol == null ? "" : symbol;
            this.color = color == null ? Color.WHITE : color;
        }

        @Override public int getIconWidth() { return 22; }
        @Override public int getIconHeight() { return 20; }

        @Override
        public void paintIcon(Component component, Graphics graphics, int x, int y) {
            Graphics2D g2 = (Graphics2D) graphics.create();
            try {
                g2.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING,
                        RenderingHints.VALUE_TEXT_ANTIALIAS_ON);
                g2.setColor(color);
                g2.setFont(new Font("Dialog", Font.BOLD, 17));
                FontMetrics metrics = g2.getFontMetrics();
                int drawX = x + Math.max(0, (getIconWidth() - metrics.stringWidth(symbol)) / 2);
                int drawY = y + (getIconHeight() - metrics.getHeight()) / 2 + metrics.getAscent();
                g2.drawString(symbol, drawX, drawY);
            } finally {
                g2.dispose();
            }
        }
    }

    // ---------------------------------------------------------------------
    // V0.1.21: 7-day internal trial, based on HTTPS server time
    // ---------------------------------------------------------------------

    private enum TrialAccessMode {
        FULL_ACCESS,
        LICENSED_FULL_ACCESS,
        READ_ONLY_EXPIRED,
        READ_ONLY_TIME_UNVERIFIED,
        READ_ONLY_STATE_INVALID
    }

    private static final class TrialState {
        private final long firstTrustedEpochDay;
        private final long lastTrustedEpochDay;
        private final String signature;

        TrialState(long firstTrustedEpochDay, long lastTrustedEpochDay, String signature) {
            this.firstTrustedEpochDay = firstTrustedEpochDay;
            this.lastTrustedEpochDay = lastTrustedEpochDay;
            this.signature = signature == null ? "" : signature;
        }
    }

    private static final class InternetTimeResult {
        private final LocalDate localDate;
        private final String source;

        InternetTimeResult(LocalDate localDate, String source) {
            this.localDate = localDate;
            this.source = source == null ? "" : source;
        }
    }

    private static final class TrialStatus {
        private final TrialAccessMode mode;
        private final LocalDate trustedToday;
        private final LocalDate startedOn;
        private final LocalDate expiresOn;
        private final long daysElapsed;
        private final long daysRemaining;
        private final String timeSource;
        private final String detail;

        TrialStatus(TrialAccessMode mode, LocalDate trustedToday, LocalDate startedOn,
                    LocalDate expiresOn, long daysElapsed, long daysRemaining,
                    String timeSource, String detail) {
            this.mode = mode;
            this.trustedToday = trustedToday;
            this.startedOn = startedOn;
            this.expiresOn = expiresOn;
            this.daysElapsed = daysElapsed;
            this.daysRemaining = daysRemaining;
            this.timeSource = timeSource == null ? "" : timeSource;
            this.detail = detail == null ? "" : detail;
        }

        static TrialStatus bootstrap() {
            return new TrialStatus(TrialAccessMode.READ_ONLY_TIME_UNVERIFIED,
                    null, null, null, 0, 0, "", "Trial time has not been verified yet.");
        }

        boolean allowsWriteBuildRun() {
            return mode == TrialAccessMode.FULL_ACCESS || mode == TrialAccessMode.LICENSED_FULL_ACCESS;
        }
    }

    /**
     * Checks Internet time on every launch.  The server Date header supplies the
     * trusted instant; it is then converted into the PC's local time zone only
     * for displaying/counting calendar days to the user.
     */
    private TrialStatus evaluateTrialStatusAtStartup() {
        TrialStatus licensedStatus = loadValidProductLicenseStatus();
        if (licensedStatus != null) return licensedStatus;

        InternetTimeResult internetTime = requestInternetTime();
        if (internetTime == null) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_TIME_UNVERIFIED,
                    null, null, null, 0, 0, "",
                    "Internet time could not be verified. Connect to the Internet and restart the application.");
        }

        long todayEpochDay = internetTime.localDate.toEpochDay();
        TrialState preferencesState = loadTrialStateFromPreferences();
        TrialState fileState = loadTrialStateFromLocalFile();
        TrialState state;

        if (preferencesState == null && fileState == null) {
            state = createSignedTrialState(todayEpochDay, todayEpochDay);
            if (!saveTrialState(state)) {
                return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                        internetTime.localDate, null, null, 0, 0, internetTime.source,
                        "Unable to save the local trial state. The program is read-only to prevent an untracked trial.");
            }
        } else if (preferencesState == null || fileState == null) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                    internetTime.localDate, null, null, 0, 0, internetTime.source,
                    "The local trial state is incomplete. Trial reset or state removal is not permitted.");
        } else if (!sameTrialState(preferencesState, fileState) || !isTrialStateSignatureValid(preferencesState)) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                    internetTime.localDate, null, null, 0, 0, internetTime.source,
                    "The local trial state did not pass integrity verification.");
        } else {
            state = preferencesState;
        }

        if (state.firstTrustedEpochDay > todayEpochDay || state.lastTrustedEpochDay > todayEpochDay) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                    internetTime.localDate, null, null, 0, 0, internetTime.source,
                    "Internet time is earlier than the stored trusted trial date. The state is locked to prevent clock rollback.");
        }

        if (todayEpochDay > state.lastTrustedEpochDay) {
            state = createSignedTrialState(state.firstTrustedEpochDay, todayEpochDay);
            if (!saveTrialState(state)) {
                return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                        internetTime.localDate, null, null, 0, 0, internetTime.source,
                        "Unable to update the trusted trial date. The program is read-only.");
            }
        }

        LocalDate startedOn = LocalDate.ofEpochDay(state.firstTrustedEpochDay);
        LocalDate expiresOn = startedOn.plusDays(TRIAL_DURATION_DAYS);
        long daysElapsed = Math.max(0L, todayEpochDay - state.firstTrustedEpochDay);
        long daysRemaining = Math.max(0L, TRIAL_DURATION_DAYS - daysElapsed);
        if (daysElapsed >= TRIAL_DURATION_DAYS) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_EXPIRED,
                    internetTime.localDate, startedOn, expiresOn, daysElapsed, 0, internetTime.source,
                    "The 7-day internal trial has ended. Contact the author for an updated build.");
        }
        return new TrialStatus(TrialAccessMode.FULL_ACCESS,
                internetTime.localDate, startedOn, expiresOn, daysElapsed, daysRemaining, internetTime.source,
                "Internet time verified.");
    }

    /** Returns a calendar day derived from an HTTPS Date header. */
    private InternetTimeResult requestInternetTime() {
        for (String endpoint : INTERNET_TIME_ENDPOINTS) {
            HttpURLConnection connection = null;
            try {
                URL url = URI.create(endpoint).toURL();
                connection = (HttpURLConnection) url.openConnection();
                connection.setConnectTimeout(3500);
                connection.setReadTimeout(3500);
                connection.setUseCaches(false);
                connection.setRequestProperty("User-Agent", APP_NAME + "/" + APP_VERSION + " Internal Trial Check");
                connection.setRequestMethod("HEAD");
                connection.connect();
                long serverMillis = connection.getHeaderFieldDate("Date", -1L);
                if (serverMillis <= 0L) serverMillis = connection.getDate();
                if (serverMillis > 0L) {
                    LocalDate localDate = Instant.ofEpochMilli(serverMillis)
                            .atZone(ZoneId.systemDefault()).toLocalDate();
                    return new InternetTimeResult(localDate, endpoint);
                }
            } catch (Exception ignored) {
                // Try the next independent Internet time source.
            } finally {
                if (connection != null) connection.disconnect();
            }
        }
        return null;
    }

    private TrialState loadTrialStateFromPreferences() {
        long first = preferences.getLong(TRIAL_FIRST_DAY_KEY, Long.MIN_VALUE);
        long last = preferences.getLong(TRIAL_LAST_DAY_KEY, Long.MIN_VALUE);
        String signature = preferences.get(TRIAL_SIGNATURE_KEY, "");
        if (first == Long.MIN_VALUE || last == Long.MIN_VALUE || signature.isBlank()) return null;
        return new TrialState(first, last, signature);
    }

    private TrialState loadTrialStateFromLocalFile() {
        File stateFile = getTrialStateFile();
        if (!stateFile.isFile()) return null;
        Properties props = new Properties();
        try (FileInputStream input = new FileInputStream(stateFile)) {
            props.load(input);
            long first = Long.parseLong(props.getProperty("firstTrustedEpochDay", ""));
            long last = Long.parseLong(props.getProperty("lastTrustedEpochDay", ""));
            String signature = props.getProperty("signature", "");
            if (signature.isBlank()) return null;
            return new TrialState(first, last, signature);
        } catch (Exception ignored) {
            return null;
        }
    }

    private boolean saveTrialState(TrialState state) {
        if (state == null || !isTrialStateSignatureValid(state)) return false;
        try {
            preferences.putLong(TRIAL_FIRST_DAY_KEY, state.firstTrustedEpochDay);
            preferences.putLong(TRIAL_LAST_DAY_KEY, state.lastTrustedEpochDay);
            preferences.put(TRIAL_SIGNATURE_KEY, state.signature);
            preferences.flush();

            File stateFile = getTrialStateFile();
            File parent = stateFile.getParentFile();
            if (parent != null) Files.createDirectories(parent.toPath());
            Properties props = new Properties();
            props.setProperty("trialRelease", TRIAL_RELEASE_ID);
            props.setProperty("firstTrustedEpochDay", Long.toString(state.firstTrustedEpochDay));
            props.setProperty("lastTrustedEpochDay", Long.toString(state.lastTrustedEpochDay));
            props.setProperty("signature", state.signature);
            try (FileOutputStream output = new FileOutputStream(stateFile)) {
                props.store(output, APP_NAME + " internal trial state");
            }
            return true;
        } catch (Exception ignored) {
            return false;
        }
    }

    private File getTrialStateFile() {
        String localAppData = System.getenv("LOCALAPPDATA");
        File base = localAppData == null || localAppData.isBlank()
                ? new File(System.getProperty("user.home"), "." + TRIAL_PRODUCT_ID)
                : new File(localAppData, TRIAL_PRODUCT_ID);
        return new File(base, TRIAL_RELEASE_ID + ".state");
    }

    private TrialState createSignedTrialState(long firstTrustedEpochDay, long lastTrustedEpochDay) {
        return new TrialState(firstTrustedEpochDay, lastTrustedEpochDay,
                calculateTrialStateSignature(firstTrustedEpochDay, lastTrustedEpochDay));
    }

    private boolean sameTrialState(TrialState first, TrialState second) {
        return first != null && second != null
                && first.firstTrustedEpochDay == second.firstTrustedEpochDay
                && first.lastTrustedEpochDay == second.lastTrustedEpochDay
                && Objects.equals(first.signature, second.signature);
    }

    private boolean isTrialStateSignatureValid(TrialState state) {
        if (state == null || state.signature == null || state.signature.isBlank()) return false;
        return state.signature.equals(calculateTrialStateSignature(
                state.firstTrustedEpochDay, state.lastTrustedEpochDay));
    }

    private String calculateTrialStateSignature(long firstTrustedEpochDay, long lastTrustedEpochDay) {
        String content = TRIAL_PRODUCT_ID + "|" + TRIAL_RELEASE_ID + "|"
                + firstTrustedEpochDay + "|" + lastTrustedEpochDay + "|"
                + System.getProperty("user.name", "") + "|"
                + System.getProperty("user.home", "") + "|"
                + System.getProperty("os.name", "") + "|" + TRIAL_STATE_SALT;
        try {
            byte[] digest = MessageDigest.getInstance("SHA-256")
                    .digest(content.getBytes(StandardCharsets.UTF_8));
            StringBuilder hex = new StringBuilder(digest.length * 2);
            for (byte value : digest) hex.append(String.format("%02x", value & 0xff));
            return hex.toString();
        } catch (Exception ex) {
            return "";
        }
    }

    private static final class ProductSerialWhitelistEntry {
        private final String serialHash;
        private final String licenseType;
        private final int durationDays;
        private final String description;

        ProductSerialWhitelistEntry(String serialHash, String licenseType, int durationDays, String description) {
            this.serialHash = serialHash == null ? "" : serialHash.trim().toLowerCase(Locale.ROOT);
            this.licenseType = licenseType == null ? "" : licenseType.trim();
            this.durationDays = durationDays;
            this.description = description == null ? "" : description.trim();
        }

        String displayType() {
            if (licenseType.equalsIgnoreCase("TRIAL_30D")) return "30-day trial";
            if (licenseType.equalsIgnoreCase("ANNUAL_365D")) return "1-year license";
            return licenseType.isBlank() ? "serial license" : licenseType;
        }
    }

    private static final class ProductSerialValidationResult {
        private final boolean valid;
        private final String normalizedSerial;
        private final String displaySerial;
        private final String message;
        private final ProductSerialWhitelistEntry entry;

        ProductSerialValidationResult(boolean valid, String normalizedSerial, String message) {
            this(valid, normalizedSerial, message, null);
        }

        ProductSerialValidationResult(boolean valid, String normalizedSerial, String message,
                                      ProductSerialWhitelistEntry entry) {
            this.valid = valid;
            this.normalizedSerial = normalizedSerial == null ? "" : normalizedSerial;
            this.displaySerial = formatProductSerial(this.normalizedSerial);
            this.message = message == null ? "" : message;
            this.entry = entry;
        }
    }

    private static final class ProductLicenseState {
        private final String normalizedSerial;
        private final long activationEpochDay;
        private final int durationDays;
        private final String licenseType;

        ProductLicenseState(String normalizedSerial, long activationEpochDay, int durationDays, String licenseType) {
            this.normalizedSerial = normalizedSerial == null ? "" : normalizedSerial;
            this.activationEpochDay = activationEpochDay;
            this.durationDays = durationDays;
            this.licenseType = licenseType == null ? "" : licenseType;
        }
    }

    private TrialStatus loadValidProductLicenseStatus() {
        String encryptedSerial = preferences.get(PRODUCT_SERIAL_PREFERENCE_KEY, "");
        if (encryptedSerial == null || encryptedSerial.isBlank()) return null;
        ProductLicenseState state = decodeProductLicenseState(decryptAiSecret(encryptedSerial));
        if (state == null || state.normalizedSerial.isBlank()) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                    null, null, null, 0, 0, "Product serial",
                    "Stored product serial state is invalid. Clear the serial and enter a valid new one.");
        }
        ProductSerialValidationResult result = validateProductSerial(state.normalizedSerial);
        if (!result.valid || result.entry == null) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                    null, null, null, 0, 0, "Product serial",
                    "Stored product serial is no longer valid: " + result.message);
        }
        return licensedTrialStatus(result, state.activationEpochDay);
    }

    private TrialStatus licensedTrialStatus(ProductSerialValidationResult result, long activationEpochDay) {
        InternetTimeResult internetTime = requestInternetTime();
        LocalDate today = internetTime == null ? LocalDate.now() : internetTime.localDate;
        String source = internetTime == null ? "Local PC date (license offline fallback)" : internetTime.source;
        long todayEpochDay = today.toEpochDay();
        int durationDays = result.entry == null ? 0 : Math.max(1, result.entry.durationDays);
        LocalDate startedOn = LocalDate.ofEpochDay(activationEpochDay);
        LocalDate expiresOn = startedOn.plusDays(durationDays);
        if (todayEpochDay < activationEpochDay) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_STATE_INVALID,
                    today, startedOn, expiresOn, 0, 0, source,
                    "Current date is earlier than the product serial activation date. This prevents clock rollback.");
        }
        long daysElapsed = Math.max(0L, todayEpochDay - activationEpochDay);
        long daysRemaining = Math.max(0L, durationDays - daysElapsed);
        String masked = maskProductSerial(result == null ? "" : result.displaySerial);
        String type = result.entry == null ? "Product serial" : result.entry.displayType();
        if (daysElapsed >= durationDays) {
            return new TrialStatus(TrialAccessMode.READ_ONLY_EXPIRED,
                    today, startedOn, expiresOn, daysElapsed, 0, source,
                    "Product serial expired. Type: " + type + ", Serial: " + masked);
        }
        return new TrialStatus(TrialAccessMode.LICENSED_FULL_ACCESS,
                today, startedOn, expiresOn, daysElapsed, daysRemaining, source,
                "Product serial activated. Type: " + type + ", Serial: " + masked);
    }

    private void showProductSerialDialog() {
        String prompt = tr(
                "請輸入 25 碼產品序列編號。可含 '-' 分隔符號，例如：XXXXX-XXXXX-XXXXX-XXXXX-XXXXX。\n" +
                        "序列編號驗證成功後，會依序號類型啟用 30 天試用或 1 年授權。\n" +
                        "本視窗不再顯示任何測試序號；請使用發行者提供的序號清單。",
                "Enter a 25-character product serial. Hyphens are allowed, for example: XXXXX-XXXXX-XXXXX-XXXXX-XXXXX.\n" +
                        "After successful validation, the serial enables either a 30-day trial or a 1-year license, depending on the issued serial type.\n" +
                        "This dialog no longer displays any demo serial; use the serial list supplied by the publisher.");
        String input = showHighContrastTextInputDialog(tr("產品序列編號", "Product Serial"), prompt, "");
        if (input == null) return;
        ProductSerialValidationResult result = validateProductSerial(input);
        if (!result.valid || result.entry == null) {
            showHighContrastInfoDialog(tr("產品序列編號無效", "Invalid Product Serial"),
                    tr("產品序列編號無效：\n", "Invalid product serial:\n") + result.message + "\n\n" +
                            tr("請確認是否完整輸入 25 碼，或複製時是否多了空白。", "Please confirm the 25 characters are complete and no extra spaces were copied."),
                    JOptionPane.ERROR_MESSAGE);
            return;
        }
        InternetTimeResult internetTime = requestInternetTime();
        LocalDate today = internetTime == null ? LocalDate.now() : internetTime.localDate;
        long activationEpochDay = today.toEpochDay();
        String stateText = encodeProductLicenseState(result.normalizedSerial, activationEpochDay,
                result.entry.durationDays, result.entry.licenseType);
        String encrypted = encryptAiSecret(stateText);
        if (encrypted.isBlank()) {
            showHighContrastInfoDialog(tr("產品序列編號", "Product Serial"),
                    tr("序列編號驗證成功，但無法寫入本機加密授權資料。", "The serial is valid, but the encrypted local license state could not be saved."),
                    JOptionPane.ERROR_MESSAGE);
            return;
        }
        preferences.put(PRODUCT_SERIAL_PREFERENCE_KEY, encrypted);
        try { preferences.flush(); } catch (Exception ignored) {}
        trialStatus = licensedTrialStatus(result, activationEpochDay);
        applyTrialAccessRestrictions();
        if (tabbedPane.getTabCount() == 0) createUntitledTab();
        updateStatus();
        showHighContrastInfoDialog(tr("產品序列編號已啟用", "Product Serial Activated"),
                tr("產品序列編號驗證成功，AICodingEditor 已啟用。\n\n類型：", "Product serial validated. AICodingEditor is now activated.\n\nType: ")
                        + result.entry.displayType()
                        + tr("\n到期日：", "\nExpires: ") + (trialStatus.expiresOn == null ? "" : trialStatus.expiresOn)
                        + tr("\n序號：", "\nSerial: ") + maskProductSerial(result.displaySerial),
                JOptionPane.INFORMATION_MESSAGE);
    }

    private void clearProductSerialActivation() {
        int choice = showHighContrastConfirmDialog(
                tr("清除產品序列編號", "Clear Product Serial"),
                tr("確定要清除本機儲存的產品序列編號嗎？\n清除後將回到 7 天試用狀態或試用唯讀狀態。",
                        "Clear the locally stored product serial?\nAfter clearing, the application returns to the 7-day trial state or trial read-only state."),
                JOptionPane.WARNING_MESSAGE);
        if (choice != JOptionPane.YES_OPTION) return;
        preferences.remove(PRODUCT_SERIAL_PREFERENCE_KEY);
        try { preferences.flush(); } catch (Exception ignored) {}
        trialStatus = evaluateTrialStatusAtStartup();
        applyTrialAccessRestrictions();
        updateStatus();
        showHighContrastInfoDialog(tr("產品序列編號", "Product Serial"),
                tr("本機產品序列編號已清除。", "The local product serial has been cleared."),
                JOptionPane.INFORMATION_MESSAGE);
    }

    private ProductSerialValidationResult validateProductSerial(String rawSerial) {
        String normalized = normalizeProductSerial(rawSerial);
        if (normalized.length() != PRODUCT_SERIAL_NORMALIZED_LENGTH) {
            return new ProductSerialValidationResult(false, normalized,
                    tr("長度必須為 25 碼，目前為 ", "Length must be 25 characters; current length is ") + normalized.length());
        }
        if (!normalized.matches("[A-Z0-9]{25}")) {
            return new ProductSerialValidationResult(false, normalized,
                    tr("只能使用英文字母 A-Z、數字 0-9 與 '-' 分隔符號。", "Use only A-Z, 0-9, and optional hyphen separators."));
        }
        ProductSerialWhitelistEntry entry = lookupProductSerialWhitelistEntry(normalized);
        if (entry == null) {
            String diag = productSerialWhitelistDiagnostic == null ? "" : productSerialWhitelistDiagnostic;
            return new ProductSerialValidationResult(false, normalized,
                    tr("此序號不在目前版本的授權白名單中。", "This serial is not in the license whitelist for this build.")
                            + (diag.isBlank() ? "" : "\n" + diag));
        }
        if (entry.durationDays <= 0) {
            return new ProductSerialValidationResult(false, normalized,
                    tr("序號白名單中的授權天數無效。", "The serial whitelist duration is invalid."));
        }
        return new ProductSerialValidationResult(true, normalized,
                tr("產品序列編號有效。", "Product serial is valid."), entry);
    }

    private ProductSerialWhitelistEntry lookupProductSerialWhitelistEntry(String normalizedSerial) {
        Map<String, ProductSerialWhitelistEntry> whitelist = loadProductSerialHashWhitelist();
        return whitelist.get(sha256Hex(normalizedSerial));
    }

    private Map<String, ProductSerialWhitelistEntry> loadProductSerialHashWhitelist() {
        if (productSerialWhitelistCache != null) return productSerialWhitelistCache;
        LinkedHashMap<String, ProductSerialWhitelistEntry> result = new LinkedHashMap<>();
        java.util.List<File> candidates = new ArrayList<>();
        for (File base : getDistributionBaseDirectories()) {
            if (base == null) continue;
            candidates.add(new File(new File(base, PRODUCT_SERIAL_HASH_WHITELIST_FOLDER), PRODUCT_SERIAL_HASH_WHITELIST_FILE));
            File parent = base.getParentFile();
            if (parent != null) candidates.add(new File(new File(parent, PRODUCT_SERIAL_HASH_WHITELIST_FOLDER), PRODUCT_SERIAL_HASH_WHITELIST_FILE));
        }
        StringBuilder tried = new StringBuilder();
        for (File file : candidates) {
            if (file == null) continue;
            tried.append(file.getAbsolutePath()).append("\n");
            if (!file.isFile()) continue;
            try {
                java.util.List<String> lines = Files.readAllLines(file.toPath(), StandardCharsets.UTF_8);
                for (String line : lines) {
                    if (line == null || line.isBlank()) continue;
                    String trimmed = line.trim();
                    if (trimmed.startsWith("#") || trimmed.toLowerCase(Locale.ROOT).startsWith("serial_sha256")) continue;
                    String[] columns = trimmed.split(",", -1);
                    if (columns.length < 3) continue;
                    String hash = columns[0].trim().toLowerCase(Locale.ROOT);
                    String type = columns[1].trim();
                    int days;
                    try { days = Integer.parseInt(columns[2].trim()); }
                    catch (NumberFormatException nfe) { continue; }
                    String desc = columns.length >= 4 ? columns[3].trim() : "";
                    if (hash.matches("[0-9a-f]{64}") && days > 0) {
                        result.put(hash, new ProductSerialWhitelistEntry(hash, type, days, desc));
                    }
                }
                productSerialWhitelistDiagnostic = "Loaded " + result.size() + " serial hash(es) from " + file.getAbsolutePath();
                productSerialWhitelistCache = result;
                return productSerialWhitelistCache;
            } catch (IOException ex) {
                productSerialWhitelistDiagnostic = "Unable to read serial hash whitelist: " + ex.getMessage();
            }
        }
        productSerialWhitelistDiagnostic = "Serial hash whitelist file was not found. Expected: License/" + PRODUCT_SERIAL_HASH_WHITELIST_FILE;
        productSerialWhitelistCache = result;
        return productSerialWhitelistCache;
    }

    private String sha256Hex(String value) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] bytes = digest.digest((value == null ? "" : value).getBytes(StandardCharsets.US_ASCII));
            StringBuilder sb = new StringBuilder(bytes.length * 2);
            for (byte b : bytes) sb.append(String.format(Locale.ROOT, "%02x", b & 0xff));
            return sb.toString();
        } catch (Exception ex) {
            return "";
        }
    }

    private String encodeProductLicenseState(String normalizedSerial, long activationEpochDay,
                                             int durationDays, String licenseType) {
        return normalizeProductSerial(normalizedSerial) + "|" + activationEpochDay + "|" + durationDays
                + "|" + (licenseType == null ? "" : licenseType.replace("|", ""));
    }

    private ProductLicenseState decodeProductLicenseState(String text) {
        if (text == null || text.isBlank()) return null;
        String[] parts = text.split("\\|", -1);
        if (parts.length >= 4) {
            try {
                return new ProductLicenseState(normalizeProductSerial(parts[0]), Long.parseLong(parts[1]),
                        Integer.parseInt(parts[2]), parts[3]);
            } catch (Exception ignored) {
                return null;
            }
        }
        // V0.2.37-14 stored only the serial. Treat it as unavailable under the
        // new whitelist-based model so old demo keys are no longer accepted.
        return null;
    }

    private String normalizeProductSerial(String rawSerial) {
        if (rawSerial == null) return "";
        return rawSerial.trim().toUpperCase(Locale.ROOT).replaceAll("[^A-Z0-9]", "");
    }

    private static String formatProductSerial(String normalized) {
        if (normalized == null || normalized.isBlank()) return "";
        String clean = normalized.replaceAll("[^A-Za-z0-9]", "").toUpperCase(Locale.ROOT);
        if (clean.length() != PRODUCT_SERIAL_NORMALIZED_LENGTH) return clean;
        return clean.replaceFirst("(.{5})(.{5})(.{5})(.{5})(.{5})", PRODUCT_SERIAL_DISPLAY_GROUP_PATTERN);
    }

    private String maskProductSerial(String displaySerial) {
        String clean = normalizeProductSerial(displaySerial);
        if (clean.length() < 10) return "";
        return clean.substring(0, 5) + "-*****-*****-*****-" + clean.substring(clean.length() - 5);
    }

    private String base32NoPadding(byte[] data) {
        final char[] alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567".toCharArray();
        StringBuilder out = new StringBuilder((data.length * 8 + 4) / 5);
        int buffer = 0;
        int bitsLeft = 0;
        for (byte value : data) {
            buffer = (buffer << 8) | (value & 0xff);
            bitsLeft += 8;
            while (bitsLeft >= 5) {
                int index = (buffer >> (bitsLeft - 5)) & 0x1f;
                bitsLeft -= 5;
                out.append(alphabet[index]);
            }
        }
        if (bitsLeft > 0) {
            out.append(alphabet[(buffer << (5 - bitsLeft)) & 0x1f]);
        }
        return out.toString();
    }

