    /**
     * Creates default executable commands. Users can keep these command names when the
     * executables are on PATH, or replace any value with a full executable path.
     */
    /**
     * Returns the default executable layout below one common root.  On a normal
     * Windows installation the result is D:\Dev-Cpp, D:\ArduinoCLI,
     * D:\JDK-26.0.1 and D:\SQL_Driver.  The caller may still replace every
     * individual tool path in the settings dialog.
     */
    private static LinkedHashMap<String, String> createDefaultLanguageToolCommands() {
        return createDefaultLanguageToolCommandsForRoot(DEFAULT_TOOLCHAIN_COMMON_ROOT);
    }

    private static LinkedHashMap<String, String> createDefaultLanguageToolCommandsForRoot(String root) {
        LinkedHashMap<String, String> map = new LinkedHashMap<>();
        map.put(TOOL_JAVA_COMPILER, toolchainPath(root, "JDK-26.0.1\\bin\\javac" + executableSuffix(".exe")));
        map.put(TOOL_JAVA_RUNTIME, toolchainPath(root, "JDK-26.0.1\\bin\\java" + executableSuffix(".exe")));
        map.put(TOOL_C_COMPILER, toolchainPath(root, "Dev-Cpp\\MinGW64\\bin\\gcc" + executableSuffix(".exe")));
        map.put(TOOL_CPP_COMPILER, toolchainPath(root, "Dev-Cpp\\MinGW64\\bin\\g++" + executableSuffix(".exe")));
        map.put(TOOL_CSHARP_COMPILER, "csc");
        map.put(TOOL_JAVASCRIPT_RUNTIME, "node");
        map.put(TOOL_PHP_RUNTIME, "php");
        map.put(TOOL_RUST_COMPILER, "rustc");
        map.put(TOOL_ARDUINO_CLI, toolchainPath(root, "ArduinoCLI\\arduino-cli" + executableSuffix(".exe")));
        map.put(TOOL_SQL_CLIENT, toolchainPath(root, "SQL_Driver\\SQLite\\sqlite3" + executableSuffix(".exe")));
        return map;
    }

    private static boolean isWindowsHost() {
        return System.getProperty("os.name", "").toLowerCase(Locale.ROOT).contains("win");
    }

    private static String executableSuffix(String windowsSuffix) {
        return isWindowsHost() ? windowsSuffix : "";
    }

    /**
     * Returns the folder containing AICodingEditor.jar. In the Windows release,
     * AICodingEditor.exe and the jar live side-by-side, so this is also the EXE
     * folder. Tool folders are therefore expected as siblings of the launcher:
     * Dev-Cpp, ArduinoCLI, JDK-26.0.1 and SQL_Driver.
     */
    private static String defaultToolchainCommonRoot() {
        return resolveDistributionDirectoryStatic().getAbsolutePath();
    }

    private static File resolveDistributionDirectoryStatic() {
        try {
            URI codeUri = AICodingEditor.class.getProtectionDomain()
                    .getCodeSource().getLocation().toURI();
            File codeLocation = new File(codeUri);
            File base = codeLocation.isFile() ? codeLocation.getParentFile() : codeLocation;
            if (base != null) return base.getCanonicalFile();
        } catch (Exception ignored) {
            // During development or restricted launchers, fall back to the process folder.
        }
        return new File(System.getProperty("user.dir", ".")).getAbsoluteFile();
    }

    private static String defaultToolchainPath(String relativePath) {
        return toolchainPath(DEFAULT_TOOLCHAIN_COMMON_ROOT, relativePath);
    }

    private static String toolchainPath(String root, String relativePath) {
        String normalizedRoot = normalizeToolchainRootStatic(root);
        String normalizedRelative = relativePath == null ? "" : relativePath
                .replace("\\", File.separator).replace("/", File.separator);
        return new File(normalizedRoot, normalizedRelative).getPath();
    }

    private static String normalizeToolchainRootStatic(String rawRoot) {
        String root = rawRoot == null ? "" : rawRoot.trim();
        if (root.isEmpty()) root = defaultToolchainCommonRoot();
        if ((root.startsWith("\"") && root.endsWith("\"")) ||
                (root.startsWith("'") && root.endsWith("'"))) {
            root = root.substring(1, root.length() - 1).trim();
        }
        if (root.isEmpty()) root = defaultToolchainCommonRoot();
        return root;
    }

