    private void loadLanguageToolchainPreferences() {
        String savedRoot = preferences.get(TOOLCHAIN_COMMON_ROOT_PREFERENCE_KEY, "").trim();
        // Upgrade the old V0.1.29 D:\ default to the new EXE/JAR-sibling root.
        // Explicit custom roots remain untouched.
        if (savedRoot.isBlank() || isLegacyWindowsToolchainRoot(savedRoot)) {
            toolchainCommonRoot = DEFAULT_TOOLCHAIN_COMMON_ROOT;
            if (!savedRoot.isBlank()) preferences.remove(TOOLCHAIN_COMMON_ROOT_PREFERENCE_KEY);
        } else {
            toolchainCommonRoot = normalizeToolchainCommonRoot(savedRoot);
        }
        LinkedHashMap<String, String> rootDefaults = createDefaultLanguageToolCommandsForRoot(toolchainCommonRoot);
        languageToolCommands.clear();
        for (Map.Entry<String, String> entry : rootDefaults.entrySet()) {
            String key = entry.getKey();
            String saved = preferences.get("toolchain.command." + key, "");
            String fallback = entry.getValue();
            String value = (saved == null || saved.isBlank()) ? fallback : saved;
            languageToolCommands.put(key, normalizeToolCommand(value, fallback));
        }
        cppLanguageStandard = normalizeCppLanguageStandard(
                preferences.get(CPP_LANGUAGE_STANDARD_PREFERENCE_KEY, DEFAULT_CPP_LANGUAGE_STANDARD));
        arduinoFqbn = preferences.get(ARDUINO_FQBN_PREFERENCE_KEY, DEFAULT_ARDUINO_FQBN).trim();
        if (arduinoFqbn.isBlank()) arduinoFqbn = DEFAULT_ARDUINO_FQBN;
        arduinoLibraryRoot = normalizeArduinoLibraryRoot(
                preferences.get(ARDUINO_LIBRARY_ROOT_PREFERENCE_KEY,
                        toolchainPath(toolchainCommonRoot, "Arduino\\libraries")));
        sqlDatabaseTarget = preferences.get(SQL_DATABASE_TARGET_PREFERENCE_KEY, DEFAULT_SQL_DATABASE_TARGET).trim();
        if (sqlDatabaseTarget.isBlank()) sqlDatabaseTarget = DEFAULT_SQL_DATABASE_TARGET;
    }

    private String normalizeToolchainCommonRoot(String rawRoot) {
        return normalizeToolchainRootStatic(rawRoot);
    }

    /** True only for the former Windows default D:\ (including a trailing slash). */
    private boolean isLegacyWindowsToolchainRoot(String rawRoot) {
        if (!isWindowsPlatform() || rawRoot == null) return false;
        String normalized = rawRoot.trim().replace('/', '\\');
        return normalized.equalsIgnoreCase("D:") || normalized.equalsIgnoreCase(LEGACY_WINDOWS_TOOLCHAIN_COMMON_ROOT);
    }

    private String getDefaultMsSqlDriverRootForToolchainRoot() {
        return toolchainPath(toolchainCommonRoot, "SQL_Driver");
    }

    private String getDefaultMySqlDriverRootForToolchainRoot() {
        return toolchainPath(toolchainCommonRoot, "SQL_Driver\\MySQL");
    }

    private String getDefaultPostgreSqlDriverRootForToolchainRoot() {
        return toolchainPath(toolchainCommonRoot, "SQL_Driver\\PostgreSQL");
    }

    private String normalizeToolCommand(String rawValue, String fallback) {
        String value = rawValue == null ? "" : rawValue.trim();
        if (value.isEmpty()) return fallback;
        if ((value.startsWith("\"") && value.endsWith("\"")) ||
                (value.startsWith("'") && value.endsWith("'"))) {
            value = value.substring(1, value.length() - 1).trim();
        }
        return value.isEmpty() ? fallback : value;
    }

    private String getLanguageToolCommand(String toolKey) {
        return normalizeToolCommand(languageToolCommands.get(toolKey),
                DEFAULT_LANGUAGE_TOOL_COMMANDS.getOrDefault(toolKey, ""));
    }

    /** Normalize the persisted C++ standard choice to one supported UI option. */
    private String normalizeCppLanguageStandard(String rawValue) {
        String value = rawValue == null ? "" : rawValue.trim();
        for (String option : cppLanguageStandardOptions()) {
            if (option.equalsIgnoreCase(value)) return option;
        }
        return DEFAULT_CPP_LANGUAGE_STANDARD;
    }

    private String[] cppLanguageStandardOptions() {
        return new String[]{
                CPP_STANDARD_AUTO,
                CPP_STANDARD_CXX98,
                CPP_STANDARD_CXX11,
                CPP_STANDARD_CXX14,
                CPP_STANDARD_CXX17,
                CPP_STANDARD_CXX20
        };
    }

    /** Convert a selected C++ standard label to its g++ compiler flag. */
    private String cppLanguageStandardFlagForChoice(String choice) {
        String normalized = normalizeCppLanguageStandard(choice);
        return switch (normalized) {
            case CPP_STANDARD_CXX98 -> "-std=c++98";
            case CPP_STANDARD_CXX11 -> "-std=c++11";
            case CPP_STANDARD_CXX14 -> "-std=c++14";
            case CPP_STANDARD_CXX17 -> "-std=c++17";
            case CPP_STANDARD_CXX20 -> "-std=c++20";
            default -> "";
        };
    }

    /**
     * Resolve the effective g++ standard flag. In Auto mode we intentionally choose
     * C++11 for legacy GCC 4.x / 5.x / 6.x / 7.x because many releases reject
     * -std=c++17. GCC 8+ receives C++17. If version detection fails, C++11 is the
     * safe compatibility default for old Dev-C++ installations.
     */
    private String resolveCppLanguageStandardFlag(String compiler) {
        String selected = normalizeCppLanguageStandard(cppLanguageStandard);
        if (!CPP_STANDARD_AUTO.equals(selected)) return cppLanguageStandardFlagForChoice(selected);

        int major = detectGppMajorVersion(compiler);
        if (major >= 8) return "-std=c++17";
        if (major >= 4) return "-std=c++11";
        return "";
    }

    private String describeCppLanguageStandard(String compiler, String flag) {
        if (flag == null || flag.isBlank()) return "Compiler default (C++98 compatible)";
        if (CPP_STANDARD_AUTO.equals(normalizeCppLanguageStandard(cppLanguageStandard))) {
            int major = detectGppMajorVersion(compiler);
            return flag + (major > 0 ? " (Auto: GCC " + major + ")" : " (Auto compatibility fallback)");
        }
        return flag + " (selected in Languages & Toolchains)";
    }

    /** Returns the major version reported by g++, or -1 if it cannot be determined. */
    private int detectGppMajorVersion(String compiler) {
        if (compiler == null || compiler.isBlank()) return -1;
        try {
            ProcessBuilder pb = new ProcessBuilder(compiler, "-dumpfullversion", "-dumpversion");
            pb.redirectErrorStream(true);
            Map<String, String> environment = createToolchainRuntimeEnvironment(TOOL_CPP_COMPILER);
            applyAICodingEditorRuntimeEnvironment(pb, environment);
            Process process = pb.start();
            byte[] bytes = process.getInputStream().readAllBytes();
            int exitCode = process.waitFor();
            if (exitCode != 0) return -1;
            Matcher matcher = Pattern.compile("(\\d+)").matcher(new String(bytes, StandardCharsets.UTF_8));
            return matcher.find() ? Integer.parseInt(matcher.group(1)) : -1;
        } catch (IOException ex) {
            return -1;
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            return -1;
        } catch (NumberFormatException ex) {
            return -1;
        }
    }

    private String normalizeArduinoLibraryRoot(String rawRoot) {
        String root = rawRoot == null ? "" : rawRoot.trim();
        if ((root.startsWith("\"") && root.endsWith("\""))
                || (root.startsWith("'") && root.endsWith("'"))) {
            root = root.substring(1, root.length() - 1).trim();
        }
        if (root.isEmpty()) root = DEFAULT_ARDUINO_LIBRARY_ROOT;
        try {
            return new File(root).getCanonicalPath();
        } catch (IOException ignored) {
            return new File(root).getAbsolutePath();
        }
    }

    private File getArduinoLibraryRootDirectory() {
        return new File(normalizeArduinoLibraryRoot(arduinoLibraryRoot));
    }

    /**
     * Resolve the configured executable immediately before ProcessBuilder starts it.
     *
     * Windows GUI applications keep the PATH that existed when Java was launched.
     * Therefore, adding MinGW to Windows PATH while Workbench is already open does
     * not repair a running Workbench process. This method first finds the command
     * in the inherited PATH, then checks well-known Dev-C++ / MinGW folders. It
     * returns a complete executable path whenever possible, which is more reliable
     * than asking CreateProcess to locate a bare gcc or g++ command.
     */
    private String getResolvedLanguageToolCommand(String toolKey) {
        return resolveLanguageToolCommandForExecution(toolKey, getLanguageToolCommand(toolKey));
    }

    private String resolveLanguageToolCommandForExecution(String toolKey, String rawCommand) {
        String configured = normalizeToolCommand(rawCommand,
                DEFAULT_LANGUAGE_TOOL_COMMANDS.getOrDefault(toolKey, ""));
        File configuredFile = new File(configured);
        if (configuredFile.isFile()) {
            return canonicalOrAbsolutePath(configuredFile);
        }

        // Do not silently replace a user-entered path that is invalid. It may be a
        // network/temporary drive that is intentionally unavailable. The only exception
        // is an untouched V0.1.29 common-root default: when that default folder has not
        // been installed yet (especially on macOS), fall back to PATH / known locations.
        if (!isBareExecutableCommand(configured)) {
            if (isUntouchedCommonRootDefaultCommand(toolKey, configured)) {
                File onPath = findExecutableOnCurrentPath(configuredFile.getName());
                if (onPath != null) return canonicalOrAbsolutePath(onPath);
                File knownLocation = findKnownToolExecutable(toolKey);
                if (knownLocation != null) return canonicalOrAbsolutePath(knownLocation);
            }
            return configured;
        }

        File onPath = findExecutableOnCurrentPath(configured);
        if (onPath != null) return canonicalOrAbsolutePath(onPath);

        File knownLocation = findKnownToolExecutable(toolKey);
        if (knownLocation != null) return canonicalOrAbsolutePath(knownLocation);
        return configured;
    }

    /** True when the path exactly matches the generated common-root default. */
    private boolean isUntouchedCommonRootDefaultCommand(String toolKey, String command) {
        String expected = createDefaultLanguageToolCommandsForRoot(toolchainCommonRoot)
                .getOrDefault(toolKey, "");
        if (expected.isBlank() || command == null) return false;
        try {
            return new File(expected).getCanonicalPath().equalsIgnoreCase(
                    new File(command).getCanonicalPath());
        } catch (IOException ignored) {
            return expected.replace('/', '\\').equalsIgnoreCase(command.replace('/', '\\'));
        }
    }

    private boolean isBareExecutableCommand(String command) {
        if (command == null || command.isBlank()) return false;
        return !command.contains("\\") && !command.contains("/") && !new File(command).isAbsolute();
    }

    private String canonicalOrAbsolutePath(File file) {
        try {
            return file.getCanonicalPath();
        } catch (IOException ignored) {
            return file.getAbsolutePath();
        }
    }

    /** Find an executable from the PATH inherited by the currently running Java process. */
    private File findExecutableOnCurrentPath(String executableName) {
        if (executableName == null || executableName.isBlank()) return null;
        String pathValue = System.getenv("PATH");
        if (pathValue == null || pathValue.isBlank()) return null;

        List<String> candidateNames = new ArrayList<>();
        candidateNames.add(executableName);
        if (isWindowsPlatform() && !executableName.toLowerCase(Locale.ROOT).endsWith(".exe")) {
            candidateNames.add(executableName + ".exe");
        }

        for (String rawFolder : pathValue.split(Pattern.quote(File.pathSeparator))) {
            String folder = rawFolder == null ? "" : rawFolder.trim();
            if ((folder.startsWith("\"") && folder.endsWith("\""))
                    || (folder.startsWith("'") && folder.endsWith("'"))) {
                folder = folder.substring(1, folder.length() - 1).trim();
            }
            if (folder.isEmpty()) continue;
            for (String candidateName : candidateNames) {
                File candidate = new File(folder, candidateName);
                if (candidate.isFile()) return candidate;
            }
        }
        return null;
    }

    /**
     * Checks common installations. Dev-C++ is checked first because it is the
     * configured development environment for this Workbench installation.
     */
    private File findKnownToolExecutable(String toolKey) {
        String executable;
        if (TOOL_JAVA_COMPILER.equals(toolKey)) executable = isWindowsPlatform() ? "javac.exe" : "javac";
        else if (TOOL_JAVA_RUNTIME.equals(toolKey)) executable = isWindowsPlatform() ? "java.exe" : "java";
        else if (TOOL_C_COMPILER.equals(toolKey)) executable = isWindowsPlatform() ? "gcc.exe" : "gcc";
        else if (TOOL_CPP_COMPILER.equals(toolKey)) executable = isWindowsPlatform() ? "g++.exe" : "g++";
        else if (TOOL_ARDUINO_CLI.equals(toolKey)) executable = isWindowsPlatform() ? "arduino-cli.exe" : "arduino-cli";
        else return null;

        List<String> folders = new ArrayList<>();
        if (isWindowsPlatform()) {
            // The configured common root is always checked first.
            if (TOOL_JAVA_COMPILER.equals(toolKey) || TOOL_JAVA_RUNTIME.equals(toolKey)) {
                folders.add(toolchainPath(toolchainCommonRoot, "JDK-26.0.1\\bin"));
                String javaHome = System.getenv("JAVA_HOME");
                if (javaHome != null && !javaHome.isBlank()) folders.add(new File(javaHome, "bin").getAbsolutePath());
            } else if (TOOL_ARDUINO_CLI.equals(toolKey)) {
                folders.add(toolchainPath(toolchainCommonRoot, "ArduinoCLI"));
            } else {
                folders.add(toolchainPath(toolchainCommonRoot, "Dev-Cpp\\MinGW64\\bin"));
                folders.add(toolchainPath(toolchainCommonRoot, "Dev-Cpp\\MinGW\\bin"));
                folders.add("C:\\Dev-Cpp\\MinGW64\\bin");
                folders.add("C:\\Dev-Cpp\\MinGW\\bin");
                folders.add("C:\\msys64\\ucrt64\\bin");
                folders.add("C:\\msys64\\mingw64\\bin");
                folders.add("C:\\msys64\\mingw32\\bin");
                folders.add("C:\\MinGW\\bin");
                folders.add("C:\\mingw64\\bin");
            }
        }

        for (String folder : folders) {
            File candidate = new File(folder, executable);
            if (candidate.isFile()) return candidate;
        }
        return null;
    }

    /**
     * The MinGW bin directory is prepended for compiler execution. This also
     * makes companion MinGW DLLs available to compiler subprocesses.
     */
    private Map<String, String> createToolchainRuntimeEnvironment(String toolKey) {
        String executable = getResolvedLanguageToolCommand(toolKey);
        File file = new File(executable);
        File parent = file.isFile() ? file.getParentFile() : null;
        if (parent == null || !parent.isDirectory()) return Collections.emptyMap();

        String previousPath = System.getenv("PATH");
        Map<String, String> environment = new LinkedHashMap<>();
        environment.put("PATH", parent.getAbsolutePath()
                + File.pathSeparator + (previousPath == null ? "" : previousPath));
        return environment;
    }

    /**
     * Runtime-only toolchain PATH. It is inherited by every process launched
     * from AICodingEditor, but deliberately does not edit the Windows global
     * User/System PATH registry values or require administrator permission.
     */
    private java.util.List<File> getBundledToolchainPathDirectories() {
        File root = new File(toolchainCommonRoot == null || toolchainCommonRoot.isBlank()
                ? DEFAULT_TOOLCHAIN_COMMON_ROOT : toolchainCommonRoot);
        java.util.List<File> candidates = java.util.List.of(
                new File(root, "JDK-26.0.1" + File.separator + "bin"),
                new File(root, "Dev-Cpp" + File.separator + "MinGW64" + File.separator + "bin"),
                new File(root, "Dev-Cpp" + File.separator + "MinGW" + File.separator + "bin"),
                new File(root, "ArduinoCLI"),
                new File(root, "SQL_Driver" + File.separator + "SQLite"),
                new File(root, "SQL_Driver")
        );
        java.util.List<File> existing = new ArrayList<>();
        for (File candidate : candidates) {
            if (candidate.isDirectory()) existing.add(candidate);
        }
        return existing;
    }

    private Map<String, String> withAICodingEditorRuntimePath(Map<String, String> overrides) {
        Map<String, String> effective = new LinkedHashMap<>();
        if (overrides != null) {
            for (Map.Entry<String, String> entry : overrides.entrySet()) {
                if (entry.getKey() != null && entry.getValue() != null) effective.put(entry.getKey(), entry.getValue());
            }
        }
        LinkedHashSet<String> pathParts = new LinkedHashSet<>();
        for (File directory : getBundledToolchainPathDirectories()) {
            pathParts.add(canonicalOrAbsolutePath(directory));
        }
        String inheritedOrProvidedPath = effective.getOrDefault("PATH", System.getenv("PATH"));
        if (inheritedOrProvidedPath != null && !inheritedOrProvidedPath.isBlank()) {
            for (String part : inheritedOrProvidedPath.split(Pattern.quote(File.pathSeparator))) {
                if (part != null && !part.isBlank()) pathParts.add(part);
            }
        }
        if (!pathParts.isEmpty()) effective.put("PATH", String.join(File.pathSeparator, pathParts));
        return effective;
    }

    private void applyAICodingEditorRuntimeEnvironment(ProcessBuilder processBuilder,
                                                        Map<String, String> overrides) {
        processBuilder.environment().put("PYTHONIOENCODING", "utf-8");
        processBuilder.environment().putAll(withAICodingEditorRuntimePath(overrides));
    }

    private String bundledToolchainPathSummary() {
        java.util.List<File> dirs = getBundledToolchainPathDirectories();
        if (dirs.isEmpty()) return tr("未發現 EXE 同層工具鏈資料夾", "No EXE-sibling toolchain folders found");
        return dirs.stream().map(File::getAbsolutePath).collect(java.util.stream.Collectors.joining(File.pathSeparator));
    }

    /** Fill C/C++ rows with discoverable Dev-C++ / MinGW executables. */
    private void autoDetectCAndCppToolchains(Map<String, JTextField> fields, Component parent) {
        File gcc = findExecutableOnCurrentPath("gcc");
        if (gcc == null) gcc = findKnownToolExecutable(TOOL_C_COMPILER);
        File gpp = findExecutableOnCurrentPath("g++");
        if (gpp == null) gpp = findKnownToolExecutable(TOOL_CPP_COMPILER);

        boolean found = false;
        StringBuilder report = new StringBuilder();
        if (gcc != null) {
            JTextField field = fields.get(TOOL_C_COMPILER);
            if (field != null) field.setText(canonicalOrAbsolutePath(gcc));
            report.append("C compiler:\n").append(canonicalOrAbsolutePath(gcc)).append("\n\n");
            found = true;
        }
        if (gpp != null) {
            JTextField field = fields.get(TOOL_CPP_COMPILER);
            if (field != null) field.setText(canonicalOrAbsolutePath(gpp));
            report.append("C++ compiler:\n").append(canonicalOrAbsolutePath(gpp)).append("\n");
            found = true;
        }

        if (found) {
            JOptionPane.showMessageDialog(parent,
                    "Detected compiler executable(s). Click Save to keep these full paths.\n\n" + report,
                    "C / C++ Toolchain Detection (V0.1.14)", JOptionPane.INFORMATION_MESSAGE);
        } else {
            JOptionPane.showMessageDialog(parent,
                    "gcc.exe / g++.exe could not be found.\n\n"
                            + "For Dev-C++, browse to:\n"
                            + "D:\\Dev-Cpp\\MinGW64\\bin\\gcc.exe\n"
                            + "D:\\Dev-Cpp\\MinGW64\\bin\\g++.exe",
                    "C / C++ Toolchain Detection (V0.1.14)", JOptionPane.WARNING_MESSAGE);
        }
    }


    private static LinkedHashMap<String, String> createDefaultMsSqlDriverPaths(String root) {
        LinkedHashMap<String, String> map = new LinkedHashMap<>();
        String base = normalizeMsSqlRoot(root);
        // Java default requested by the user.
        map.put(MSSQL_JAVA, base + "\\JDBC\\mssql-jdbc-13.4.0.jre11.jar");
        // C / C++ use the Windows ODBC API.  The ODBC Driver itself must also be installed
        // in Windows; this reference path is the optional import library used by compilation.
        map.put(MSSQL_C, base + "\\C\\odbc32.lib");
        map.put(MSSQL_CPP, base + "\\CPP\\odbc32.lib");
        map.put(MSSQL_CSHARP, base + "\\CSharp\\Microsoft.Data.SqlClient.dll");
        // Runtime package/module directories for Python and Node.js.
        map.put(MSSQL_PYTHON, base + "\\Python\\site-packages");
        map.put(MSSQL_JAVASCRIPT, base + "\\NodeJS\\node_modules");
        // One or more PHP extensions may be separated by semicolons.
        map.put(MSSQL_PHP, base + "\\PHP\\php_sqlsrv.dll");
        // Rust tiberius requires Cargo; this is used as CARGO_HOME when Rust MS SQL support is enabled.
        map.put(MSSQL_RUST, base + "\\Rust\\cargo-home");
        map.put(MSSQL_ARDUINO, base + "\\Arduino\\libraries");
        map.put(MSSQL_SQL, base + "\\SQL\\sqlcmd.exe");
        return map;
    }

