    private static String normalizeSqlDriverRoot(String rawRoot, String fallbackRoot) {
        String fallback = fallbackRoot == null || fallbackRoot.trim().isEmpty() ? defaultToolchainPath("SQL_Driver") : fallbackRoot.trim();
        String root = rawRoot == null ? "" : rawRoot.trim();
        if (root.isEmpty()) root = fallback;
        while (root.endsWith("\\") || root.endsWith("/")) root = root.substring(0, root.length() - 1);
        return root.isEmpty() ? fallback : root;
    }

