            rg.gridx = 3; rg.gridy = row; rg.weightx = 0; rows.add(browse, rg);
            rg.gridx = 4; rg.gridy = row; rg.weightx = 0; rows.add(test, rg);
            enableBoxes.put(key, enabled);
