        scroll.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        scroll.setVerticalScrollBarPolicy(ScrollPaneConstants.VERTICAL_SCROLLBAR_AS_NEEDED);
        scroll.setHorizontalScrollBarPolicy(ScrollPaneConstants.HORIZONTAL_SCROLLBAR_AS_NEEDED);
        scroll.getVerticalScrollBar().setUnitIncrement(18);

        JPanel msSqlPage = new JPanel(new BorderLayout(8, 8));
        msSqlPage.add(top, BorderLayout.NORTH);
        msSqlPage.add(scroll, BorderLayout.CENTER);
        applyDarkContainerTheme(msSqlPage);

