        JButton cancelButton = new JButton("Cancel");
        autoDetectCAndCppButton.addActionListener(e -> autoDetectCAndCppToolchains(fields, dialog));
        resetButton.addActionListener(e -> {
            String selectedRoot = normalizeToolchainCommonRoot(commonRootField.getText());
            commonRootField.setText(selectedRoot);
            LinkedHashMap<String, String> rootDefaults = createDefaultLanguageToolCommandsForRoot(selectedRoot);
            for (Map.Entry<String, JTextField> entry : fields.entrySet()) {
                entry.getValue().setText(rootDefaults.getOrDefault(entry.getKey(), ""));
            }
            cppLanguageStandardBox.setSelectedItem(DEFAULT_CPP_LANGUAGE_STANDARD);
            arduinoFqbnField.setText(DEFAULT_ARDUINO_FQBN);
            arduinoLibraryRootField.setText(toolchainPath(selectedRoot, "Arduino\\libraries"));
            sqlDatabaseField.setText(DEFAULT_SQL_DATABASE_TARGET);
        });
        saveButton.addActionListener(e -> {
            String previousRoot = toolchainCommonRoot;
            toolchainCommonRoot = normalizeToolchainCommonRoot(commonRootField.getText());
            preferences.put(TOOLCHAIN_COMMON_ROOT_PREFERENCE_KEY, toolchainCommonRoot);
            LinkedHashMap<String, String> rootDefaults = createDefaultLanguageToolCommandsForRoot(toolchainCommonRoot);
            for (Map.Entry<String, JTextField> entry : fields.entrySet()) {
                String key = entry.getKey();
                String command = normalizeToolCommand(entry.getValue().getText(), rootDefaults.getOrDefault(key, ""));
                languageToolCommands.put(key, command);
                preferences.put("toolchain.command." + key, command);
            }
            // Keep the separate MS SQL driver root aligned with the common root only
            // when it is still using the prior default. Explicit MS SQL custom paths
            // are intentionally preserved.
            String previousDefaultMsSqlRoot = toolchainPath(previousRoot, "SQL_Driver");
            if (normalizeMsSqlRoot(msSqlDriverRoot).equals(normalizeMsSqlRoot(previousDefaultMsSqlRoot))) {
                msSqlDriverRoot = getDefaultMsSqlDriverRootForToolchainRoot();
                preferences.put(MS_SQL_DRIVER_ROOT_PREFERENCE_KEY, msSqlDriverRoot);
            }
            String previousDefaultMySqlRoot = toolchainPath(previousRoot, "SQL_Driver\\MySQL");
            if (normalizeSqlDriverRoot(mySqlDriverRoot, DEFAULT_MYSQL_DRIVER_ROOT).equals(normalizeSqlDriverRoot(previousDefaultMySqlRoot, DEFAULT_MYSQL_DRIVER_ROOT))) {
                mySqlDriverRoot = getDefaultMySqlDriverRootForToolchainRoot();
                preferences.put(MYSQL_DRIVER_ROOT_PREFERENCE_KEY, mySqlDriverRoot);
            }
            String previousDefaultPostgreSqlRoot = toolchainPath(previousRoot, "SQL_Driver\\PostgreSQL");
            if (normalizeSqlDriverRoot(postgreSqlDriverRoot, DEFAULT_POSTGRESQL_DRIVER_ROOT).equals(normalizeSqlDriverRoot(previousDefaultPostgreSqlRoot, DEFAULT_POSTGRESQL_DRIVER_ROOT))) {
                postgreSqlDriverRoot = getDefaultPostgreSqlDriverRootForToolchainRoot();
                preferences.put(POSTGRESQL_DRIVER_ROOT_PREFERENCE_KEY, postgreSqlDriverRoot);
            }
            cppLanguageStandard = normalizeCppLanguageStandard(
                    Objects.toString(cppLanguageStandardBox.getSelectedItem(), DEFAULT_CPP_LANGUAGE_STANDARD));
            preferences.put(CPP_LANGUAGE_STANDARD_PREFERENCE_KEY, cppLanguageStandard);
            arduinoFqbn = arduinoFqbnField.getText().trim();
            if (arduinoFqbn.isBlank()) arduinoFqbn = DEFAULT_ARDUINO_FQBN;
            arduinoLibraryRoot = normalizeArduinoLibraryRoot(arduinoLibraryRootField.getText());
            sqlDatabaseTarget = sqlDatabaseField.getText().trim();
            if (sqlDatabaseTarget.isBlank()) sqlDatabaseTarget = DEFAULT_SQL_DATABASE_TARGET;
            preferences.put(ARDUINO_FQBN_PREFERENCE_KEY, arduinoFqbn);
            preferences.put(ARDUINO_LIBRARY_ROOT_PREFERENCE_KEY, arduinoLibraryRoot);
            preferences.put(SQL_DATABASE_TARGET_PREFERENCE_KEY, sqlDatabaseTarget);

            // When users browse/select a real arduino-cli.exe path and save it, prepare the
            // classic Arduino AVR core immediately in the Embedded Console.  The setup script
            // checks core list without showing it; an installed core only triggers version +
            // board list, while a missing core triggers update-index + core install arduino:avr.
            String savedArduinoCli = getLanguageToolCommand(TOOL_ARDUINO_CLI);
            if (isExistingArduinoCliExecutable(savedArduinoCli)) {
                dialog.dispose();
                startArduinoAvrCoreSetupInEmbeddedConsole(savedArduinoCli);
            } else {
                JOptionPane.showMessageDialog(dialog, "Language toolchain settings saved.",
                        "Languages & Toolchains", JOptionPane.INFORMATION_MESSAGE);
                dialog.dispose();
            }
        });
        cancelButton.addActionListener(e -> dialog.dispose());
        JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT, 8, 6));
        buttons.add(autoDetectCAndCppButton);
        buttons.add(resetButton);
        buttons.add(saveButton);
        buttons.add(cancelButton);

