    private List<String> detectSuggestedPipPackagesFromCurrentPythonFile() {
        EditorTab tab = currentTab();
        if (tab == null) return List.of();
        String fileName = tab.file == null ? "" : tab.file.getName();
        if (!fileName.isEmpty() && !getFileExtension(fileName).equalsIgnoreCase("py")) return List.of();
        return detectSuggestedPipPackages(tab.textPane.getText());
    }

    private List<String> detectSuggestedPipPackages(String sourceText) {
        if (sourceText == null || sourceText.isBlank()) return List.of();
        LinkedHashSet<String> packages = new LinkedHashSet<>();
        Pattern fromPattern = Pattern.compile("(?m)^\\s*from\\s+([A-Za-z_][A-Za-z0-9_]*)");
        Pattern importPattern = Pattern.compile("(?m)^\\s*import\\s+(.+)$");

        Matcher fromMatcher = fromPattern.matcher(sourceText);
        while (fromMatcher.find()) addKnownPipPackage(packages, fromMatcher.group(1));

        Matcher importMatcher = importPattern.matcher(sourceText);
        while (importMatcher.find()) {
            String clause = importMatcher.group(1).split("#", 2)[0];
            for (String part : clause.split(",")) {
                String module = part.trim().split("\\s+as\\s+", 2)[0].trim();
                int dot = module.indexOf('.');
                if (dot >= 0) module = module.substring(0, dot);
                addKnownPipPackage(packages, module);
            }
        }
        return new ArrayList<>(packages);
    }

    private void addKnownPipPackage(Set<String> packages, String importRoot) {
        if (importRoot == null) return;
        String normalized = importRoot.trim();
        int dot = normalized.indexOf('.');
        if (dot >= 0) normalized = normalized.substring(0, dot);
        String packageName = KNOWN_PYTHON_PACKAGE_MAP.get(normalized);
        if (packageName != null) packages.add(packageName);
    }

    private String buildPythonImportScanSummary() {
        EditorTab tab = currentTab();
        if (tab == null) return "Open a Python file first.\n\nStandard-library modules such as os, re, time, sqlite3, and datetime do not need pip installation.";
        String name = tab.file == null ? "untitled.py" : tab.file.getName();
        if (!getFileExtension(name).equalsIgnoreCase("py")) {
            return "Current tab is not a .py file.\n\nOpen a Python file, then click Scan Current .py.\nStandard-library modules do not need pip installation.";
        }
        List<String> packages = detectSuggestedPipPackages(tab.textPane.getText());
        if (packages.isEmpty()) {
            return "No known third-party package imports were detected.\n\nThe scanner recognizes web/data modules and AI modules such as pandas, numpy, scikit-learn, tensorflow, keras, torch, torchvision, transformers, datasets, opencv-python, xgboost, lightgbm, matplotlib, graphviz, and streamlit.\nStandard-library modules do not need pip installation.";
        }
        return "Suggested pip packages:\n" + String.join(System.lineSeparator(), packages)
                + "\n\nNo pip installation is needed for standard-library modules such as os, re, time, sqlite3, and datetime.";
    }

    private List<String> parsePipPackageList(String rawText) {
        LinkedHashSet<String> packages = new LinkedHashSet<>();
        if (rawText == null) return List.of();
        for (String token : rawText.split("[,;\\s]+")) {
            String value = token.trim();
            if (value.isEmpty()) continue;
            // Allow normal PyPI names, version constraints, extras, and local requirement URLs.
            // Spaces are split above; ProcessBuilder still avoids shell interpretation.
            if (value.matches("[A-Za-z0-9_.\\-\\[\\]=<>!~:@/+]+")) packages.add(value);
        }
        return new ArrayList<>(packages);
    }

    private String importModuleForPipPackage(String packageName) {
        if (packageName == null) return "";
        String normalized = packageName.trim().toLowerCase(Locale.ROOT);
        if (normalized.startsWith("beautifulsoup4")) return "bs4";
        if (normalized.startsWith("webdriver-manager")) return "webdriver_manager";
        if (normalized.startsWith("scikit-learn")) return "sklearn";
        if (normalized.startsWith("opencv-python")) return "cv2";
        if (normalized.startsWith("pillow")) return "PIL";
        if (normalized.startsWith("imbalanced-learn")) return "imblearn";
        int end = normalized.length();
        for (char marker : new char[]{'=', '<', '>', '!', '~', '[', '@'}) {
            int i = normalized.indexOf(marker);
            if (i >= 0) end = Math.min(end, i);
        }
        return normalized.substring(0, end).replace('-', '_');
    }

    private void startPythonImportCheck(List<String> packages) {
        List<String> modules = new ArrayList<>();
        for (String packageName : packages) {
            String module = importModuleForPipPackage(packageName);
            if (!module.isBlank()) modules.add(module);
        }
        if (modules.isEmpty()) return;
        String quotedModules = modules.stream().map(m -> "'" + m.replace("'", "") + "'")
                .collect(java.util.stream.Collectors.joining(", "));
        String script = "import importlib.util\n"
                + "modules = [" + quotedModules + "]\n"
                + "for name in modules:\n"
                + "    print(f'{name}: ' + ('OK' if importlib.util.find_spec(name) else 'MISSING'))\n";
        File workingDirectory = getPythonWorkingDirectory();
        UvPythonProject project = getUvPythonProjectForFile(workingDirectory);
        String interpreter = project == null ? getPythonInterpreterCommand() : project.pythonExecutable.getAbsolutePath();
        startInteractiveConsole(List.of(interpreter, "-X", "utf8", "-c", script),
                workingDirectory, "Python Import Check", StandardCharsets.UTF_8,
                createUvProjectEnvironment(project));
    }

    private void startPythonPipInstall(List<String> packages, boolean userInstall) {
        File workingDirectory = getPythonWorkingDirectory();
        UvPythonProject project = getUvPythonProjectForFile(workingDirectory);
        if (project != null) {
            List<String> command = new ArrayList<>();
            command.add(getUvCommandForExecution());
            command.add("pip");
            command.add("install");
            command.add("--python");
            command.add(project.pythonExecutable.getAbsolutePath());
            command.addAll(packages);
            startInteractiveConsole(command, project.rootDirectory, "uv pip install",
                    StandardCharsets.UTF_8, createUvProjectEnvironment(project));
            return;
        }

        List<String> command = new ArrayList<>();
        command.add(getPythonInterpreterCommand());
        command.add("-X");
        command.add("utf8");
        command.add("-m");
        command.add("pip");
        command.add("install");
        command.add("--disable-pip-version-check");
        if (userInstall) command.add("--user");
        command.addAll(packages);
        startInteractiveConsole(command, workingDirectory, "Python pip install", StandardCharsets.UTF_8);
    }

    private void startPythonPipUpgrade(boolean userInstall) {
        File workingDirectory = getPythonWorkingDirectory();
        UvPythonProject project = getUvPythonProjectForFile(workingDirectory);
        if (project != null) {
            List<String> command = new ArrayList<>();
            command.add(getUvCommandForExecution());
            command.add("pip");
            command.add("install");
            command.add("--upgrade");
            command.add("--python");
            command.add(project.pythonExecutable.getAbsolutePath());
            command.add("pip");
            startInteractiveConsole(command, project.rootDirectory, "uv pip upgrade",
                    StandardCharsets.UTF_8, createUvProjectEnvironment(project));
            return;
        }

        List<String> command = new ArrayList<>();
        command.add(getPythonInterpreterCommand());
        command.add("-X");
        command.add("utf8");
        command.add("-m");
        command.add("pip");
        command.add("install");
        command.add("--upgrade");
        command.add("pip");
        command.add("--disable-pip-version-check");
        if (userInstall) command.add("--user");
        startInteractiveConsole(command, workingDirectory, "Python pip upgrade", StandardCharsets.UTF_8);
    }

    private File getPythonWorkingDirectory() {
        EditorTab tab = currentTab();
        if (tab != null && tab.file != null && tab.file.getParentFile() != null) return tab.file.getParentFile();
        return currentDirectory != null ? currentDirectory : new File(System.getProperty("user.dir"));
    }


    // ---------------------------------------------------------------------
    // uv Python project Workbench integration (V0.1.05)
    // ---------------------------------------------------------------------

    @FunctionalInterface
    private interface UvSetupOutput {
        void append(String text);
    }

    /**
     * One Workbench Python project.  The virtual environment always belongs to
     * the project root and is never shared with other projects.
     */
    private static final class UvPythonProject {
        private final File rootDirectory;
        private final File venvDirectory;
        private final File pythonExecutable;
        private final String pythonVersion;

        UvPythonProject(File rootDirectory, File venvDirectory, File pythonExecutable, String pythonVersion) {
            this.rootDirectory = rootDirectory;
            this.venvDirectory = venvDirectory;
            this.pythonExecutable = pythonExecutable;
            this.pythonVersion = pythonVersion;
        }

        String displayName() {
            return rootDirectory.getName() + " [Python " + pythonVersion + "]";
        }
    }

    /** Loads uv command and default Workbench Python project location. */
    private void loadUvPythonProjectPreferences() {
        uvCommand = normalizeToolCommand(
                preferences.get(UV_COMMAND_PREFERENCE_KEY, DEFAULT_UV_COMMAND),
                DEFAULT_UV_COMMAND
        );

        String defaultFolder = new File(System.getProperty("user.home"), "WorkbenchProjects").getAbsolutePath();
        String savedFolder = preferences.get(UV_PROJECT_ROOT_PREFERENCE_KEY, defaultFolder);
        if (savedFolder == null || savedFolder.isBlank()) savedFolder = defaultFolder;
        uvProjectRootDirectory = new File(savedFolder.trim());
    }


    /**
     * V0.1.33 startup behavior: use the configured Python interpreter to make
     * the uv command available before the user creates a uv project or clicks
     * Streamlit.  The check/installation is asynchronous and only writes to
     * Python's package location, never to the source file being edited.
     */
    private void ensureUvInstalledAtStartup() {
        if (uvStartupBootstrapAttempted || uvStartupBootstrapInProgress) return;
        uvStartupBootstrapAttempted = true;
        uvStartupBootstrapInProgress = true;
        setEmbeddedConsoleVisible(true);
        appendConsoleText(embeddedConsoleArea,
                "\n[uv] Startup check: verifying the uv command for the configured Python environment...\n");

        Thread worker = new Thread(() -> {
            File workingDirectory = getUvProjectRootDirectory();
            String detectedCommand = getUvCommandForExecution();
            boolean available = isUvCommandAvailable(detectedCommand, workingDirectory, Collections.emptyMap());
            ProcessCommandResult installResult = null;
            boolean usedUserFallback = false;

            if (!available) {
                String interpreter = getPythonInterpreterCommand();
                installResult = runBlockingProcess(
                        List.of(interpreter, "-X", "utf8", "-m", "pip", "install",
                                "--disable-pip-version-check", UV_BOOTSTRAP_PACKAGE),
                        workingDirectory, Collections.emptyMap());
                if (!installResult.succeeded()) {
                    // System Python may not be writable.  A --user retry works
                    // for normal non-virtual Python installations on Windows/macOS.
                    usedUserFallback = true;
                    installResult = runBlockingProcess(
                            List.of(interpreter, "-X", "utf8", "-m", "pip", "install",
                                    "--disable-pip-version-check", "--user", UV_BOOTSTRAP_PACKAGE),
                            workingDirectory, Collections.emptyMap());
                }
                detectedCommand = getUvCommandForExecution();
                available = installResult.succeeded()
                        && isUvCommandAvailable(detectedCommand, workingDirectory, Collections.emptyMap());
            }

            final boolean finalAvailable = available;
            final String finalCommand = detectedCommand;
            final ProcessCommandResult finalInstallResult = installResult;
            final boolean finalUsedUserFallback = usedUserFallback;
            SwingUtilities.invokeLater(() -> {
                uvStartupBootstrapInProgress = false;
                uvAvailableForSession = finalAvailable;
                if (finalAvailable) {
                    uvCommand = finalCommand;
                    preferences.put(UV_COMMAND_PREFERENCE_KEY, uvCommand);
                    String message = finalInstallResult == null
                            ? "[uv] Available: " + uvCommand + "\n"
                            : "[uv] Installed and ready: " + uvCommand
                                    + (finalUsedUserFallback ? " (installed with --user)" : "") + "\n";
                    appendConsoleText(embeddedConsoleArea, message);
                } else {
                    String detail = finalInstallResult == null
                            ? "uv was not found."
                            : trimBackgroundCommandOutput(finalInstallResult.output(), finalInstallResult.failureMessage());
                    appendConsoleText(embeddedConsoleArea,
                            "[uv] Automatic installation failed. " + detail + "\n");
                    JOptionPane.showMessageDialog(this,
                            tr("無法自動安裝 uv。\n\n已嘗試：\n"
                                            + getPythonInterpreterCommand() + " -m pip install uv\n\n"
                                            + "請確認 Python 與 pip 可使用，再於設定 → 偏好 → 一般 → uv / Python 專案設定 uv 路徑。\n\n"
                                            + detail,
                                    "AICodingEditor could not install uv automatically.\n\nTried:\n"
                                            + getPythonInterpreterCommand() + " -m pip install uv\n\n"
                                            + "Check that Python and pip are available, then configure uv under Settings → Preference → General → uv / Python Projects.\n\n"
                                            + detail),
                            "uv", JOptionPane.WARNING_MESSAGE);
                }
            });
        }, "aicodingeditor-uv-startup-bootstrap");
        worker.setDaemon(true);
        worker.start();
    }

    /** Returns an executable uv path when it can be resolved from PATH or Python Scripts. */
    private String getUvCommandForExecution() {
        String configured = normalizeToolCommand(uvCommand, DEFAULT_UV_COMMAND);
        File explicit = new File(configured);
        if (explicit.isFile()) return canonicalOrAbsolutePath(explicit);
        if (isBareExecutableCommand(configured)) {
            File onPath = findExecutableOnCurrentPath(configured);
            if (onPath != null) return canonicalOrAbsolutePath(onPath);
            File nearPython = findUvExecutableNearConfiguredPython();
            if (nearPython != null) return canonicalOrAbsolutePath(nearPython);
        }
        return configured;
    }

    /** Looks in common global/user Python Scripts locations without changing PATH. */
    private File findUvExecutableNearConfiguredPython() {
        List<File> candidates = new ArrayList<>();
        String executable = isWindowsPlatform() ? "uv.exe" : "uv";
        File interpreter = new File(getPythonInterpreterCommand());
        if (interpreter.isFile() && interpreter.getParentFile() != null) {
            File parent = interpreter.getParentFile();
            if (isWindowsPlatform()) {
                if (parent.getName().equalsIgnoreCase("Scripts")) {
                    candidates.add(new File(parent, executable));
                } else {
                    candidates.add(new File(new File(parent, "Scripts"), executable));
                }
            } else {
                candidates.add(new File(parent, executable));
                candidates.add(new File(new File(parent.getParentFile() == null ? parent : parent.getParentFile(), "bin"), executable));
            }

            Matcher versionMatcher = Pattern.compile("Python(\\d+)", Pattern.CASE_INSENSITIVE)
                    .matcher(parent.getAbsolutePath());
            String compactVersion = versionMatcher.find() ? versionMatcher.group(1) : "";
            String appData = System.getenv("APPDATA");
            if (isWindowsPlatform() && appData != null && !appData.isBlank()) {
                if (!compactVersion.isBlank()) {
                    candidates.add(new File(new File(new File(new File(appData, "Python"), "Python" + compactVersion), "Scripts"), executable));
                }
                candidates.add(new File(new File(appData, "Python"), "Scripts" + File.separator + executable));
            }
        }
        if (!isWindowsPlatform()) {
            candidates.add(new File(new File(System.getProperty("user.home", "."), ".local/bin"), executable));
        }
        for (File candidate : candidates) {
            if (candidate.isFile()) return candidate;
        }
        return null;
    }

    /** Runs a finite setup/check command from a background thread and captures combined output. */
    private ProcessCommandResult runBlockingProcess(List<String> command, File workingDirectory,
                                                    Map<String, String> environmentOverrides) {
        try {
            ProcessBuilder pb = new ProcessBuilder(command);
            if (workingDirectory != null && workingDirectory.isDirectory()) pb.directory(workingDirectory);
            pb.redirectErrorStream(true);
            applyAICodingEditorRuntimeEnvironment(pb, environmentOverrides);
            Process process = pb.start();
            String output = new String(process.getInputStream().readAllBytes(), StandardCharsets.UTF_8);
            return new ProcessCommandResult(process.waitFor(), output, null);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            return new ProcessCommandResult(-1, "", "Process was interrupted.");
        } catch (IOException ex) {
            return new ProcessCommandResult(-1, "", ex.getMessage());
        }
    }

    private String trimBackgroundCommandOutput(String output, String failureMessage) {
        String text = output == null ? "" : output.trim();
        if (failureMessage != null && !failureMessage.isBlank()) {
            text = text.isBlank() ? failureMessage : text + "\n" + failureMessage;
        }
        if (text.length() > 2400) return text.substring(text.length() - 2400);
        return text.isBlank() ? "No diagnostic output." : text;
    }

    private File getUvProjectRootDirectory() {
        if (uvProjectRootDirectory == null) {
            uvProjectRootDirectory = new File(System.getProperty("user.home"), "WorkbenchProjects");
        }
        return uvProjectRootDirectory;
    }

    /**
     * Settings -> Preference -> General -> uv / Python Projects.
     * The uv command can be either "uv" when it is on PATH or a full uv.exe path.
     */
    private void showUvPythonProjectSettingsDialog() {
        JDialog dialog = new JDialog(this, "uv / Python Projects", true);
        dialog.setLayout(new BorderLayout(8, 8));
        dialog.setSize(850, 260);
        dialog.setLocationRelativeTo(this);

        JPanel panel = new JPanel(new GridBagLayout());
        panel.setBorder(BorderFactory.createEmptyBorder(12, 12, 12, 12));
        GridBagConstraints gbc = new GridBagConstraints();
        gbc.insets = new Insets(5, 5, 5, 5);
        gbc.fill = GridBagConstraints.HORIZONTAL;

        JTextField uvField = new JTextField(uvCommand, 52);
        JTextField projectRootField = new JTextField(getUvProjectRootDirectory().getAbsolutePath(), 52);
        JButton browseUvButton = new JButton("Browse uv.exe...");
        JButton browseRootButton = new JButton("Browse...");
        JButton testUvButton = new JButton("Test uv");
        JButton saveButton = new JButton("Save");
        JButton cancelButton = new JButton("Cancel");

        gbc.gridx = 0; gbc.gridy = 0; gbc.weightx = 0;
        panel.add(new JLabel("uv command:"), gbc);
        gbc.gridx = 1; gbc.gridy = 0; gbc.weightx = 1;
        panel.add(uvField, gbc);
        gbc.gridx = 2; gbc.gridy = 0; gbc.weightx = 0;
        panel.add(browseUvButton, gbc);

        gbc.gridx = 0; gbc.gridy = 1; gbc.weightx = 0;
        panel.add(new JLabel("New project root:"), gbc);
        gbc.gridx = 1; gbc.gridy = 1; gbc.weightx = 1;
        panel.add(projectRootField, gbc);
        gbc.gridx = 2; gbc.gridy = 1; gbc.weightx = 0;
        panel.add(browseRootButton, gbc);

        JLabel note = new JLabel("<html>Each new project creates its own <b>.venv</b> with Python "
                + DEFAULT_UV_PYTHON_VERSION
                + ". Workbench sets <b>KERAS_BACKEND=tensorflow</b> for Python commands in that project.</html>");
        gbc.gridx = 0; gbc.gridy = 2; gbc.gridwidth = 3; gbc.weightx = 1;
        panel.add(note, gbc);
        gbc.gridwidth = 1;

        JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT, 6, 0));
        buttons.add(testUvButton);
        buttons.add(saveButton);
        buttons.add(cancelButton);
        gbc.gridx = 0; gbc.gridy = 3; gbc.gridwidth = 3;
        panel.add(buttons, gbc);

        browseUvButton.addActionListener(e -> {
            JFileChooser chooser = new JFileChooser();
            chooser.setDialogTitle("Select uv.exe");
            chooser.setFileSelectionMode(JFileChooser.FILES_ONLY);
            if (chooser.showOpenDialog(dialog) == JFileChooser.APPROVE_OPTION) {
                uvField.setText(chooser.getSelectedFile().getAbsolutePath());
            }
        });
        browseRootButton.addActionListener(e -> {
            File selected = chooseDirectory("Select default Workbench Python project folder",
                    new File(projectRootField.getText().trim()));
            if (selected != null) projectRootField.setText(selected.getAbsolutePath());
        });
        testUvButton.addActionListener(e -> testUvCommand(uvField.getText(), dialog));
        saveButton.addActionListener(e -> {
            String command = normalizeToolCommand(uvField.getText(), DEFAULT_UV_COMMAND);
            String root = projectRootField.getText() == null ? "" : projectRootField.getText().trim();
            if (root.isEmpty()) {
                JOptionPane.showMessageDialog(dialog, "New project root cannot be empty.",
                        "uv / Python Projects", JOptionPane.WARNING_MESSAGE);
                return;
            }
            File rootFolder = new File(root);
            try {
                Files.createDirectories(rootFolder.toPath());
                rootFolder = rootFolder.getCanonicalFile();
            } catch (IOException ex) {
                JOptionPane.showMessageDialog(dialog, "Cannot create or access this folder:\n"
                                + rootFolder.getAbsolutePath() + "\n\n" + ex.getMessage(),
                        "uv / Python Projects", JOptionPane.ERROR_MESSAGE);
                return;
            }
            uvCommand = command;
            uvProjectRootDirectory = rootFolder;
            preferences.put(UV_COMMAND_PREFERENCE_KEY, uvCommand);
            preferences.put(UV_PROJECT_ROOT_PREFERENCE_KEY, uvProjectRootDirectory.getAbsolutePath());
            JOptionPane.showMessageDialog(dialog,
                    "uv Python project settings saved.\n\nuv command: " + uvCommand
                            + "\nNew project root: " + uvProjectRootDirectory.getAbsolutePath(),
                    "uv / Python Projects", JOptionPane.INFORMATION_MESSAGE);
            dialog.dispose();
        });
        cancelButton.addActionListener(e -> dialog.dispose());

        dialog.add(panel, BorderLayout.CENTER);
        dialog.getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR, 1));
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        applyDarkContainerTheme(dialog.getContentPane());
        dialog.setVisible(true);
    }

    private void testUvCommand(String rawCommand, Component parent) {
        String command = normalizeToolCommand(rawCommand, DEFAULT_UV_COMMAND);
        try {
            ProcessBuilder pb = new ProcessBuilder(command, "--version");
            pb.redirectErrorStream(true);
            Process process = pb.start();
            String output;
            try (java.io.BufferedReader reader = new java.io.BufferedReader(
                    new java.io.InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                output = reader.lines().collect(java.util.stream.Collectors.joining(System.lineSeparator()));
            }
            int exitCode = process.waitFor();
            if (exitCode == 0) {
                JOptionPane.showMessageDialog(parent,
                        "uv is available:\n" + command + "\n\n" + output,
                        "uv Test Success", JOptionPane.INFORMATION_MESSAGE);
            } else {
                JOptionPane.showMessageDialog(parent,
                        "uv returned exit code " + exitCode + ":\n" + command + "\n\n" + output,
                        "uv Test Failed", JOptionPane.ERROR_MESSAGE);
            }
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(parent,
                    "Cannot start uv:\n" + command + "\n\n"
                            + "Install uv, add it to PATH, or choose the full uv.exe path.\n"
                            + ex.getMessage(),
                    "uv Test Failed", JOptionPane.ERROR_MESSAGE);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            JOptionPane.showMessageDialog(parent, "uv test was interrupted.", "uv Test", JOptionPane.ERROR_MESSAGE);
        }
    }

    private void showNewUvPythonProjectDialog() {
        if (!requireTrialWriteBuildAccess("Create New Python Project")) return;
        NewUvPythonProjectDialog dialog = new NewUvPythonProjectDialog();
        dialog.setVisible(true);
    }

    private void openExistingUvPythonProject() {
        File folder = chooseDirectory("Open existing Python uv project", getUvProjectRootDirectory());
        if (folder == null) return;
        try {
            UvPythonProject project = loadUvPythonProject(folder);
            activateUvPythonProject(project, true);
            addWorkbenchRoot(project.rootDirectory);
            saveWorkbenchRoots();
            setFileBrowserRoot(project.rootDirectory);
            File starter = new File(project.rootDirectory, "main.py");
            if (starter.isFile()) openFile(starter);
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                    "Cannot open this as a Workbench Python uv project:\n"
                            + folder.getAbsolutePath() + "\n\n" + ex.getMessage()
                            + "\n\nExpected: " + UV_PROJECT_CONFIG_FILE + " or a .venv containing Python.",
                    "Open Python uv Project", JOptionPane.ERROR_MESSAGE);
        }
    }

    /**
     * When the user opens/selects a file under a uv project, make that environment
     * active.  The global Python Interpreter setting is never overwritten.
     */
    private void tryActivateUvPythonProjectForFolder(File folder, boolean announce) {
        UvPythonProject discovered = findUvPythonProjectForFolder(folder);
        if (discovered != null) activateUvPythonProject(discovered, announce);
    }

    private void activateUvPythonProject(UvPythonProject project, boolean announce) {
        if (project == null) return;
        boolean changed = activeUvPythonProject == null
                || !activeUvPythonProject.rootDirectory.equals(project.rootDirectory);
        activeUvPythonProject = project;
        updateStatus();
        if (announce && changed) {
            setEmbeddedConsoleVisible(true);
            appendConsoleText(embeddedConsoleArea,
                    "\nActive Python uv project: " + project.displayName()
                            + "\nRoot: " + project.rootDirectory.getAbsolutePath()
                            + "\nPython: " + project.pythonExecutable.getAbsolutePath()
                            + "\n");
        }
    }

    /**
     * Read a project created by Workbench.  An existing project with only .venv
     * can also be opened; its metadata is inferred without modifying the project.
     */
    private UvPythonProject loadUvPythonProject(File folder) throws IOException {
        if (folder == null || !folder.exists() || !folder.isDirectory()) {
            throw new IOException("Project folder does not exist.");
        }
        File root = folder.getCanonicalFile();
        Properties properties = new Properties();
        File config = new File(root, UV_PROJECT_CONFIG_FILE);
        if (config.isFile()) {
            try (java.io.Reader reader = Files.newBufferedReader(config.toPath(), StandardCharsets.UTF_8)) {
                properties.load(reader);
            }
        }

        String venvRelative = properties.getProperty("venv.path", UV_PROJECT_VENV_FOLDER).trim();
        if (venvRelative.isEmpty()) venvRelative = UV_PROJECT_VENV_FOLDER;
        File venv = new File(root, venvRelative);

        String defaultPythonRelative = isWindowsPlatform()
                ? UV_PROJECT_VENV_FOLDER + "\\Scripts\\python.exe"
                : UV_PROJECT_VENV_FOLDER + "/bin/python";
        String pythonRelative = properties.getProperty("python.executable", defaultPythonRelative).trim();
        if (pythonRelative.isEmpty()) pythonRelative = defaultPythonRelative;
        File python = new File(root, pythonRelative);

        if (!python.isFile()) {
            // A project without metadata may still have a standard .venv.
            python = pythonInUvVenv(venv);
        }
        if (!python.isFile()) {
            throw new IOException("Project virtual-environment Python is missing:\n" + python.getAbsolutePath());
        }
        String version = properties.getProperty("python.version", DEFAULT_UV_PYTHON_VERSION).trim();
        if (version.isEmpty()) version = DEFAULT_UV_PYTHON_VERSION;
        return new UvPythonProject(root, venv.getCanonicalFile(), python.getCanonicalFile(), version);
    }

    private UvPythonProject findUvPythonProjectForFolder(File folder) {
        File cursor = folder;
        if (cursor != null && cursor.isFile()) cursor = cursor.getParentFile();
        while (cursor != null) {
            File config = new File(cursor, UV_PROJECT_CONFIG_FILE);
            File venv = new File(cursor, UV_PROJECT_VENV_FOLDER);
            if (config.isFile() || venv.isDirectory()) {
                try {
                    return loadUvPythonProject(cursor);
                } catch (IOException ignored) {
                    // This folder is not a usable Workbench uv project. Keep looking upward.
                }
            }
            cursor = cursor.getParentFile();
        }
        return null;
    }

    private UvPythonProject getUvPythonProjectForFile(File sourceFile) {
        UvPythonProject discovered = findUvPythonProjectForFolder(sourceFile);
        if (discovered != null) {
            activateUvPythonProject(discovered, false);
            return discovered;
        }
        if (activeUvPythonProject != null && sourceFile != null
                && isFileInsideDirectory(sourceFile, activeUvPythonProject.rootDirectory)) {
            return activeUvPythonProject;
        }
        return null;
    }

    private boolean isFileInsideDirectory(File child, File parent) {
        if (child == null || parent == null) return false;
        try {
            Path childPath = child.getCanonicalFile().toPath();
            Path parentPath = parent.getCanonicalFile().toPath();
            return childPath.startsWith(parentPath);
        } catch (IOException ex) {
            return false;
        }
    }

    private File pythonInUvVenv(File venv) {
        return isWindowsPlatform()
                ? new File(venv, "Scripts" + File.separator + "python.exe")
                : new File(venv, "bin" + File.separator + "python");
    }

    private boolean isWindowsPlatform() {
        return System.getProperty("os.name", "").toLowerCase(Locale.ROOT).contains("win");
    }

    /**
     * Builds the environment inherited by every Workbench-launched Python command.
     * It places the project .venv Scripts directory first in PATH and sets the
     * correct Keras backend before Python imports Keras.
     */
    private Map<String, String> createUvProjectEnvironment(UvPythonProject project) {
        Map<String, String> environment = new LinkedHashMap<>();
        if (project == null) return environment;

        File scripts = isWindowsPlatform()
                ? new File(project.venvDirectory, "Scripts")
                : new File(project.venvDirectory, "bin");
        String oldPath = System.getenv("PATH");
        environment.put("VIRTUAL_ENV", project.venvDirectory.getAbsolutePath());
        environment.put("PATH", scripts.getAbsolutePath()
                + File.pathSeparator + (oldPath == null ? "" : oldPath));
        environment.put("KERAS_BACKEND", UV_KERAS_BACKEND);
        environment.put("PYTHONUTF8", "1");
        environment.put("PYTHONIOENCODING", "utf-8");
        // V0.2.37-15: keep all future uv operations safe on Windows/OneDrive/cross-volume paths.
        environment.put("UV_LINK_MODE", "copy");
        return environment;
    }

    private Map<String, String> createPythonRuntimeEnvironment(UvPythonProject project,
                                                               List<String> packageDirs) {
        Map<String, String> environment = new LinkedHashMap<>();
        if (packageDirs != null && !packageDirs.isEmpty()) {
            environment.putAll(createRuntimePathEnvironment("PYTHONPATH", packageDirs));
        }
        if (project != null) {
            environment.putAll(createUvProjectEnvironment(project));
        }
        return environment;
    }

    private String pythonInterpreterForFile(File pythonFile) {
        UvPythonProject project = getUvPythonProjectForFile(pythonFile);
        return project == null ? getPythonInterpreterCommand() : project.pythonExecutable.getAbsolutePath();
    }

    /**
     * Creates a new uv Python 3.10 project.  It is executed only in SwingWorker
     * background threads; it can download Python/packages and must not block the UI.
     */
    private UvPythonProject createUvPythonTensorFlowProject(File parentDirectory,
                                                            String projectName,
                                                            UvSetupOutput output)
            throws IOException, InterruptedException {
        if (parentDirectory == null) throw new IOException("Project parent folder is required.");
        String safeName = validateUvProjectName(projectName);
        Files.createDirectories(parentDirectory.toPath());

        File parent = parentDirectory.getCanonicalFile();
        File root = new File(parent, safeName).getCanonicalFile();
        if (!root.getParentFile().equals(parent)) {
            throw new IOException("Invalid project name.");
        }
        if (root.exists()) {
            try (Stream<Path> entries = Files.list(root.toPath())) {
                if (entries.findAny().isPresent()) {
                    throw new IOException("Project directory already exists and is not empty:\n" + root.getAbsolutePath());
                }
            }
        }
        Files.createDirectories(root.toPath());

        appendUvSetupOutput(output, "\n=== Creating Workbench uv Python project ===\n");
        appendUvSetupOutput(output, "Project: " + root.getAbsolutePath() + "\n");
        appendUvSetupOutput(output, "Python:  " + DEFAULT_UV_PYTHON_VERSION + "\n");
        appendUvSetupOutput(output, "Keras backend: " + UV_KERAS_BACKEND + "\n\n");

        writeUvProjectFiles(root, safeName);

        runUvSetupRequired(
                List.of(getUvCommandForExecution(), "--version"),
                root, Collections.emptyMap(), output,
                "Cannot execute uv. Install uv or update Settings -> Preference -> General -> uv / Python Projects."
        );

        runUvSetupRequired(
                List.of(getUvCommandForExecution(), "venv", "--python", DEFAULT_UV_PYTHON_VERSION, UV_PROJECT_VENV_FOLDER),
                root, Collections.emptyMap(), output,
                "Unable to create .venv with Python " + DEFAULT_UV_PYTHON_VERSION
        );

        File venv = new File(root, UV_PROJECT_VENV_FOLDER);
        File python = pythonInUvVenv(venv);
        if (!python.isFile()) {
            throw new IOException("Virtual-environment Python was not created:\n" + python.getAbsolutePath());
        }

        List<String> installCommand = new ArrayList<>();
        installCommand.add(getUvCommandForExecution());
        installCommand.add("pip");
        installCommand.add("install");
        // V0.2.37-15: Windows OneDrive / cross-volume uv caches may not support hardlinks.
        // Force copy mode so package installation can succeed even when uv cache and .venv
        // are on different file systems or under paths that reject hardlinks.
        installCommand.add("--link-mode");
        installCommand.add("copy");
        installCommand.add("--python");
        installCommand.add(python.getAbsolutePath());
        installCommand.addAll(DEFAULT_UV_PYTHON_PACKAGES);
        runUvSetupRequired(
                installCommand,
                root, createUvProjectEnvironment(new UvPythonProject(root, venv, python, DEFAULT_UV_PYTHON_VERSION)),
                output,
                "Unable to install TensorFlow / Keras / Matplotlib / pydot"
        );

        UvPythonProject project = new UvPythonProject(
                root.getCanonicalFile(), venv.getCanonicalFile(), python.getCanonicalFile(), DEFAULT_UV_PYTHON_VERSION
        );
        runUvSetupRequired(
                List.of(project.pythonExecutable.getAbsolutePath(), "-X", "utf8", "-c",
                        "import tensorflow as tf; import keras; import matplotlib; import pydot; "
                                + "print('TensorFlow=' + tf.__version__); "
                                + "print('Keras=' + keras.__version__); "
                                + "print('Matplotlib=' + matplotlib.__version__); "
                                + "print('pydot=' + pydot.__version__); "
                                + "print('KERAS_BACKEND=' + keras.backend.backend())"),
                root, createUvProjectEnvironment(project), output,
                "Installed packages could not be imported"
        );

        appendUvSetupOutput(output,
                "\n✓ Project ready.\n"
                        + "Embedded Console examples:\n"
                        + "  uv pip install pandas scikit-learn\n"
                        + "  python main.py\n"
                        + "  uv pip list\n\n");
        return project;
    }

    private String validateUvProjectName(String projectName) {
        String name = projectName == null ? "" : projectName.trim();
        if (name.isEmpty()) throw new IllegalArgumentException("Project name is required.");
        if (!name.matches("[A-Za-z0-9][A-Za-z0-9 _.-]{0,80}")) {
            throw new IllegalArgumentException(
                    "Project name may use letters, numbers, spaces, underscore, hyphen and period only."
            );
        }
        return name;
    }

    private void writeUvProjectFiles(File root, String projectName) throws IOException {
        Path rootPath = root.toPath();
        Files.writeString(rootPath.resolve(".python-version"),
                DEFAULT_UV_PYTHON_VERSION + System.lineSeparator(),
                StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

        Files.writeString(rootPath.resolve("requirements.txt"),
                "# Direct packages installed by Workbench for this project\n"
                        + "tensorflow\n"
                        + "keras\n"
                        + "matplotlib\n"
                        + "# Needed by keras.utils.plot_model(...)\n"
                        + "pydot\n",
                StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

        Files.writeString(rootPath.resolve(UV_PROJECT_ENV_FILE),
                "# Loaded by Workbench when it runs Python in this project\n"
                        + "KERAS_BACKEND=" + UV_KERAS_BACKEND + "\n"
                        + "PYTHONUTF8=1\n"
                        + "UV_LINK_MODE=copy\n",
                StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

        Properties properties = new Properties();
        properties.setProperty("project.type", "python-uv");
        properties.setProperty("project.name", projectName);
        properties.setProperty("python.version", DEFAULT_UV_PYTHON_VERSION);
        properties.setProperty("venv.path", UV_PROJECT_VENV_FOLDER);
        properties.setProperty("python.executable",
                isWindowsPlatform() ? ".venv\\Scripts\\python.exe" : ".venv/bin/python");
        properties.setProperty("keras.backend", UV_KERAS_BACKEND);
        properties.setProperty("package.install.command", "uv pip install <package_name>");
        try (java.io.Writer writer = Files.newBufferedWriter(rootPath.resolve(UV_PROJECT_CONFIG_FILE),
                StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING)) {
            properties.store(writer, "Workbench Python + uv project configuration");
        }

        Files.writeString(rootPath.resolve("main.py"),
                "# Workbench uv Python project\n"
                        + "# KERAS_BACKEND must be selected before importing keras.\n"
                        + "import os\n"
                        + "os.environ.setdefault(\"KERAS_BACKEND\", \"tensorflow\")\n\n"
                        + "import tensorflow as tf\n"
                        + "import keras\n"
                        + "import matplotlib.pyplot as plt\n\n"
                        + "print(f\"TensorFlow: {tf.__version__}\")\n"
                        + "print(f\"Keras:      {keras.__version__}\")\n"
                        + "print(f\"Backend:    {keras.backend.backend()}\")\n"
                        + "print(f\"Devices:    {tf.config.list_physical_devices()}\")\n\n"
                        + "plt.plot([1, 2, 3], [1, 4, 9])\n"
                        + "plt.title(\"Matplotlib is ready\")\n"
                        + "plt.show()\n",
                StandardCharsets.UTF_8, StandardOpenOption.CREATE_NEW);

        Files.writeString(rootPath.resolve("README_Workbench_Python.txt"),
                "Workbench Python uv Project\n"
                        + "============================\n\n"
                        + "This project owns its own .venv. Use Workbench Embedded Console:\n"
                        + "  uv pip install <package_name>\n"
                        + "  python main.py\n\n"
                        + "KERAS_BACKEND is automatically set to tensorflow by Workbench.\n\n"
                        + "Keras plot_model support:\n"
                        + "- pydot is installed in this project.\n"
                        + "- Windows also needs the Graphviz system program dot.exe.\n"
                        + "  Install it once in a normal Windows terminal, for example:\n"
                        + "  winget install graphviz\n"
                        + "- Restart Workbench after Graphviz installation, then verify:\n"
                        + "  where dot\n"
                        + "  dot -V\n",
                StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

        if (isWindowsPlatform()) {
            Files.writeString(rootPath.resolve("run_python.bat"),
                    "@echo off\r\n"
                            + "set \"KERAS_BACKEND=" + UV_KERAS_BACKEND + "\"\r\n"
                            + "set \"PYTHONUTF8=1\"\r\n"
                            + "set \"UV_LINK_MODE=copy\"\r\n"
                            + "\"%~dp0.venv\\Scripts\\python.exe\" \"%~dp0main.py\" %*\r\n",
                    StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);
        }
    }

    private void runUvSetupRequired(List<String> command, File workingDirectory,
                                    Map<String, String> environment, UvSetupOutput output,
                                    String failureMessage) throws IOException, InterruptedException {
        int exitCode = runUvSetupCommand(command, workingDirectory, environment, output);
        if (exitCode != 0) throw new IOException(failureMessage + " (exit code " + exitCode + ")");
    }

    private int runUvSetupCommand(List<String> command, File workingDirectory,
                                  Map<String, String> environment, UvSetupOutput output)
            throws IOException, InterruptedException {
        appendUvSetupOutput(output, "> " + commandForDisplay(command) + "\n");
        ProcessBuilder pb = new ProcessBuilder(command);
        if (workingDirectory != null) pb.directory(workingDirectory);
        pb.redirectErrorStream(true);
        pb.environment().put("PYTHONIOENCODING", "utf-8");
        if (environment != null) pb.environment().putAll(environment);

        Process process = pb.start();
        try (java.io.BufferedReader reader = new java.io.BufferedReader(
                new java.io.InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
            String line;
            while ((line = reader.readLine()) != null) {
                appendUvSetupOutput(output, line + System.lineSeparator());
            }
        }
        int exitCode = process.waitFor();
        appendUvSetupOutput(output, "[Exit code: " + exitCode + "]\n\n");
        return exitCode;
    }

    private void appendUvSetupOutput(UvSetupOutput output, String text) {
        if (output != null && text != null) output.append(text);
    }

    private String commandForDisplay(List<String> command) {
        List<String> shown = new ArrayList<>();
        for (String part : command) {
            shown.add(part != null && part.contains(" ") ? "\"" + part + "\"" : String.valueOf(part));
        }
        return String.join(" ", shown);
    }

    /**
     * Modal project wizard. Setup runs in SwingWorker so the Workbench remains
     * responsive while uv downloads Python/packages.
     */
    private final class NewUvPythonProjectDialog extends JDialog {
        private final JTextField nameField = new JTextField("TensorFlow_Keras_Pj", 28);
        private final JTextField locationField = new JTextField(getUvProjectRootDirectory().getAbsolutePath(), 45);
        private final JTextArea outputArea = new JTextArea(14, 72);
        private final JButton createButton = new JButton("Create Project");

        NewUvPythonProjectDialog() {
            super(AICodingEditor.this,
                    "New Python Project - uv / TensorFlow / Keras", true);
            buildUi();
        }

        private void buildUi() {
            setDefaultCloseOperation(WindowConstants.DISPOSE_ON_CLOSE);
            setLayout(new BorderLayout(8, 8));

            JPanel form = new JPanel(new GridBagLayout());
            form.setBorder(BorderFactory.createEmptyBorder(12, 12, 0, 12));
            GridBagConstraints gbc = new GridBagConstraints();
            gbc.insets = new Insets(4, 4, 4, 4);
            gbc.anchor = GridBagConstraints.WEST;

            gbc.gridx = 0; gbc.gridy = 0; gbc.weightx = 0; gbc.fill = GridBagConstraints.NONE;
            form.add(new JLabel("Project name:"), gbc);
            gbc.gridx = 1; gbc.gridy = 0; gbc.weightx = 1; gbc.fill = GridBagConstraints.HORIZONTAL;
            form.add(nameField, gbc);

            gbc.gridx = 0; gbc.gridy = 1; gbc.weightx = 0; gbc.fill = GridBagConstraints.NONE;
            form.add(new JLabel("Location:"), gbc);
            gbc.gridx = 1; gbc.gridy = 1; gbc.weightx = 1; gbc.fill = GridBagConstraints.HORIZONTAL;
            form.add(locationField, gbc);
            JButton browseButton = new JButton("Browse...");
            browseButton.addActionListener(e -> {
                File selected = chooseDirectory("Select project location",
                        new File(locationField.getText().trim()));
                if (selected != null) locationField.setText(selected.getAbsolutePath());
            });
            gbc.gridx = 2; gbc.gridy = 1; gbc.weightx = 0; gbc.fill = GridBagConstraints.NONE;
            form.add(browseButton, gbc);

            JLabel summary = new JLabel("<html>Creates a project-local <b>.venv</b> using Python "
                    + DEFAULT_UV_PYTHON_VERSION + "; installs <b>TensorFlow, Keras, Matplotlib, pydot</b>; "
                    + "and sets <b>KERAS_BACKEND=tensorflow</b>.</html>");
            gbc.gridx = 0; gbc.gridy = 2; gbc.gridwidth = 3; gbc.weightx = 1;
            form.add(summary, gbc);
            add(form, BorderLayout.NORTH);

            outputArea.setEditable(false);
            outputArea.setFont(new Font("Monospaced", Font.PLAIN, 12));
            JScrollPane scroll = new JScrollPane(outputArea);
            scroll.setBorder(BorderFactory.createTitledBorder("uv Setup Output"));
            add(scroll, BorderLayout.CENTER);

            JButton cancelButton = new JButton("Cancel");
            cancelButton.addActionListener(e -> dispose());
            createButton.addActionListener(e -> createProject());
            JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT, 6, 6));
            buttons.add(cancelButton);
            buttons.add(createButton);
            add(buttons, BorderLayout.SOUTH);

            getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR, 1));
            getContentPane().setBackground(APP_MENU_BACKGROUND);
            applyDarkContainerTheme(getContentPane());
            setMinimumSize(new Dimension(810, 480));
            setSize(900, 570);
            setLocationRelativeTo(AICodingEditor.this);
        }

        private void createProject() {
            final File parent;
            try {
                String location = locationField.getText() == null ? "" : locationField.getText().trim();
                if (location.isEmpty()) throw new IOException("Project location is required.");
                parent = new File(location);
                Files.createDirectories(parent.toPath());
                validateUvProjectName(nameField.getText());
            } catch (Exception ex) {
                JOptionPane.showMessageDialog(this, ex.getMessage(),
                        "Invalid Python project settings", JOptionPane.ERROR_MESSAGE);
                return;
            }

            outputArea.setText("");
            createButton.setEnabled(false);
            SwingWorker<UvPythonProject, String> worker = new SwingWorker<>() {
                @Override
                protected UvPythonProject doInBackground() throws Exception {
                    return createUvPythonTensorFlowProject(parent, nameField.getText(), this::publish);
                }

                @Override
                protected void process(List<String> chunks) {
                    for (String chunk : chunks) outputArea.append(chunk);
                    outputArea.setCaretPosition(outputArea.getDocument().getLength());
                }

                @Override
                protected void done() {
                    createButton.setEnabled(true);
                    try {
                        UvPythonProject project = get();
                        uvProjectRootDirectory = parent.getCanonicalFile();
                        preferences.put(UV_PROJECT_ROOT_PREFERENCE_KEY, uvProjectRootDirectory.getAbsolutePath());
                        activateUvPythonProject(project, true);
                        addWorkbenchRoot(project.rootDirectory);
                        saveWorkbenchRoots();
                        setFileBrowserRoot(project.rootDirectory);
                        File starter = new File(project.rootDirectory, "main.py");
                        if (starter.isFile()) openFile(starter);
                        JOptionPane.showMessageDialog(NewUvPythonProjectDialog.this,
                                "Python uv project created successfully.\n\n"
                                        + project.rootDirectory.getAbsolutePath()
                                        + "\n\nUse Embedded Console:\n"
                                        + "uv pip install pandas\n"
                                        + "python main.py",
                                "Workbench Python Project", JOptionPane.INFORMATION_MESSAGE);
                        dispose();
                    } catch (Exception ex) {
                        Throwable cause = ex.getCause() == null ? ex : ex.getCause();
                        outputArea.append("\nERROR: " + cause.getMessage() + "\n");
                        JOptionPane.showMessageDialog(NewUvPythonProjectDialog.this,
                                "Project setup failed. Review uv Setup Output.\n\n" + cause.getMessage(),
                                "Workbench Python Project", JOptionPane.ERROR_MESSAGE);
                    }
                }
            };
            worker.execute();
        }
    }

    // ---------------------------------------------------------------------
    // Embedded Console command mode
    // ---------------------------------------------------------------------

    /**
     * When no interactive process is running, the Embedded Console input becomes
     * a command line.  uv pip / pip commands are forced into the active project
     * .venv, and python commands use the active project interpreter.
     */
    private void runEmbeddedConsoleCommand(String typedCommand) {
        if (!requireTrialWriteBuildAccess("Embedded Console Command")) return;
        String command = typedCommand == null ? "" : typedCommand.trim();
        if (command.isEmpty()) return;

        String lower = command.toLowerCase(Locale.ROOT);
        if ("clear".equals(lower) || "cls".equals(lower)) {
            embeddedConsoleArea.setText("");
            return;
        }
        if ("help".equals(lower)) {
            appendConsoleText(embeddedConsoleArea,
                    "\nWorkbench Embedded Console commands\n"
                            + "  uv pip install <package>   Install into the active project .venv\n"
                            + "  pip install <package>      Same as uv pip install for active project\n"
                            + "  uv pip list                List active project packages\n"
                            + "  python file.py             Run with active project .venv Python\n"
                            + "  where python               Verify the local .venv Python on Windows\n"
                            + "  project                    Show active project\n"
                            + "  clear                      Clear console output\n\n");
            return;
        }
        if ("project".equals(lower)) {
            appendConsoleText(embeddedConsoleArea, activeUvPythonProject == null
                    ? "\nNo active Python uv project.\n"
                    : "\nActive project: " + activeUvPythonProject.displayName()
                            + "\nRoot: " + activeUvPythonProject.rootDirectory.getAbsolutePath()
                            + "\nPython: " + activeUvPythonProject.pythonExecutable.getAbsolutePath() + "\n");
            return;
        }

        List<String> tokens;
        try {
            tokens = tokenizeEmbeddedConsoleCommand(command);
        } catch (IllegalArgumentException ex) {
            appendConsoleText(embeddedConsoleArea, "\n[command error] " + ex.getMessage() + "\n");
            return;
        }
        if (tokens.isEmpty()) return;

        UvPythonProject project = activeUvPythonProject;
        File workingDirectory = project != null ? project.rootDirectory : getPythonWorkingDirectory();
        Map<String, String> environment = createUvProjectEnvironment(project);

        if (isUvPipCommand(tokens)) {
            if (project == null) {
                appendConsoleText(embeddedConsoleArea,
                        "\n[no active Python uv project] Use File -> New Python Project or Open Existing Python uv Project first.\n");
                return;
            }
            tokens.set(0, getUvCommandForExecution());
            List<String> routed = forceUvPipToActiveProject(tokens, project);
            startInteractiveConsole(routed, project.rootDirectory,
                    "Embedded Console - uv pip", StandardCharsets.UTF_8, environment);
            return;
        }

        if ("pip".equalsIgnoreCase(executableBaseName(tokens.get(0)))) {
            if (project == null) {
                appendConsoleText(embeddedConsoleArea,
                        "\n[no active Python uv project] pip install is routed only after a uv project is active.\n");
                return;
            }
            List<String> converted = new ArrayList<>();
            converted.add(getUvCommandForExecution());
            converted.add("pip");
            converted.addAll(tokens.subList(1, tokens.size()));
            startInteractiveConsole(forceUvPipToActiveProject(converted, project),
                    project.rootDirectory, "Embedded Console - uv pip", StandardCharsets.UTF_8, environment);
            return;
        }

        if (isPythonConsoleCommand(tokens.get(0))) {
            if (project != null) tokens.set(0, project.pythonExecutable.getAbsolutePath());
            else tokens.set(0, getPythonInterpreterCommand());
            startInteractiveConsole(tokens, workingDirectory,
                    "Embedded Console - Python", StandardCharsets.UTF_8, environment);
            return;
        }

        // Execute a selected .exe directly through ProcessBuilder. This avoids cmd.exe
        // quote parsing failures for commands such as:
        // "D:\ArduinoCLI\arduino-cli.exe" compile --fqbn ... --library "D:\Arduino\libraries\ADCTouch"
        if (isDirectExecutableConsoleCommand(tokens)) {
            startInteractiveConsole(tokens, workingDirectory,
                    "Embedded Console - Executable", StandardCharsets.UTF_8, environment);
            return;
        }

        // Use a temporary UTF-8 batch file for shell built-ins, pipes and redirection.
        // Passing an arbitrary quoted executable directly to cmd /c can make cmd treat
        // only the first quoted path as its command, producing errorlevel 1 before the
        // tool begins. The batch file avoids that Windows quoting edge case.
        if (isWindowsPlatform()) {
            startWindowsShellCommandInEmbeddedConsole(command, workingDirectory, environment);
        } else {
            startInteractiveConsole(List.of("/bin/sh", "-lc", command),
                    workingDirectory, "Embedded Console - Command", StandardCharsets.UTF_8, environment);
        }
    }

    private boolean isDirectExecutableConsoleCommand(List<String> tokens) {
        if (tokens == null || tokens.isEmpty()) return false;
        String first = tokens.get(0);
        if (new File(first).isFile()) return true;

        String base = executableBaseName(first).toLowerCase(Locale.ROOT);
        if ("arduino-cli".equals(base) || "arduino-cli.exe".equals(base)) {
            tokens.set(0, resolveLanguageToolCommandForExecution(
                    TOOL_ARDUINO_CLI, getLanguageToolCommand(TOOL_ARDUINO_CLI)));
            return true;
        }
        return false;
    }

    private void startWindowsShellCommandInEmbeddedConsole(String command, File workingDirectory,
                                                            Map<String, String> environment) {
        try {
            File script = Files.createTempFile("AICodingEditor_Console_", ".cmd").toFile();
            script.deleteOnExit();
            Files.writeString(script.toPath(),
                    "@echo off\r\n"
                            + "chcp 65001>nul\r\n"
                            + command + "\r\n",
                    StandardCharsets.UTF_8, StandardOpenOption.TRUNCATE_EXISTING);
            startInteractiveConsole(List.of("cmd.exe", "/d", "/s", "/c",
                            "call \"" + script.getAbsolutePath() + "\""),
                    workingDirectory, "Embedded Console - Command", StandardCharsets.UTF_8, environment);
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                    "Cannot create a temporary Windows command script.\n\n" + ex.getMessage(),
                    "Embedded Console", JOptionPane.ERROR_MESSAGE);
        }
    }

    private List<String> tokenizeEmbeddedConsoleCommand(String command) {
        List<String> tokens = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean quoted = false;
        char quote = 0;
        for (int i = 0; i < command.length(); i++) {
            char ch = command.charAt(i);
            if ((ch == '"' || ch == '\'') && (!quoted || quote == ch)) {
                if (quoted) {
                    quoted = false;
                    quote = 0;
                } else {
                    quoted = true;
                    quote = ch;
                }
            } else if (Character.isWhitespace(ch) && !quoted) {
                if (current.length() > 0) {
                    tokens.add(current.toString());
                    current.setLength(0);
                }
            } else {
                current.append(ch);
            }
        }
        if (quoted) throw new IllegalArgumentException("Unclosed quote in command.");
        if (current.length() > 0) tokens.add(current.toString());
        return tokens;
    }

    private boolean isUvPipCommand(List<String> tokens) {
        return tokens.size() >= 3
                && "uv".equalsIgnoreCase(executableBaseName(tokens.get(0)))
                && "pip".equalsIgnoreCase(tokens.get(1));
    }

    private boolean isPythonConsoleCommand(String token) {
        String base = executableBaseName(token).toLowerCase(Locale.ROOT);
        return "python".equals(base) || "python.exe".equals(base)
                || "python3".equals(base) || "python3.exe".equals(base);
    }

    private String executableBaseName(String command) {
        if (command == null || command.isBlank()) return "";
        return new File(command).getName();
    }

    /**
     * Force --python <active-venv-python> even if a user typed a different
     * environment. This prevents accidental installation into global Python or
     * another Workbench project.
     */
    private List<String> forceUvPipToActiveProject(List<String> source, UvPythonProject project) {
        List<String> command = new ArrayList<>(source);
        for (int i = 3; i < command.size(); i++) {
            String token = command.get(i);
            if ("--python".equalsIgnoreCase(token) || "-p".equalsIgnoreCase(token)) {
                command.remove(i);
                if (i < command.size()) command.remove(i);
                i--;
            } else if (token.toLowerCase(Locale.ROOT).startsWith("--python=")
                    || token.toLowerCase(Locale.ROOT).startsWith("-p=")) {
                command.remove(i);
                i--;
            }
        }
        int insertAt = Math.min(3, command.size());
        command.add(insertAt, "--python");
        command.add(insertAt + 1, project.pythonExecutable.getAbsolutePath());
        return command;
    }

