    private void registerShortcut(String id, String displayName, KeyStroke defaultKeyStroke, String description, Runnable action) {
        ShortcutDefinition def = new ShortcutDefinition(id, displayName, defaultKeyStroke, description, action);
        String saved = preferences.get("shortcut." + id, null);
        if (saved != null && !saved.isBlank()) {
            KeyStroke savedKeyStroke = KeyStroke.getKeyStroke(saved);
            if (savedKeyStroke != null) def.currentKeyStroke = savedKeyStroke;
        }
        shortcutDefinitions.put(id, def);
    }

    private void applyShortcutBindings() {
        InputMap inputMap = getRootPane().getInputMap(JComponent.WHEN_IN_FOCUSED_WINDOW);
        ActionMap actionMap = getRootPane().getActionMap();
        for (ShortcutDefinition def : shortcutDefinitions.values()) {
            if (def.boundKeyStroke != null) inputMap.remove(def.boundKeyStroke);
            if (def.currentKeyStroke != null) {
                inputMap.put(def.currentKeyStroke, def.id);
                actionMap.put(def.id, new AbstractAction() {
                    @Override public void actionPerformed(ActionEvent e) {
                        if (def.action != null) def.action.run();
                    }
                });
                def.boundKeyStroke = def.currentKeyStroke;
            }
        }
        updateShortcutMenuAccelerators();
    }

    private void bindShortcutMenuItem(String shortcutId, JMenuItem item) {
        if (shortcutId == null || item == null) return;
        shortcutMenuItems.put(shortcutId, item);
        ShortcutDefinition def = shortcutDefinitions.get(shortcutId);
        if (def != null) item.setAccelerator(def.currentKeyStroke);
    }

    private void updateShortcutMenuAccelerators() {
        for (Map.Entry<String, JMenuItem> entry : shortcutMenuItems.entrySet()) {
            ShortcutDefinition def = shortcutDefinitions.get(entry.getKey());
            JMenuItem item = entry.getValue();
            if (def != null && item != null) item.setAccelerator(def.currentKeyStroke);
        }
    }

    private void showShortcutMapperDialog() {
        JDialog dialog = new JDialog(this, "Shortcut Mapper", true);
        dialog.setLayout(new BorderLayout(8, 8));
        dialog.setSize(840, 360);
        dialog.setLocationRelativeTo(this);

        String[] columns = {"Action", "Shortcut", "Default", "Description"};
        javax.swing.table.DefaultTableModel model = new javax.swing.table.DefaultTableModel(columns, 0) {
            @Override public boolean isCellEditable(int row, int column) { return false; }
        };
        java.util.List<ShortcutDefinition> rows = new ArrayList<>(shortcutDefinitions.values());
        for (ShortcutDefinition def : rows) {
            model.addRow(new Object[]{
                    def.displayName,
                    keyStrokeToDisplay(def.currentKeyStroke),
                    keyStrokeToDisplay(def.defaultKeyStroke),
                    def.description
            });
        }

        JTable table = new JTable(model);
        table.setSelectionMode(ListSelectionModel.SINGLE_SELECTION);
        table.setAutoResizeMode(JTable.AUTO_RESIZE_OFF);
        table.getColumnModel().getColumn(0).setPreferredWidth(230);
        table.getColumnModel().getColumn(1).setPreferredWidth(130);
        table.getColumnModel().getColumn(2).setPreferredWidth(130);
        table.getColumnModel().getColumn(3).setPreferredWidth(520);
        table.setRowHeight(24);
        table.setBackground(new Color(25, 25, 25));
        table.setForeground(Color.WHITE);
        table.setSelectionBackground(new Color(70, 90, 140));
        table.setSelectionForeground(Color.WHITE);
        table.getTableHeader().setBackground(APP_MENU_ITEM_BACKGROUND);
        table.getTableHeader().setForeground(APP_MENU_FOREGROUND);

        JLabel hint = new JLabel("  Notepad++ style shortcut mapper. Select an action, click Edit Shortcut, then press a new key combination.");
        hint.setForeground(APP_MENU_FOREGROUND);
        hint.setBorder(BorderFactory.createEmptyBorder(6, 6, 0, 6));

        JButton editButton = new JButton("Edit Shortcut...");
        JButton resetButton = new JButton("Reset Selected");
        JButton resetAllButton = new JButton("Reset All Defaults");
        JButton closeButton = new JButton("Close");

        editButton.addActionListener(e -> {
            int row = table.getSelectedRow();
            if (row < 0) {
                JOptionPane.showMessageDialog(dialog, "Please select one action first.", "Shortcut Mapper", JOptionPane.INFORMATION_MESSAGE);
                return;
            }
            ShortcutDefinition def = rows.get(row);
            KeyStroke newKeyStroke = captureShortcut(dialog, def);
            if (newKeyStroke == null) return;

            ShortcutDefinition duplicate = findShortcutDuplicate(def.id, newKeyStroke);
            if (duplicate != null) {
                JOptionPane.showMessageDialog(dialog,
                        "This shortcut is already used by:\n" + duplicate.displayName + "\n\nPlease choose another shortcut.",
                        "Shortcut Conflict", JOptionPane.WARNING_MESSAGE);
                return;
            }

            def.currentKeyStroke = newKeyStroke;
            preferences.put("shortcut." + def.id, newKeyStroke.toString());
            applyShortcutBindings();
            model.setValueAt(keyStrokeToDisplay(def.currentKeyStroke), row, 1);
        });

        resetButton.addActionListener(e -> {
            int row = table.getSelectedRow();
            if (row < 0) return;
            ShortcutDefinition def = rows.get(row);
            def.currentKeyStroke = def.defaultKeyStroke;
            preferences.remove("shortcut." + def.id);
            applyShortcutBindings();
            model.setValueAt(keyStrokeToDisplay(def.currentKeyStroke), row, 1);
        });

        resetAllButton.addActionListener(e -> {
            for (int i = 0; i < rows.size(); i++) {
                ShortcutDefinition def = rows.get(i);
                def.currentKeyStroke = def.defaultKeyStroke;
                preferences.remove("shortcut." + def.id);
                model.setValueAt(keyStrokeToDisplay(def.currentKeyStroke), i, 1);
            }
            applyShortcutBindings();
        });
        closeButton.addActionListener(e -> dialog.dispose());

        JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT, 6, 6));
        buttons.add(editButton);
        buttons.add(resetButton);
        buttons.add(resetAllButton);
        buttons.add(closeButton);

        dialog.add(hint, BorderLayout.NORTH);
        dialog.add(new JScrollPane(table), BorderLayout.CENTER);
        dialog.add(buttons, BorderLayout.SOUTH);
        dialog.getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        applyDarkContainerTheme(dialog.getContentPane());
        table.setBackground(new Color(25, 25, 25));
        table.setForeground(Color.WHITE);
        table.getTableHeader().setBackground(APP_MENU_ITEM_BACKGROUND);
        table.getTableHeader().setForeground(APP_MENU_FOREGROUND);
        dialog.setVisible(true);
    }

    private KeyStroke captureShortcut(Component parent, ShortcutDefinition def) {
        JDialog dialog = new JDialog(this, "Edit Shortcut - " + def.displayName, true);
        dialog.setLayout(new BorderLayout(8, 8));
        dialog.setSize(520, 170);
        dialog.setLocationRelativeTo(parent);

        JPanel panel = new JPanel(new BorderLayout(8, 8));
        panel.setBorder(BorderFactory.createEmptyBorder(12, 12, 12, 12));
        JLabel label = new JLabel("Press the new shortcut key combination, for example Ctrl+Q or Ctrl+K:");
        JTextField shortcutField = new JTextField(keyStrokeToDisplay(def.currentKeyStroke));
        shortcutField.setEditable(false);
        shortcutField.setFont(new Font("Monospaced", Font.BOLD, 16));
        final KeyStroke[] captured = {null};

        shortcutField.addKeyListener(new KeyAdapter() {
            @Override public void keyPressed(KeyEvent e) {
                int keyCode = e.getKeyCode();
                if (keyCode == KeyEvent.VK_CONTROL || keyCode == KeyEvent.VK_SHIFT || keyCode == KeyEvent.VK_ALT || keyCode == KeyEvent.VK_META) {
                    e.consume();
                    return;
                }
                if (keyCode == KeyEvent.VK_ESCAPE) {
                    captured[0] = null;
                    dialog.dispose();
                    e.consume();
                    return;
                }
                captured[0] = KeyStroke.getKeyStroke(keyCode, e.getModifiersEx());
                shortcutField.setText(keyStrokeToDisplay(captured[0]));
                e.consume();
            }
        });

        JButton okButton = new JButton("OK");
        JButton cancelButton = new JButton("Cancel");
        okButton.addActionListener(e -> {
            if (captured[0] == null) {
                JOptionPane.showMessageDialog(dialog, "Please press a shortcut first.", "Shortcut Mapper", JOptionPane.INFORMATION_MESSAGE);
                return;
            }
            dialog.dispose();
        });
        cancelButton.addActionListener(e -> { captured[0] = null; dialog.dispose(); });

        JPanel buttonPanel = new JPanel(new FlowLayout(FlowLayout.RIGHT));
        buttonPanel.add(okButton);
        buttonPanel.add(cancelButton);

        panel.add(label, BorderLayout.NORTH);
        panel.add(shortcutField, BorderLayout.CENTER);
        panel.add(buttonPanel, BorderLayout.SOUTH);
        dialog.add(panel, BorderLayout.CENTER);
        dialog.getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        applyDarkContainerTheme(dialog.getContentPane());
        SwingUtilities.invokeLater(shortcutField::requestFocusInWindow);
        dialog.setVisible(true);
        return captured[0];
    }

    private ShortcutDefinition findShortcutDuplicate(String actionId, KeyStroke keyStroke) {
        if (keyStroke == null) return null;
        for (ShortcutDefinition def : shortcutDefinitions.values()) {
            if (!def.id.equals(actionId) && keyStroke.equals(def.currentKeyStroke)) return def;
        }
        return null;
    }

    private String keyStrokeToDisplay(KeyStroke keyStroke) {
        if (keyStroke == null) return "(none)";
        String modifiers = KeyEvent.getModifiersExText(keyStroke.getModifiers());
        String key = KeyEvent.getKeyText(keyStroke.getKeyCode());
        return modifiers == null || modifiers.isBlank() ? key : modifiers + "+" + key;
    }

    // ---------------------------------------------------------------------
    // Macro functions
    // ---------------------------------------------------------------------

    private File getMacroDirectory() {
        return new File(System.getProperty("user.home"), "." + APP_NAME + File.separator + "macros");
    }

    private File getMacroFile(RecordedMacro macro) {
        return new File(getMacroDirectory(), macro.id + MACRO_FILE_EXTENSION);
    }

    private String macroShortcutId(RecordedMacro macro) {
        return "savedMacro." + macro.id;
    }

    private void loadSavedMacros() {
        savedMacros.clear();
        File folder = getMacroDirectory();
        if (!folder.exists() || !folder.isDirectory()) return;

        File[] macroFiles = folder.listFiles((dir, name) -> name.toLowerCase(Locale.ROOT).endsWith(MACRO_FILE_EXTENSION));
        if (macroFiles == null) return;
        Arrays.sort(macroFiles, Comparator.comparing(File::getName, String.CASE_INSENSITIVE_ORDER));

        for (File macroFile : macroFiles) {
            try (ObjectInputStream input = new ObjectInputStream(new FileInputStream(macroFile))) {
                Object object = input.readObject();
                if (object instanceof RecordedMacro macro && macro.isUsable()) {
                    savedMacros.put(macro.id, macro);
                    registerSavedMacroShortcut(macro);
                }
            } catch (IOException | ClassNotFoundException ignored) {
                // Ignore invalid/old macro files so one bad file cannot stop the editor.
            }
        }
    }

    private void registerSavedMacroShortcut(RecordedMacro macro) {
        if (macro == null || macro.id == null || macro.id.isBlank()) return;
        String id = macroShortcutId(macro);
        ShortcutDefinition old = shortcutDefinitions.remove(id);
        if (old != null && old.boundKeyStroke != null && getRootPane() != null) {
            getRootPane().getInputMap(JComponent.WHEN_IN_FOCUSED_WINDOW).remove(old.boundKeyStroke);
        }
        registerShortcut(id,
                "Macro: " + macro.name,
                null,
                "Run saved macro '" + macro.name + "' at the current caret position.",
                () -> playSavedMacro(macro.id));
    }

    private void unregisterSavedMacroShortcut(RecordedMacro macro) {
        if (macro == null) return;
        String id = macroShortcutId(macro);
        ShortcutDefinition def = shortcutDefinitions.remove(id);
        if (def != null && def.boundKeyStroke != null && getRootPane() != null) {
            getRootPane().getInputMap(JComponent.WHEN_IN_FOCUSED_WINDOW).remove(def.boundKeyStroke);
        }
        preferences.remove("shortcut." + id);
    }

    private void updateSavedMacrosMenu() {
        if (savedMacrosMenu == null) return;
        savedMacrosMenu.removeAll();
        if (savedMacros.isEmpty()) {
            JMenuItem empty = new JMenuItem(tr("沒有已儲存巨集", "No Saved Macros"));
            empty.setEnabled(false);
            savedMacrosMenu.add(empty);
        } else {
            java.util.List<RecordedMacro> macros = new ArrayList<>(savedMacros.values());
            macros.sort(Comparator.comparing(m -> m.name, String.CASE_INSENSITIVE_ORDER));
            for (RecordedMacro macro : macros) {
                JMenuItem item = new JMenuItem(macro.name + "  (" + macro.steps.size() + " steps)");
                ShortcutDefinition shortcut = shortcutDefinitions.get(macroShortcutId(macro));
                if (shortcut != null) item.setAccelerator(shortcut.currentKeyStroke);
                item.setToolTipText("Run saved macro: " + macro.name);
                item.addActionListener(e -> playSavedMacro(macro.id));
                savedMacrosMenu.add(item);
            }
        }
        applyMenuElementTheme(savedMacrosMenu);
    }

    private void updateMacroMenuState() {
        if (startRecordingMacroItem != null) startRecordingMacroItem.setEnabled(!macroRecording && !macroPlaying);
        if (stopRecordingMacroItem != null) stopRecordingMacroItem.setEnabled(macroRecording);
        boolean hasCurrent = lastRecordedMacro != null && !lastRecordedMacro.steps.isEmpty();
        if (playbackRecordedMacroItem != null) playbackRecordedMacroItem.setEnabled(hasCurrent && !macroRecording && !macroPlaying);
        if (saveCurrentRecordedMacroItem != null) saveCurrentRecordedMacroItem.setEnabled(hasCurrent && !macroRecording);
        if (runMacroMultipleTimesItem != null) runMacroMultipleTimesItem.setEnabled((hasCurrent || !savedMacros.isEmpty()) && !macroRecording && !macroPlaying);
    }

    private void startMacroRecording() {
        if (!requireTrialWriteBuildAccess("Start Macro Recording")) return;
        if (macroPlaying) {
            JOptionPane.showMessageDialog(this, "A macro is playing now. Please wait until playback finishes.", "Macro", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        EditorTab tab = currentTab();
        if (tab == null) return;
        macroRecording = true;
        macroRecordingTab = tab;
        macroRecordingStartCaret = tab.textPane.getCaretPosition();
        currentMacroSteps.clear();
        updateMacroMenuState();
        statusLabel.setText(" MACRO REC: Recording text edits in " + (tab.file == null ? "untitled" : tab.file.getName()) + ". Use Macro -> Stop Recording when done.");
        tab.textPane.requestFocusInWindow();
    }

    private void stopMacroRecording() {
        if (!requireTrialWriteBuildAccess("Stop Macro Recording")) return;
        if (!macroRecording) return;
        EditorTab tab = macroRecordingTab;
        int finalCaret = tab == null ? macroRecordingStartCaret : tab.textPane.getCaretPosition();
        macroRecording = false;
        macroRecordingTab = null;

        if (currentMacroSteps.isEmpty()) {
            updateMacroMenuState();
            JOptionPane.showMessageDialog(this,
                    "No text edits were captured.\n\nMacro recording captures typing, delete/backspace, paste, Find/Replace text changes, and comment/uncomment edits.",
                    "Macro", JOptionPane.INFORMATION_MESSAGE);
            updateStatus();
            return;
        }

        lastRecordedMacro = new RecordedMacro(
                "current-" + UUID.randomUUID(),
                "Current Recorded Macro",
                new ArrayList<>(currentMacroSteps),
                finalCaret - macroRecordingStartCaret,
                System.currentTimeMillis());
        updateMacroMenuState();
        updateStatus();
        JOptionPane.showMessageDialog(this,
                "Macro recording stopped.\nCaptured " + lastRecordedMacro.steps.size() + " text-editing step(s).\n\nYou may now Playback, Save Current Recorded Macro, or Run a Macro Multiple Times.",
                "Macro", JOptionPane.INFORMATION_MESSAGE);
    }

    private boolean shouldRecordMacro(EditorTab tab) {
        return macroRecording
                && !macroPlaying
                && !applyingHighlight
                && tab != null
                && tab == macroRecordingTab
                && currentMacroSteps.size() < MAX_MACRO_STEPS;
    }

    private void recordMacroInsert(EditorTab tab, int offset, String text) {
        if (!shouldRecordMacro(tab) || text == null || text.isEmpty()) return;
        currentMacroSteps.add(MacroStep.insert(offset - macroRecordingStartCaret, text));
    }

    private void recordMacroRemove(EditorTab tab, int offset, int length) {
        if (!shouldRecordMacro(tab) || length <= 0) return;
        currentMacroSteps.add(MacroStep.remove(offset - macroRecordingStartCaret, length));
    }

    private void playCurrentRecordedMacro() {
        if (!requireTrialWriteBuildAccess("Playback Macro")) return;
        if (lastRecordedMacro == null || lastRecordedMacro.steps.isEmpty()) {
            JOptionPane.showMessageDialog(this, "There is no recorded macro yet. Use Macro -> Start Recording first.", "Macro", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        playMacro(lastRecordedMacro, 1);
    }

    private void playSavedMacro(String macroId) {
        RecordedMacro macro = savedMacros.get(macroId);
        if (macro == null) {
            JOptionPane.showMessageDialog(this, "The saved macro is no longer available.", "Macro", JOptionPane.WARNING_MESSAGE);
            return;
        }
        playMacro(macro, 1);
    }

    private void playMacro(RecordedMacro macro, int times) {
        if (macro == null || macro.steps.isEmpty()) return;
        if (macroRecording) {
            JOptionPane.showMessageDialog(this, "Stop macro recording before playback.", "Macro", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        if (macroPlaying) return;
        EditorTab tab = currentTab();
        if (tab == null) return;
        if (times < 1) times = 1;
        if (times > 10_000) times = 10_000;

        StyledDocument document = tab.textPane.getStyledDocument();
        macroPlaying = true;
        updateMacroMenuState();
        try {
            for (int repeat = 0; repeat < times; repeat++) {
                int baseCaret = tab.textPane.getCaretPosition();
                for (MacroStep step : macro.steps) {
                    int offset = clamp(baseCaret + step.offsetDelta, 0, document.getLength());
                    if (step.type == MacroStepType.INSERT) {
                        document.insertString(offset, step.text == null ? "" : step.text, null);
                    } else if (step.type == MacroStepType.REMOVE && offset < document.getLength()) {
                        int length = Math.min(step.length, document.getLength() - offset);
                        if (length > 0) document.remove(offset, length);
                    }
                }
                int targetCaret = clamp(baseCaret + macro.caretDelta, 0, document.getLength());
                tab.textPane.setCaretPosition(targetCaret);
            }
            setModified(tab, true);
            scheduleHighlight();
            statusLabel.setText(" Macro played: " + macro.name + " x " + times);
        } catch (BadLocationException ex) {
            JOptionPane.showMessageDialog(this,
                    "Macro playback stopped because the target document does not match the recorded edit positions.\n\n" + ex.getMessage(),
                    "Macro Playback", JOptionPane.WARNING_MESSAGE);
        } finally {
            macroPlaying = false;
            updateMacroMenuState();
        }
    }

    private int clamp(int value, int min, int max) {
        return Math.max(min, Math.min(value, max));
    }

    private void saveCurrentRecordedMacro() {
        if (!requireTrialWriteBuildAccess("Save Recorded Macro")) return;
        if (lastRecordedMacro == null || lastRecordedMacro.steps.isEmpty()) {
            JOptionPane.showMessageDialog(this, "There is no current recorded macro to save.", "Macro", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        String defaultName = "Macro_" + new java.text.SimpleDateFormat("yyyyMMdd_HHmmss").format(new Date());
        String name = showHighContrastTextInputDialog("Macro", "Macro name:", defaultName);
        if (name == null) return;
        name = name.trim();
        if (name.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Macro name cannot be empty.", "Macro", JOptionPane.WARNING_MESSAGE);
            return;
        }

        for (RecordedMacro existing : savedMacros.values()) {
            if (existing.name.equalsIgnoreCase(name)) {
                int choice = JOptionPane.showConfirmDialog(this,
                        "A saved macro with this name already exists. Replace it?\n" + name,
                        "Macro", JOptionPane.YES_NO_OPTION);
                if (choice != JOptionPane.YES_OPTION) return;
                deleteSavedMacro(existing, false);
                break;
            }
        }

        RecordedMacro saved = new RecordedMacro(
                UUID.randomUUID().toString(),
                name,
                new ArrayList<>(lastRecordedMacro.steps),
                lastRecordedMacro.caretDelta,
                System.currentTimeMillis());
        File folder = getMacroDirectory();
        if (!folder.exists() && !folder.mkdirs()) {
            JOptionPane.showMessageDialog(this, "Cannot create macro folder:\n" + folder.getAbsolutePath(), "Macro", JOptionPane.ERROR_MESSAGE);
            return;
        }
        try (ObjectOutputStream output = new ObjectOutputStream(new FileOutputStream(getMacroFile(saved)))) {
            output.writeObject(saved);
            savedMacros.put(saved.id, saved);
            registerSavedMacroShortcut(saved);
            applyShortcutBindings();
            updateSavedMacrosMenu();
            updateMacroMenuState();
            JOptionPane.showMessageDialog(this,
                    "Saved macro: " + saved.name + "\nSteps: " + saved.steps.size() + "\nFolder: " + folder.getAbsolutePath(),
                    "Macro", JOptionPane.INFORMATION_MESSAGE);
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this, "Could not save macro:\n" + ex.getMessage(), "Macro", JOptionPane.ERROR_MESSAGE);
        }
    }

    private void showRunMacroMultipleTimesDialog() {
        if (!requireTrialWriteBuildAccess("Run Macro Multiple Times")) return;
        java.util.List<MacroChoice> choices = new ArrayList<>();
        if (lastRecordedMacro != null && !lastRecordedMacro.steps.isEmpty()) {
            choices.add(new MacroChoice("Current Recorded Macro", lastRecordedMacro));
        }
        for (RecordedMacro macro : savedMacros.values()) {
            choices.add(new MacroChoice("Saved: " + macro.name, macro));
        }
        if (choices.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Record or save a macro first.", "Macro", JOptionPane.INFORMATION_MESSAGE);
            return;
        }

        JComboBox<MacroChoice> macroBox = new JComboBox<>(choices.toArray(new MacroChoice[0]));
        JSpinner repeatSpinner = new JSpinner(new SpinnerNumberModel(2, 1, 10_000, 1));
        JPanel panel = new JPanel(new GridBagLayout());
        GridBagConstraints gbc = new GridBagConstraints();
        gbc.insets = new Insets(5, 5, 5, 5);
        gbc.fill = GridBagConstraints.HORIZONTAL;
        gbc.gridx = 0; gbc.gridy = 0; panel.add(new JLabel("Macro:"), gbc);
        gbc.gridx = 1; gbc.gridy = 0; gbc.weightx = 1; panel.add(macroBox, gbc);
        gbc.gridx = 0; gbc.gridy = 1; gbc.weightx = 0; panel.add(new JLabel("Times:"), gbc);
        gbc.gridx = 1; gbc.gridy = 1; gbc.weightx = 1; panel.add(repeatSpinner, gbc);
        applyDarkContainerTheme(panel);

        int result = JOptionPane.showConfirmDialog(this, panel, "Run a Macro Multiple Times", JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
        if (result != JOptionPane.OK_OPTION) return;
        MacroChoice selected = (MacroChoice) macroBox.getSelectedItem();
        int times = ((Number) repeatSpinner.getValue()).intValue();
        if (selected != null) playMacro(selected.macro, times);
    }

    private void trimTrailingSpacesAndSave() {
        if (!requireTrialWriteBuildAccess("Trim and Save")) return;
        EditorTab tab = currentTab();
        if (tab == null) return;
        String original = tab.textPane.getText();
        String trimmed = original.replaceAll("(?m)[\\t ]+$", "");
        if (!original.equals(trimmed)) {
            tab.textPane.setText(trimmed);
            tab.textPane.setCaretPosition(Math.min(tab.textPane.getCaretPosition(), trimmed.length()));
            setModified(tab, true);
            scheduleHighlight();
        }
        saveCurrentFile();
    }

    private void showMacroManagerDialog() {
        if (!requireTrialWriteBuildAccess("Modify Macro Settings")) return;
        JDialog dialog = new JDialog(this, "Macro Manager", true);
        dialog.setLayout(new BorderLayout(8, 8));
        dialog.setSize(860, 360);
        dialog.setLocationRelativeTo(this);

        String[] columns = {"Macro", "Steps", "Shortcut", "Storage"};
        javax.swing.table.DefaultTableModel model = new javax.swing.table.DefaultTableModel(columns, 0) {
            @Override public boolean isCellEditable(int row, int column) { return false; }
        };
        java.util.List<RecordedMacro> rows = new ArrayList<>();
        rebuildMacroManagerRows(model, rows);

        JTable table = new JTable(model);
        table.setSelectionMode(ListSelectionModel.SINGLE_SELECTION);
        table.setAutoResizeMode(JTable.AUTO_RESIZE_OFF);
        table.getColumnModel().getColumn(0).setPreferredWidth(250);
        table.getColumnModel().getColumn(1).setPreferredWidth(90);
        table.getColumnModel().getColumn(2).setPreferredWidth(150);
        table.getColumnModel().getColumn(3).setPreferredWidth(330);
        table.setRowHeight(24);
        table.setBackground(new Color(25, 25, 25));
        table.setForeground(Color.WHITE);
        table.setSelectionBackground(new Color(70, 90, 140));
        table.setSelectionForeground(Color.WHITE);
        table.getTableHeader().setBackground(APP_MENU_ITEM_BACKGROUND);
        table.getTableHeader().setForeground(APP_MENU_FOREGROUND);

        JLabel hint = new JLabel("  Assign or remove a saved macro shortcut, run it, or delete it. Saved macros are available in Macro -> Saved Macros and Shortcut Mapper.");
        hint.setForeground(APP_MENU_FOREGROUND);
        hint.setBorder(BorderFactory.createEmptyBorder(6, 6, 0, 6));

        JButton runButton = new JButton("Run Selected");
        JButton assignButton = new JButton("Assign Shortcut...");
        JButton removeShortcutButton = new JButton("Remove Shortcut");
        JButton deleteButton = new JButton("Delete Macro");
        JButton closeButton = new JButton("Close");

        runButton.addActionListener(e -> {
            int row = table.getSelectedRow();
            if (row >= 0) playMacro(rows.get(row), 1);
        });
        assignButton.addActionListener(e -> {
            int row = table.getSelectedRow();
            if (row < 0) {
                JOptionPane.showMessageDialog(dialog, "Select a macro first.", "Macro Manager", JOptionPane.INFORMATION_MESSAGE);
                return;
            }
            RecordedMacro macro = rows.get(row);
            ShortcutDefinition def = shortcutDefinitions.get(macroShortcutId(macro));
            if (def == null) return;
            KeyStroke keyStroke = captureShortcut(dialog, def);
            if (keyStroke == null) return;
            ShortcutDefinition duplicate = findShortcutDuplicate(def.id, keyStroke);
            if (duplicate != null) {
                JOptionPane.showMessageDialog(dialog, "This shortcut is already used by:\n" + duplicate.displayName, "Shortcut Conflict", JOptionPane.WARNING_MESSAGE);
                return;
            }
            def.currentKeyStroke = keyStroke;
            preferences.put("shortcut." + def.id, keyStroke.toString());
            applyShortcutBindings();
            updateSavedMacrosMenu();
            rebuildMacroManagerRows(model, rows);
        });
        removeShortcutButton.addActionListener(e -> {
            int row = table.getSelectedRow();
            if (row < 0) return;
            RecordedMacro macro = rows.get(row);
            ShortcutDefinition def = shortcutDefinitions.get(macroShortcutId(macro));
            if (def == null) return;
            def.currentKeyStroke = null;
            preferences.remove("shortcut." + def.id);
            applyShortcutBindings();
            updateSavedMacrosMenu();
            rebuildMacroManagerRows(model, rows);
        });
        deleteButton.addActionListener(e -> {
            int row = table.getSelectedRow();
            if (row < 0) return;
            RecordedMacro macro = rows.get(row);
            int choice = JOptionPane.showConfirmDialog(dialog, "Delete saved macro?\n" + macro.name, "Macro Manager", JOptionPane.YES_NO_OPTION);
            if (choice != JOptionPane.YES_OPTION) return;
            deleteSavedMacro(macro, true);
            rebuildMacroManagerRows(model, rows);
        });
        closeButton.addActionListener(e -> dialog.dispose());

        JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT, 6, 6));
        buttons.add(runButton);
        buttons.add(assignButton);
        buttons.add(removeShortcutButton);
        buttons.add(deleteButton);
        buttons.add(closeButton);

        dialog.add(hint, BorderLayout.NORTH);
        dialog.add(new JScrollPane(table), BorderLayout.CENTER);
        dialog.add(buttons, BorderLayout.SOUTH);
        dialog.getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        applyDarkContainerTheme(dialog.getContentPane());
        table.setBackground(new Color(25, 25, 25));
        table.setForeground(Color.WHITE);
        table.getTableHeader().setBackground(APP_MENU_ITEM_BACKGROUND);
        table.getTableHeader().setForeground(APP_MENU_FOREGROUND);
        dialog.setVisible(true);
    }

    private void rebuildMacroManagerRows(javax.swing.table.DefaultTableModel model, java.util.List<RecordedMacro> rows) {
        rows.clear();
        rows.addAll(savedMacros.values());
        rows.sort(Comparator.comparing(m -> m.name, String.CASE_INSENSITIVE_ORDER));
        model.setRowCount(0);
        for (RecordedMacro macro : rows) {
            ShortcutDefinition def = shortcutDefinitions.get(macroShortcutId(macro));
            model.addRow(new Object[]{
                    macro.name,
                    macro.steps.size(),
                    keyStrokeToDisplay(def == null ? null : def.currentKeyStroke),
                    getMacroFile(macro).getAbsolutePath()
            });
        }
    }

    private void deleteSavedMacro(RecordedMacro macro, boolean showMessage) {
        if (macro == null) return;
        savedMacros.remove(macro.id);
        unregisterSavedMacroShortcut(macro);
        File file = getMacroFile(macro);
        boolean deleted = !file.exists() || file.delete();
        applyShortcutBindings();
        updateSavedMacrosMenu();
        updateMacroMenuState();
        if (showMessage) {
            JOptionPane.showMessageDialog(this,
                    deleted ? "Deleted macro: " + macro.name : "Macro was removed from the list, but its file could not be deleted:\n" + file.getAbsolutePath(),
                    "Macro Manager", deleted ? JOptionPane.INFORMATION_MESSAGE : JOptionPane.WARNING_MESSAGE);
        }
    }

    private void toggleLineComment() {
        if (!requireTrialWriteBuildAccess("Toggle Line Comment")) return;
        JTextPane pane = currentTextPane();
        EditorTab tab = currentTab();
        if (pane == null || tab == null) return;
        String ext = getFileExtension(tab.file == null ? "txt" : tab.file.getName()).toUpperCase();
        String token = lineCommentTokenFor(ext);
        if (token == null) {
            JOptionPane.showMessageDialog(this, "Line comment is not configured for this file type: " + ext, "Comment", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        try {
            StyledDocument doc = pane.getStyledDocument();
            Element root = doc.getDefaultRootElement();
            int selectionStart = pane.getSelectionStart();
            int selectionEnd = pane.getSelectionEnd();
            int startLine = root.getElementIndex(selectionStart);
            int endLine = root.getElementIndex(Math.max(selectionStart, selectionEnd - (selectionEnd > selectionStart ? 1 : 0)));

            boolean hasContent = false;
            boolean allCommented = true;
            for (int line = startLine; line <= endLine; line++) {
                Element lineElement = root.getElement(line);
                String lineText = getLineTextWithoutLineBreak(doc, lineElement);
                if (lineText.trim().isEmpty()) continue;
                hasContent = true;
                if (!isLineCommented(lineText, token)) allCommented = false;
            }
            if (!hasContent) return;

            for (int line = endLine; line >= startLine; line--) {
                Element lineElement = root.getElement(line);
                String lineText = getLineTextWithoutLineBreak(doc, lineElement);
                if (lineText.trim().isEmpty()) continue;
                int indent = leadingWhitespaceLength(lineText);
                int insertPosition = lineElement.getStartOffset() + indent;
                if (allCommented) {
                    int removeLength = token.length();
                    int optionalSpacePosition = indent + token.length();
                    if (lineText.length() > optionalSpacePosition && lineText.charAt(optionalSpacePosition) == ' ') removeLength++;
                    doc.remove(insertPosition, removeLength);
                } else {
                    doc.insertString(insertPosition, token + " ", null);
                }
            }
            setModified(tab, true);
            scheduleHighlight();
        } catch (BadLocationException ex) {
            JOptionPane.showMessageDialog(this, "Toggle line comment failed: " + ex.getMessage(), "Comment", JOptionPane.ERROR_MESSAGE);
        }
    }

    private void toggleBlockComment() {
        if (!requireTrialWriteBuildAccess("Toggle Block Comment")) return;
        JTextPane pane = currentTextPane();
        EditorTab tab = currentTab();
        if (pane == null || tab == null) return;
        String ext = getFileExtension(tab.file == null ? "txt" : tab.file.getName()).toUpperCase();
        String[] delimiters = blockCommentDelimitersFor(ext);
        if (delimiters == null) {
            JOptionPane.showMessageDialog(this, "Block comment is not configured for this file type: " + ext, "Comment", JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        String open = delimiters[0];
        String close = delimiters[1];
        try {
            StyledDocument doc = pane.getStyledDocument();
            int start = pane.getSelectionStart();
            int end = pane.getSelectionEnd();
            if (start == end) {
                Element root = doc.getDefaultRootElement();
                Element lineElement = root.getElement(root.getElementIndex(start));
                start = lineElement.getStartOffset();
                end = Math.max(start, lineElement.getEndOffset() - 1);
            }
            String selectedText = doc.getText(start, end - start);
            int leading = leadingWhitespaceLength(selectedText);
            int trailing = trailingWhitespaceLength(selectedText);
            int contentStart = start + leading;
            int contentEnd = end - trailing;
            String content = doc.getText(contentStart, Math.max(0, contentEnd - contentStart));

            if (content.startsWith(open) && content.endsWith(close) && content.length() >= open.length() + close.length()) {
                doc.remove(contentEnd - close.length(), close.length());
                doc.remove(contentStart, open.length());
                pane.select(contentStart, Math.max(contentStart, contentEnd - open.length() - close.length()));
            } else {
                doc.insertString(end, close, null);
                doc.insertString(start, open, null);
                pane.select(start, end + open.length() + close.length());
            }
            setModified(tab, true);
            scheduleHighlight();
        } catch (BadLocationException ex) {
            JOptionPane.showMessageDialog(this, "Toggle block comment failed: " + ex.getMessage(), "Comment", JOptionPane.ERROR_MESSAGE);
        }
    }

    private String getLineTextWithoutLineBreak(StyledDocument doc, Element lineElement) throws BadLocationException {
        int start = lineElement.getStartOffset();
        int end = Math.min(lineElement.getEndOffset(), doc.getLength());
        String text = doc.getText(start, Math.max(0, end - start));
        while (text.endsWith("\n") || text.endsWith("\r")) text = text.substring(0, text.length() - 1);
        return text;
    }

    private boolean isLineCommented(String lineText, String token) {
        int indent = leadingWhitespaceLength(lineText);
        return lineText.startsWith(token, indent);
    }

    private int leadingWhitespaceLength(String text) {
        int i = 0;
        while (i < text.length() && Character.isWhitespace(text.charAt(i)) && text.charAt(i) != '\n' && text.charAt(i) != '\r') i++;
        return i;
    }

    private int trailingWhitespaceLength(String text) {
        int i = text.length();
        while (i > 0 && Character.isWhitespace(text.charAt(i - 1))) i--;
        return text.length() - i;
    }

    private String lineCommentTokenFor(String ext) {
        return switch (ext) {
            case "JAVA", "C", "CPP", "CXX", "CC", "H", "HPP", "CS", "INO", "PDE", "JS", "JSX", "TS", "TSX", "PHP", "RS" -> "//";
            case "PY" -> "#";
            case "SQL" -> "--";
            default -> null;
        };
    }

    private String[] blockCommentDelimitersFor(String ext) {
        return switch (ext) {
            case "JAVA", "C", "CPP", "CXX", "CC", "H", "HPP", "CS", "INO", "PDE", "JS", "JSX", "TS", "TSX", "PHP", "RS", "SQL" -> new String[]{"/*", "*/"};
            case "PY" -> new String[]{"\"\"\"", "\"\"\""};
            default -> null;
        };
    }

    private void setModified(EditorTab tab, boolean modified) {
        if (tab == null || tab.modified == modified) return;
        tab.modified = modified;
        updateTabTitle(tab);
    }

    private void updateTabTitle(EditorTab tab) {
        int index = tabbedPane.indexOfComponent(tab.scrollPane);
        if (index < 0) return;
        String base = tab.file == null ? "untitled" : tab.file.getName();

        // Use a short title in the fixed-width tab. The complete path is kept in the tooltip.
        String display = (tab.modified ? "* " : "") + abbreviateTabTitle(base);
        tabbedPane.setTitleAt(index, display);
        tab.tabTitleLabel.setText(display);
        String toolTip = tab.file == null ? "Untitled" : tab.file.getAbsolutePath();
        tabbedPane.setToolTipTextAt(index, toolTip);
        tab.tabHeader.setToolTipText(toolTip);
        tab.tabTitleLabel.setToolTipText(toolTip);
        updateTabHeaderStyles();
    }

    /**
     * Keeps file extensions visible while avoiding oversized tabs.
     * Example: "very_long_python_script_name.py" becomes "very_long_pyth…py".
     */
    private String abbreviateTabTitle(String name) {
        if (name == null || name.length() <= TAB_TITLE_MAX_CHARS) return name == null ? "" : name;

        int extensionIndex = name.lastIndexOf('.');
        String extension = extensionIndex > 0 ? name.substring(extensionIndex) : "";
        int visiblePrefix = Math.max(6, TAB_TITLE_MAX_CHARS - extension.length() - 1);
        if (visiblePrefix >= name.length()) return name;
        return name.substring(0, visiblePrefix) + "…" + extension;
    }

    private void applyMenuTheme(JMenuBar menuBar) {
        menuBar.setOpaque(true);
        menuBar.setBackground(APP_MENU_BACKGROUND);
        menuBar.setForeground(APP_MENU_FOREGROUND);
        menuBar.setBorder(BorderFactory.createMatteBorder(1, 1, 1, 1, APP_BORDER_COLOR));
        for (MenuElement element : menuBar.getSubElements()) applyMenuElementTheme(element);
    }

    private void applyMenuElementTheme(MenuElement element) {
        Component component = element.getComponent();
        if (component instanceof JComponent jc) {
            jc.setOpaque(true);
            jc.setBackground(APP_MENU_BACKGROUND);
            jc.setForeground(APP_MENU_FOREGROUND);
        }
        if (component instanceof JMenu menu) {
            menu.setOpaque(true);
            menu.setBackground(APP_MENU_BACKGROUND);
            menu.setForeground(APP_MENU_FOREGROUND);
            menu.setBorderPainted(false);
            menu.getPopupMenu().setOpaque(true);
            menu.getPopupMenu().setBackground(APP_MENU_ITEM_BACKGROUND);
            menu.getPopupMenu().setForeground(APP_MENU_FOREGROUND);
            menu.getPopupMenu().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        }
        if (component instanceof JMenuItem item) {
            item.setOpaque(true);
            item.setBackground(APP_MENU_ITEM_BACKGROUND);
            item.setForeground(APP_MENU_FOREGROUND);
            item.setBorder(BorderFactory.createEmptyBorder(4, 10, 4, 10));
            item.setBorderPainted(true);
        }
        if (component instanceof JSeparator separator) {
            separator.setBackground(new Color(75, 75, 75));
            separator.setForeground(new Color(95, 95, 95));
        }
        for (MenuElement child : element.getSubElements()) applyMenuElementTheme(child);
    }

