    /** Updates the Send button separately from code-write permissions. */
    private void updateAiSendButtonState() {
        boolean ready = !aiRequestInProgress;
        aiSendButton.setEnabled(ready);
        aiSendButton.setText(ready ? "\u25b6" : "...");
        aiSendButton.setToolTipText(ready
                ? tr("送出 AI 問題（Ctrl+Enter）。送出本身不會修改、儲存或執行任何檔案。",
                        "Send to AI (Ctrl+Enter). Sending alone never changes, saves, or runs a file.")
                : tr("AI 請求進行中；完成、失敗或逾時後會自動恢復可送出狀態。",
                        "An AI request is in progress. The button becomes available again after completion, failure, or timeout."));
        styleAiPrimaryButton(aiSendButton);
        aiSendButton.revalidate();
        aiSendButton.repaint();
    }

    /**
     * Forces a predictable dark button appearance even when Windows Look & Feel
     * tries to paint its own light native button background.
     */
    private void styleDarkButton(JButton button) {
        if (button == null) return;

        // WindowsButtonUI can ignore per-button setBackground(...) and use the
        // operating-system light button painter. BasicButtonUI paints the
        // component's own foreground/background colors consistently.
        button.setUI(new BasicButtonUI());
        button.setOpaque(true);
        button.setContentAreaFilled(true);
        button.setBorderPainted(true);
        button.setFocusPainted(false);
        button.setRolloverEnabled(true);
        button.setBackground(APP_MENU_ITEM_BACKGROUND); // dark gray fill: #373737
        button.setForeground(APP_MENU_FOREGROUND);      // white button text: #FFFFFF
        button.setBorder(BorderFactory.createCompoundBorder(
                BorderFactory.createLineBorder(new Color(150, 150, 150)),
                BorderFactory.createEmptyBorder(4, 9, 4, 9)));
    }

    /**
     * Converts known hard-coded dialog labels that existed before the full UI
     * language preference was added.  Code/editor content is intentionally not
     * touched; only buttons and labels are translated.
     */
    private String localizeKnownUiLiteral(String text) {
        if (text == null || UI_LANGUAGE_EN.equals(uiLanguage)) return text;
        String traditional = KNOWN_ENGLISH_UI_TO_TRADITIONAL.getOrDefault(text, text);
        return UI_LANGUAGE_ZH_CN.equals(uiLanguage) ? toSimplifiedChinese(traditional) : traditional;
    }

    private void localizeKnownComponentText(Component component) {
        if (component instanceof AbstractButton button) {
            button.setText(localizeKnownUiLiteral(button.getText()));
        } else if (component instanceof JLabel label) {
            label.setText(localizeKnownUiLiteral(label.getText()));
        }
    }

