    private boolean closeAllTabs(boolean exitAfter) {
        while (tabbedPane.getTabCount() > 0) {
            EditorTab tab = currentTab();
            if (tab == null) break;
            if (!closeTab(tab, true)) return false;
        }
        if (!exitAfter && tabbedPane.getTabCount() == 0 && hasTrialWriteBuildAccess()) createUntitledTab();
        return true;
    }

    private void closeAllTabsAndExit() {
        if (closeAllTabs(true)) System.exit(0);
    }

    private void updateStatus() {
        EditorTab tab = currentTab();
        if (tab == null) {
            statusLabel.setText(tr(" 類型: TXT | 編碼: UTF-8 | 檔案: 未開啟", " Type: TXT | Encoding: UTF-8 | File: Not open") + trialStatusSuffix());
            setTitle(APP_NAME + " " + APP_VERSION + " - " + trialWindowTitleSuffix());
            return;
        }
        String fileName = tab.file == null ? "untitled.txt" : tab.file.getName();
        String ext = getFileExtension(fileName).toUpperCase();
        String type = detectLanguageType(ext) + (tab.notebookModel == null ? "" : tr("（儲存格文字模式）", " (cell-text mode)"));
        String path = tab.file == null ? tr("未儲存", "Not saved") : tab.file.getAbsolutePath();
        String macroState = macroRecording ? tr(" | 巨集錄製中", " | MACRO REC") : (macroPlaying ? tr(" | 巨集播放中", " | MACRO PLAY") : "");
        String uvState = activeUvPythonProject == null ? "" : " | uv: " + activeUvPythonProject.rootDirectory.getName();
        statusLabel.setText(String.format(tr(" 類型: %s | 編碼: %s | 檔案: %s%s%s%s", " Type: %s | Encoding: %s | File: %s%s%s%s"),
                type, tab.charset.name(), path, macroState, uvState, trialStatusSuffix()));
        setTitle(APP_NAME + " " + APP_VERSION + " - " + fileName
                + (activeUvPythonProject == null ? "" : " [uv: " + activeUvPythonProject.rootDirectory.getName() + "]")
                + (macroRecording ? " [REC]" : "")
                + trialWindowTitleSuffix());
        applyHighlighting(tab, ext);
    }

    private void scheduleHighlight() {
        if (!applyingHighlight) highlightTimer.restart();
    }

    private void applyHighlightingToCurrentTab() {
        EditorTab tab = currentTab();
        if (tab == null) return;
        String fileName = tab.file == null ? "untitled.txt" : tab.file.getName();
        applyHighlighting(tab, getFileExtension(fileName).toUpperCase());
    }

