    private void findNextText(String find, boolean matchCase) {
        JTextPane textPane = currentTextPane();
        if (textPane == null || textPane.getText().isEmpty()) { JOptionPane.showMessageDialog(this, "目前文件沒有內容。", "Find", JOptionPane.INFORMATION_MESSAGE); return; }
        String text = textPane.getText();
        String source = matchCase ? text : text.toLowerCase();
        String target = matchCase ? find : find.toLowerCase();
        int start = Math.max(textPane.getSelectionEnd(), textPane.getCaretPosition());
        if (start >= source.length()) start = 0;
        int index = source.indexOf(target, start);
        if (index < 0 && start > 0) index = source.indexOf(target, 0);
        if (index < 0) { JOptionPane.showMessageDialog(this, "找不到文字：" + find, "Find", JOptionPane.INFORMATION_MESSAGE); return; }
        textPane.requestFocusInWindow(); textPane.select(index, index + find.length());
        try { Rectangle r = textPane.modelToView2D(index).getBounds(); textPane.scrollRectToVisible(r); } catch (BadLocationException ignored) {}
    }

    private void replaceAllText(String find, String replacement, boolean matchCase) {
        JTextPane textPane = currentTextPane();
        if (textPane == null || find == null || find.isEmpty()) return;
        String text = textPane.getText();
        String updated; int count;
        if (matchCase) { count = countOccurrences(text, find); updated = text.replace(find, replacement == null ? "" : replacement); }
        else {
            Pattern pattern = Pattern.compile(Pattern.quote(find), Pattern.CASE_INSENSITIVE | Pattern.UNICODE_CASE);
            Matcher matcher = pattern.matcher(text); StringBuffer buffer = new StringBuffer(); count = 0; String safeReplacement = Matcher.quoteReplacement(replacement == null ? "" : replacement);
            while (matcher.find()) { matcher.appendReplacement(buffer, safeReplacement); count++; }
            matcher.appendTail(buffer); updated = buffer.toString();
        }
        if (count == 0) { JOptionPane.showMessageDialog(this, "找不到文字：" + find, "Replace", JOptionPane.INFORMATION_MESSAGE); return; }
        textPane.setText(updated); scheduleHighlight(); JOptionPane.showMessageDialog(this, "Replace completed. 共取代 " + count + " 處。", "Replace", JOptionPane.INFORMATION_MESSAGE);
    }

    private int countOccurrences(String text, String find) {
        int count = 0, index = 0;
        while ((index = text.indexOf(find, index)) >= 0) { count++; index += find.length(); }
        return count;
    }

