    private String searchFiles(String folderPath, String keyword, String extensions, boolean matchCase) {
        if (keyword == null || keyword.isEmpty()) return "請輸入 Keyword。";
        File root = new File(folderPath == null ? "" : folderPath.trim());
        if (!root.exists() || !root.isDirectory()) return "Folder 不存在或不是資料夾：" + root.getAbsolutePath();

        Set<String> extSet = parseExtensionSet(extensions);
        StringBuilder sb = new StringBuilder();
        int[] hits = {0};
        int[] files = {0};
        String target = matchCase ? keyword : keyword.toLowerCase();

        try (Stream<Path> stream = Files.walk(root.toPath())) {
            stream.filter(Files::isRegularFile).forEach(path -> {
                String ext = getFileExtension(path.getFileName().toString()).toLowerCase();
                if (!extSet.isEmpty() && !extSet.contains(ext)) return;
                try {
                    byte[] bytes = Files.readAllBytes(path);
                    Charset cs = detectCharset(bytes);
                    String text = new String(bytes, cs);
                    String[] lines = text.split("\\R", -1);
                    boolean fileHit = false;
                    for (int i = 0; i < lines.length; i++) {
                        String source = matchCase ? lines[i] : lines[i].toLowerCase();
                        if (source.contains(target)) {
                            if (!fileHit) {
                                files[0]++;
                                fileHit = true;
                            }
                            hits[0]++;
                            sb.append(path).append(':').append(i + 1).append(": ")
                                    .append(lines[i].trim()).append('\n');
                        }
                    }
                } catch (Exception ex) {
                    sb.append("[Skip] ").append(path).append(" - ").append(ex.getMessage()).append('\n');
                }
            });
        } catch (IOException ex) {
            return "搜尋失敗：" + ex.getMessage();
        }
        if (hits[0] == 0) return "找不到：" + keyword;
        return "Files: " + files[0] + " | Hits: " + hits[0] + "\n\n" + sb;
    }

    private String replaceInFiles(String folderPath, String find, String replacement,
                                  String extensions, boolean matchCase) {
        File root = new File(folderPath == null ? "" : folderPath.trim());
        if (!root.exists() || !root.isDirectory()) {
            return "Folder 不存在或不是資料夾：" + root.getAbsolutePath();
        }

        Set<String> extSet = parseExtensionSet(extensions);
        StringBuilder log = new StringBuilder();
        int[] changedFiles = {0};
        int[] replacements = {0};
        int[] failedFiles = {0};

        try (Stream<Path> stream = Files.walk(root.toPath())) {
            stream.filter(Files::isRegularFile).forEach(path -> {
                String ext = getFileExtension(path.getFileName().toString()).toLowerCase();
                if (!extSet.isEmpty() && !extSet.contains(ext)) return;

                try {
                    byte[] bytes = Files.readAllBytes(path);
                    Charset charset = detectCharset(bytes);
                    String original = new String(bytes, charset);
                    TextReplacement result = replaceTextInString(original, find,
                            replacement == null ? "" : replacement, matchCase);

                    if (result.count() > 0) {
                        Files.writeString(path, result.text(), charset);
                        changedFiles[0]++;
                        replacements[0] += result.count();
                        log.append("UPDATED ").append(path)
                                .append(" : ").append(result.count()).append(" replacement(s)\n");
                    }
                } catch (Exception ex) {
                    failedFiles[0]++;
                    log.append("FAILED  ").append(path).append(" : ").append(ex.getMessage()).append('\n');
                }
            });
        } catch (IOException ex) {
            return "Replace in Files failed: " + ex.getMessage();
        }

        if (changedFiles[0] == 0) {
            return "No matching text found: " + find;
        }
        return "Replace in Files completed.\nChanged files: " + changedFiles[0]
                + "\nTotal replacements: " + replacements[0]
                + "\nFailed files: " + failedFiles[0]
                + "\n\nImportant: open editor tabs keep their current in-memory text. Reload any changed file to see disk updates.\n\n"
                + log;
    }

    private TextReplacement replaceTextInString(String text, String find, String replacement, boolean matchCase) {
        if (matchCase) {
            int count = countOccurrences(text, find);
            return new TextReplacement(text.replace(find, replacement), count);
        }
        Pattern pattern = Pattern.compile(Pattern.quote(find), Pattern.CASE_INSENSITIVE | Pattern.UNICODE_CASE);
        Matcher matcher = pattern.matcher(text);
        StringBuffer buffer = new StringBuffer();
        int count = 0;
        while (matcher.find()) {
            matcher.appendReplacement(buffer, Matcher.quoteReplacement(replacement));
            count++;
        }
        matcher.appendTail(buffer);
        return new TextReplacement(buffer.toString(), count);
    }

    private record TextReplacement(String text, int count) {}

