    private String batchConvertToUtf8(String src, String out, String extensions, String sourceEncoding) {
        File sourceRoot = new File(src == null ? "" : src.trim());
        File outRoot = new File(out == null ? "" : out.trim());
        if (!sourceRoot.exists() || !sourceRoot.isDirectory()) return "Source Folder 不存在或不是資料夾：" + sourceRoot.getAbsolutePath();
        if (!outRoot.exists() && !outRoot.mkdirs()) return "無法建立 Output Folder：" + outRoot.getAbsolutePath();
        Set<String> extSet = parseExtensionSet(extensions);
        StringBuilder log = new StringBuilder(); int[] ok = {0}; int[] fail = {0};
        try (Stream<Path> stream = Files.walk(sourceRoot.toPath())) {
            stream.filter(Files::isRegularFile).forEach(path -> {
                String ext = getFileExtension(path.getFileName().toString()).toLowerCase();
                if (!extSet.isEmpty() && !extSet.contains(ext)) return;
                try {
                    byte[] bytes = Files.readAllBytes(path);
                    Charset srcCs = "Auto Detect".equals(sourceEncoding) ? detectCharset(bytes) : Charset.forName(sourceEncoding);
                    String text = new String(bytes, srcCs);
                    Path relative = sourceRoot.toPath().relativize(path);
                    Path target = outRoot.toPath().resolve(relative);
                    Files.createDirectories(target.getParent());
                    Files.writeString(target, text, StandardCharsets.UTF_8);
                    ok[0]++;
                    log.append("OK   ").append(srcCs.name()).append(" -> UTF-8 : ").append(relative).append('\n');
                } catch (Exception ex) {
                    fail[0]++; log.append("FAIL ").append(path).append(" : ").append(ex.getMessage()).append('\n');
                }
            });
        } catch (IOException ex) { return "批次轉檔失敗：" + ex.getMessage(); }
        return "Batch Convert Completed. OK=" + ok[0] + ", FAIL=" + fail[0] + "\nOutput: " + outRoot.getAbsolutePath() + "\n\n" + log;
    }

    private File chooseDirectory(String initialText) {
        JFileChooser chooser = new JFileChooser();
        chooser.setFileSelectionMode(JFileChooser.DIRECTORIES_ONLY);
        File initial = initialText == null || initialText.isBlank() ? currentDirectory : new File(initialText.trim());
        if (initial.exists()) chooser.setCurrentDirectory(initial.isDirectory() ? initial : initial.getParentFile());
        int option = chooser.showOpenDialog(this);
        return option == JFileChooser.APPROVE_OPTION ? chooser.getSelectedFile() : null;
    }

    private Set<String> parseExtensionSet(String extensions) {
        Set<String> set = new HashSet<>();
        if (extensions == null || extensions.isBlank()) return set;
        for (String e : extensions.split("[,;\\s]+")) {
            String cleaned = e.trim().toLowerCase();
            if (cleaned.startsWith("*.")) cleaned = cleaned.substring(2);
            else if (cleaned.startsWith(".")) cleaned = cleaned.substring(1);
            if (!cleaned.isEmpty()) set.add(cleaned);
        }
        return set;
    }

    private Charset detectCharset(byte[] bytes) {
        if (bytes.length >= 3 && (bytes[0] & 0xFF) == 0xEF && (bytes[1] & 0xFF) == 0xBB && (bytes[2] & 0xFF) == 0xBF) return StandardCharsets.UTF_8;
        if (bytes.length >= 2 && (bytes[0] & 0xFF) == 0xFF && (bytes[1] & 0xFF) == 0xFE) return StandardCharsets.UTF_16LE;
        if (bytes.length >= 2 && (bytes[0] & 0xFF) == 0xFE && (bytes[1] & 0xFF) == 0xFF) return StandardCharsets.UTF_16BE;
        boolean isAsciiOnly = true, utf8Valid = true; int expected = 0;
        for (byte value : bytes) {
            int b = value & 0xFF; if (b >= 0x80) isAsciiOnly = false;
            if (expected > 0) { if ((b & 0xC0) != 0x80) { utf8Valid = false; break; } expected--; }
            else if (b >= 0x80) { if ((b & 0xE0) == 0xC0) expected = 1; else if ((b & 0xF0) == 0xE0) expected = 2; else if ((b & 0xF8) == 0xF0) expected = 3; else { utf8Valid = false; break; } }
        }
        if (isAsciiOnly || (utf8Valid && expected == 0)) return StandardCharsets.UTF_8;
        try { return Charset.forName("MS950"); } catch (Exception e) { return Charset.forName("Big5"); }
    }

    private boolean isBig5Like(Charset charset) {
        String name = charset.name().toLowerCase();
        return name.contains("big5") || name.contains("ms950") || name.contains("950");
    }

    private String getFileExtension(String name) {
        int idx = name.lastIndexOf('.');
        return idx == -1 ? "TXT" : name.substring(idx + 1);
    }

    private String detectLanguageType(String ext) {
        return switch (ext) {
            case "C" -> "C"; case "CPP", "CXX", "CC" -> "C++"; case "H", "HPP" -> "C/C++ Header"; case "JAVA" -> "Java"; case "JS" -> "JavaScript"; case "JSX", "TSX" -> "React"; case "TS" -> "TypeScript"; case "NS" -> "NS Script"; case "PY" -> "Python"; case "IPYNB" -> "Jupyter Notebook"; case "SQL" -> "SQL"; case "CSV" -> "CSV"; case "JSON" -> "JSON"; case "HTM", "HTML" -> "HTML"; case "RS" -> "Rust"; case "CS" -> "C#"; case "INO", "PDE" -> "Arduino"; case "PHP" -> "PHP"; case "TXT" -> "TXT"; default -> ext;
        };
    }

    private String appendEncodingBeforeExtension(String name, String charsetName) {
        String safe = charsetName.replace('-', '_').replace(' ', '_');
        int idx = name.lastIndexOf('.');
        if (idx < 0) return name + "_" + safe;
        return name.substring(0, idx) + "_" + safe + name.substring(idx);
    }

    private void applyHighlighting(EditorTab tab, String ext) {
        if (tab == null || applyingHighlight) return;
        // Notebook tabs show a Python-oriented cell-text view (# %% markers).
        if ("IPYNB".equalsIgnoreCase(ext)) ext = "PY";
        applyingHighlight = true;
        try {
            StyledDocument doc = tab.textPane.getStyledDocument();
            SimpleAttributeSet plain = new SimpleAttributeSet();
            StyleConstants.setForeground(plain, editorTextColor);
            StyleConstants.setBackground(plain, editorBackgroundColor);
            StyleConstants.setBold(plain, false);
            doc.setCharacterAttributes(0, doc.getLength(), plain, true);
            String text = doc.getText(0, doc.getLength());

            String keywordPattern = keywordPatternFor(ext);
            if (keywordPattern != null) applyRegexStyle(doc, text, keywordPattern, ext.equals("SQL") ? Pattern.CASE_INSENSITIVE : 0, KEYWORD_BLUE, true);

            String stringPattern = stringPatternFor(ext);
            if (stringPattern != null) applyRegexStyle(doc, text, stringPattern, Pattern.MULTILINE | Pattern.DOTALL, STRING_ORANGE, false);

            String commentPattern = commentPatternFor(ext);
            if (commentPattern != null) applyRegexStyle(doc, text, commentPattern, Pattern.MULTILINE | Pattern.DOTALL, COMMENT_GREEN, false);
        } catch (BadLocationException ignored) {
        } finally {
            applyingHighlight = false;
        }
    }

    private void applyRegexStyle(StyledDocument doc, String text, String pattern, int flags, Color fg, boolean bold) {
        Pattern p = Pattern.compile(pattern, flags);
        Matcher m = p.matcher(text);
        SimpleAttributeSet style = new SimpleAttributeSet();
        StyleConstants.setForeground(style, fg);
        StyleConstants.setBackground(style, editorBackgroundColor);
        StyleConstants.setBold(style, bold);
        while (m.find()) doc.setCharacterAttributes(m.start(), m.end() - m.start(), style, false);
    }

    private String keywordPatternFor(String ext) {
        return switch (ext) {
            case "C", "CPP", "CXX", "CC", "H", "HPP", "JAVA", "CS", "INO", "PDE" -> "\\b(class|struct|if|else|for|while|do|switch|case|break|continue|return|int|long|float|double|char|void|boolean|bool|public|private|protected|static|final|const|new|import|package|using|namespace|try|catch|throw|throws|extends|implements|include|define|uint8_t|uint16_t|uint32_t|size_t|sizeof|setup|loop|pinMode|digitalWrite|digitalRead|analogRead|analogWrite|delay|delayMicroseconds|millis|micros|tone|noTone|Serial|HIGH|LOW|INPUT|OUTPUT|INPUT_PULLUP)\\b";
            case "JS", "JSX", "TS", "TSX" -> "\\b(const|let|var|function|return|if|else|for|while|import|export|class|true|false|null|undefined|from|default|async|await|try|catch|new|this|props|state)\\b";
            case "PY" -> "\\b(def|class|if|elif|else|for|while|return|import|from|as|print|in|is|not|and|or|True|False|None|try|except|finally|with|lambda)\\b";
            case "SQL" -> "\\b(SELECT|INSERT|UPDATE|DELETE|FROM|WHERE|JOIN|LEFT|RIGHT|INNER|OUTER|ON|GROUP|BY|ORDER|CREATE|ALTER|DROP|TABLE|VIEW|INDEX|INTO|VALUES|SET|HAVING|DISTINCT|TOP|LIMIT|AS|AND|OR|NOT|NULL)\\b";
            case "PHP" -> "\\b(echo|function|global|if|else|elseif|foreach|while|return|class|public|private|protected|new|namespace|use|try|catch|throw|extends|implements)\\b";
            case "RS" -> "\\b(fn|let|mut|match|if|else|for|while|loop|return|struct|enum|impl|use|pub|mod|crate|trait|where|async|await|move|ref|self|Self)\\b";
            case "HTML", "HTM" -> "(<\\/?[a-zA-Z][a-zA-Z0-9-]*\\b[^>]*>|\\b(class|id|style|href|src|alt|title)=\")";
            case "JSON" -> "(\"[^\"]+\"\\s*:)";
            default -> null;
        };
    }

    private String stringPatternFor(String ext) {
        return switch (ext) {
            case "JAVA", "C", "CPP", "CXX", "CC", "H", "HPP", "CS", "INO", "PDE", "JS", "JSX", "TS", "TSX", "PHP", "RS" -> "\"(?:\\\\.|[^\"\\\\])*\"|'(?:\\\\.|[^'\\\\])*'";
            case "PY" -> "\"(?:\\\\.|[^\"\\\\])*\"|'(?:\\\\.|[^'\\\\])*'";
            case "SQL" -> "'(?:''|[^'])*'";
            default -> null;
        };
    }

    private String commentPatternFor(String ext) {
        return switch (ext) {
            case "JAVA", "C", "CPP", "CXX", "CC", "H", "HPP", "CS", "INO", "PDE", "JS", "JSX", "TS", "TSX", "PHP", "RS" -> "//.*?$|/\\*[\\s\\S]*?\\*/";
            case "PY" -> "#.*?$|'''[\\s\\S]*?'''|\"\"\"[\\s\\S]*?\"\"\"";
            case "SQL" -> "---.*?$|--.*?$|/\\*[\\s\\S]*?\\*/";
            default -> null;
        };
    }

    private JMenu createScreenSizeMenu() {
        JMenu screenSizeMenu = new JMenu(tr("螢幕尺寸", "Screen Size"));
        JMenuItem showCurrentItem = new JMenuItem(tr("顯示目前螢幕尺寸", "Show Current Screen Size")); showCurrentItem.addActionListener(e -> showCurrentScreenSize()); screenSizeMenu.add(showCurrentItem); screenSizeMenu.addSeparator();
        int[][] commonSizes = {{480,768},{768,1024},{800,600},{1024,768},{1280,720},{1366,768},{1440,900},{1600,900},{1920,1080},{1920,1200},{2560,1440},{3840,2160}};
        for (int[] size : commonSizes) { JMenuItem item = new JMenuItem(size[0] + " x " + size[1]); item.addActionListener(e -> setWindowSize(size[0], size[1])); screenSizeMenu.add(item); }
        screenSizeMenu.addSeparator();
        JMenuItem maximizeItem = new JMenuItem(tr("最大化 / 使用完整工作區", "Maximize / Full Screen Work Area")); maximizeItem.addActionListener(e -> maximizeWindowToWorkArea()); screenSizeMenu.add(maximizeItem);
        JMenuItem customItem = new JMenuItem(tr("自訂 X x Y...", "Custom X x Y...")); customItem.addActionListener(e -> changeCustomWindowSize()); screenSizeMenu.add(customItem);
        return screenSizeMenu;
    }

    private void showCurrentScreenSize() {
        Dimension fullScreen = Toolkit.getDefaultToolkit().getScreenSize();
        Rectangle workArea = GraphicsEnvironment.getLocalGraphicsEnvironment().getMaximumWindowBounds();
        JOptionPane.showMessageDialog(this, "目前 Java 偵測到的主要螢幕完整解析度：" + fullScreen.width + " x " + fullScreen.height + "\n可用工作區：" + workArea.width + " x " + workArea.height + "\n目前視窗大小：" + getWidth() + " x " + getHeight(), tr("螢幕尺寸", "Screen Size"), JOptionPane.INFORMATION_MESSAGE);
    }

    private void setWindowSize(int width, int height) { setExtendedState(JFrame.NORMAL); setSize(width, height); setLocationRelativeTo(null); }
    private void maximizeWindowToWorkArea() { setExtendedState(JFrame.MAXIMIZED_BOTH); }

    private void changeCustomWindowSize() {
        JTextField widthField = new JTextField(String.valueOf(getWidth()), 8); JTextField heightField = new JTextField(String.valueOf(getHeight()), 8);
        JPanel panel = new JPanel(new GridLayout(2, 2, 6, 6)); panel.add(new JLabel(tr("寬度 / X:", "Width / X:"))); panel.add(widthField); panel.add(new JLabel(tr("高度 / Y:", "Height / Y:"))); panel.add(heightField);
        applyDarkContainerTheme(panel);
        int result = JOptionPane.showConfirmDialog(this, panel, tr("自訂視窗尺寸", "Custom Window Size"), JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
        if (result != JOptionPane.OK_OPTION) return;
        try { int width = Integer.parseInt(widthField.getText().trim()); int height = Integer.parseInt(heightField.getText().trim()); if (width < 320 || height < 240) { JOptionPane.showMessageDialog(this, "視窗尺寸太小，請至少輸入 320 x 240。", tr("螢幕尺寸錯誤", "Screen Size Error"), JOptionPane.WARNING_MESSAGE); return; } setWindowSize(width, height); }
        catch (NumberFormatException ex) { JOptionPane.showMessageDialog(this, "請輸入正確的整數，例如 1366 與 768。", tr("螢幕尺寸錯誤", "Screen Size Error"), JOptionPane.ERROR_MESSAGE); }
    }

    private void applyEditorTheme(EditorTab tab) {
        if (tab == null) return;
        tab.textPane.setBackground(editorBackgroundColor);
        tab.textPane.setForeground(editorTextColor);
        tab.textPane.setCaretColor(editorTextColor);
        tab.textPane.setSelectionColor(new Color(70, 90, 140));
        tab.textPane.setSelectedTextColor(Color.WHITE);
        tab.scrollPane.getViewport().setBackground(editorBackgroundColor);
        tab.scrollPane.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        tab.lineNumberView.setTheme(new Color(35, 35, 35), Color.LIGHT_GRAY);
        applyHighlighting(tab, getFileExtension(tab.file == null ? "txt" : tab.file.getName()).toUpperCase());
    }

    private void applyEditorThemeToAllTabs() {
        for (int i = 0; i < tabbedPane.getTabCount(); i++) {
            Component c = tabbedPane.getComponentAt(i);
            if (c instanceof JScrollPane sp && sp.getClientProperty("editorTab") instanceof EditorTab tab) applyEditorTheme(tab);
        }
        repaint();
    }

