        JPanel mainPanel = new JPanel(new BorderLayout(8, 8)); mainPanel.setBorder(BorderFactory.createEmptyBorder(12, 12, 12, 12));
        JLabel previewLabel = new JLabel(" Preview:  if (javaCode) { return true; } "); previewLabel.setOpaque(true); previewLabel.setFont(new Font("Monospaced", Font.PLAIN, 16)); previewLabel.setBackground(editorBackgroundColor); previewLabel.setForeground(editorTextColor); previewLabel.setBorder(BorderFactory.createEmptyBorder(12, 12, 12, 12)); mainPanel.add(previewLabel, BorderLayout.CENTER);
        JButton bgButton = new JButton("Choose Background..."); JButton textButton = new JButton("Choose Text..."); JButton resetButton = new JButton("Reset Black / White"); JButton okButton = new JButton("OK"); JButton cancelButton = new JButton("Cancel");
        final Color[] selectedBg = {editorBackgroundColor}; final Color[] selectedText = {editorTextColor};
        bgButton.addActionListener(e -> { Color c = JColorChooser.showDialog(dialog, "Choose Background Color", selectedBg[0]); if (c != null) { selectedBg[0] = c; previewLabel.setBackground(c); } });
