        cancelButton.addActionListener(e -> dialog.dispose());
        JPanel topButtons = new JPanel(new FlowLayout(FlowLayout.LEFT)); topButtons.add(bgButton); topButtons.add(textButton); topButtons.add(resetButton); mainPanel.add(topButtons, BorderLayout.NORTH);
        JPanel bottomButtons = new JPanel(new FlowLayout(FlowLayout.RIGHT)); bottomButtons.add(okButton); bottomButtons.add(cancelButton); mainPanel.add(bottomButtons, BorderLayout.SOUTH);
        dialog.add(mainPanel, BorderLayout.CENTER); dialog.getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR, 1)); dialog.getContentPane().setBackground(APP_MENU_BACKGROUND); applyDarkContainerTheme(dialog.getContentPane()); previewLabel.setBackground(editorBackgroundColor); previewLabel.setForeground(editorTextColor); dialog.setVisible(true);
