    private void changeFontSize() {
        EditorTab tab = currentTab();
        int currentSize = tab == null ? 14 : tab.textPane.getFont().getSize();
        String sizeStr = showHighContrastTextInputDialog(tr("字型大小", "Font Size"), tr("輸入字型大小：", "Enter font size:"), String.valueOf(currentSize));
        if (sizeStr == null) return;
        try {
            int size = Integer.parseInt(sizeStr.trim());
            for (int i = 0; i < tabbedPane.getTabCount(); i++) {
                Component c = tabbedPane.getComponentAt(i);
                if (c instanceof JScrollPane sp && sp.getClientProperty("editorTab") instanceof EditorTab t) {
                    Font newFont = new Font("Monospaced", Font.PLAIN, size);
                    t.textPane.setFont(newFont); t.lineNumberView.setFont(newFont); t.lineNumberView.repaint();
                }
            }
        } catch (NumberFormatException ex) { JOptionPane.showMessageDialog(this, "請輸入正確的數字。", "Font Size Error", JOptionPane.ERROR_MESSAGE); }
    }

    private void copyCurrentPathToClipboard() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null) { JOptionPane.showMessageDialog(this, "目前尚未開啟檔案。", "No File", JOptionPane.INFORMATION_MESSAGE); return; }
        Toolkit.getDefaultToolkit().getSystemClipboard().setContents(new java.awt.datatransfer.StringSelection(tab.file.getAbsolutePath()), null);
        JOptionPane.showMessageDialog(this, "已複製完整路徑：\n" + tab.file.getAbsolutePath());
    }

    private boolean ensureCurrentFileSaved() {
        if (!requireTrialWriteBuildAccess("Save Before Build / Run")) return false;
        EditorTab tab = currentTab();
        if (tab == null) return false;
        if (tab.modified || tab.file == null) saveCurrentFile();
        return tab.file != null && !tab.modified;
    }

    private String showProgramInputDialog(String title, String message) {
        JDialog dialog = new JDialog(this, title, true);
        dialog.setLayout(new BorderLayout(8, 8));
        dialog.setSize(620, 420);
        dialog.setLocationRelativeTo(this);
        dialog.getContentPane().setBackground(APP_MENU_BACKGROUND);
        dialog.getRootPane().setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));

        JPanel mainPanel = new JPanel(new BorderLayout(8, 8));
        mainPanel.setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10));
        mainPanel.setBackground(APP_MENU_BACKGROUND);

        JLabel hint = new JLabel("<html>" + message.replace("\n", "<br>") + "</html>");
        hint.setForeground(APP_MENU_FOREGROUND);
        mainPanel.add(hint, BorderLayout.NORTH);

        JTextArea inputArea = new JTextArea(12, 60);
        inputArea.setFont(new Font("Monospaced", Font.PLAIN, 14));
        inputArea.setBackground(editorBackgroundColor);
        inputArea.setForeground(editorTextColor);
        inputArea.setCaretColor(editorTextColor);
        inputArea.setLineWrap(false);
        JScrollPane inputScroll = new JScrollPane(inputArea);
        inputScroll.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        mainPanel.add(inputScroll, BorderLayout.CENTER);

        JCheckBox appendNewLine = new JCheckBox("Append final Enter / newline", true);
        appendNewLine.setBackground(APP_MENU_BACKGROUND);
        appendNewLine.setForeground(APP_MENU_FOREGROUND);

        JButton runButton = new JButton("Run");
        JButton cancelButton = new JButton("Cancel");
        runButton.setBackground(APP_MENU_ITEM_BACKGROUND);
        runButton.setForeground(APP_MENU_FOREGROUND);
        cancelButton.setBackground(APP_MENU_ITEM_BACKGROUND);
        cancelButton.setForeground(APP_MENU_FOREGROUND);

        JPanel bottomPanel = new JPanel(new BorderLayout());
        bottomPanel.setBackground(APP_MENU_BACKGROUND);
        bottomPanel.add(appendNewLine, BorderLayout.WEST);

        JPanel buttonPanel = new JPanel(new FlowLayout(FlowLayout.RIGHT));
        buttonPanel.setBackground(APP_MENU_BACKGROUND);
        buttonPanel.add(runButton);
        buttonPanel.add(cancelButton);
        bottomPanel.add(buttonPanel, BorderLayout.EAST);
        mainPanel.add(bottomPanel, BorderLayout.SOUTH);

        final String[] result = new String[1];
        runButton.addActionListener(e -> {
            String text = inputArea.getText();
            if (appendNewLine.isSelected() && !text.isEmpty() && !text.endsWith("\n")) {
                text += System.lineSeparator();
            }
            result[0] = text;
            dialog.dispose();
        });
        cancelButton.addActionListener(e -> { result[0] = null; dialog.dispose(); });

        dialog.add(mainPanel, BorderLayout.CENTER);
        SwingUtilities.invokeLater(inputArea::requestFocusInWindow);
        dialog.setVisible(true);
        return result[0];
    }

    private void compileCurrentFileAuto() {
        if (blockNewBuildOrRunWhileProgramActive("Compile Current")) return;
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null) {
            JOptionPane.showMessageDialog(this, "請先開啟並儲存要編譯或檢查的檔案。", "Compile Current", JOptionPane.WARNING_MESSAGE);
            return;
        }

        String ext = getFileExtension(tab.file.getName()).toLowerCase();
        switch (ext) {
            case "java" -> compileCurrentJavaFile();
            case "c" -> compileCurrentCFile();
            case "cpp", "cc", "cxx" -> compileCurrentCppFile();
            case "cs" -> compileCurrentCSharpFile();
            case "py" -> checkCurrentPythonSyntax();
            case "ipynb" -> validateCurrentJupyterNotebook();
            case "js", "mjs", "cjs" -> checkCurrentJavaScriptSyntax();
            case "php" -> checkCurrentPhpSyntax();
            case "rs" -> compileCurrentRustFile();
            case "ino", "pde" -> compileCurrentArduinoSketch();
            default -> JOptionPane.showMessageDialog(this,
                    "目前副檔名不支援 Compile Current：." + ext +
                            "\n支援：.java, .c, .cpp/.cc/.cxx, .cs, .py, .ipynb, .js/.mjs/.cjs, .php, .rs, .ino/.pde",
                    "Compile Current", JOptionPane.INFORMATION_MESSAGE);
        }
    }

    private void compileCurrentJavaFile() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !getFileExtension(tab.file.getName()).equalsIgnoreCase("java")) {
            JOptionPane.showMessageDialog(this, "請先開啟並儲存 Java 檔案。", "Java Compile", JOptionPane.WARNING_MESSAGE);
            return;
        }
        if (!ensureCurrentFileSaved()) return;
        List<String> jdbcJars = getSelectedMsSqlDriverPaths(MSSQL_JAVA, "Java Compile");
        if (jdbcJars == null) return;
        List<String> command = new ArrayList<>();
        command.add(getResolvedLanguageToolCommand(TOOL_JAVA_COMPILER));
        command.add("-encoding");
        command.add(tab.charset.name());
        if (!jdbcJars.isEmpty()) {
            command.add("-cp");
            command.add(javaClassPathWithMsSqlDriver(null, jdbcJars));
        }
        command.add(tab.file.getName());
        executeCommand(command, tab.file.getParentFile(), "Java Compile");
    }

    private void runCurrentJavaClass() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !getFileExtension(tab.file.getName()).equalsIgnoreCase("java")) {
            JOptionPane.showMessageDialog(this, "請先開啟 Java 檔案。", "Java Run", JOptionPane.WARNING_MESSAGE);
            return;
        }
        if (sourceLikelyNeedsInput(tab.textPane.getText())) {
            String input = showProgramInputDialog("Java Program Input",
                    "此 Java 程式看起來可能需要鍵盤輸入。\n" +
                    "請把每次輸入內容依序填入，每筆輸入請換行。\n" +
                    "例如 Scanner.nextInt() 可輸入：50\n" +
                    "若不需要輸入，可直接按 Run。");
            if (input == null) return;
            runJavaClassWithProvidedInput(input);
            return;
        }
        runJavaClassWithProvidedInput("");
    }

    private void runCurrentJavaClassInteractive() {
        if (blockNewBuildOrRunWhileProgramActive("Java Interactive Console")) return;
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !getFileExtension(tab.file.getName()).equalsIgnoreCase("java")) {
            JOptionPane.showMessageDialog(this, "請先開啟 Java 檔案。", "Java Interactive Console", JOptionPane.WARNING_MESSAGE);
            return;
        }
        if (!ensureCurrentFileSaved()) return;
        List<String> jdbcJars = getSelectedMsSqlDriverPaths(MSSQL_JAVA, "Java Interactive Console");
        if (jdbcJars == null) return;

        String className = removeExtension(tab.file.getName());
        Charset javaIoCharset = normalizedJavaOutputCharset(tab.charset);
        File classPathDir = tab.file.getParentFile();
        String classPath = javaClassPathWithMsSqlDriver(classPathDir, jdbcJars);
        startInteractiveConsole(
                List.of(getResolvedLanguageToolCommand(TOOL_JAVA_RUNTIME),
                        "-Dfile.encoding=" + javaIoCharset.name(),
                        "-Dsun.stdout.encoding=" + javaIoCharset.name(),
                        "-Dsun.stderr.encoding=" + javaIoCharset.name(),
                        "-cp", classPath,
                        className),
                classPathDir,
                "Java Interactive Console - " + className,
                javaIoCharset
        );
    }

    private void runCurrentJavaClassWithInput() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !getFileExtension(tab.file.getName()).equalsIgnoreCase("java")) {
            JOptionPane.showMessageDialog(this, "請先開啟 Java 檔案。", "Java Run", JOptionPane.WARNING_MESSAGE);
            return;
        }
        String input = showProgramInputDialog("Java Program Input",
                "請輸入要送給 Java 程式 System.in 的內容。\n" +
                "每一行代表一次 Enter；例如要輸入兩個數字，可寫：\n10\n20");
        if (input == null) return;
        runJavaClassWithProvidedInput(input);
    }

    private void runJavaClassWithProvidedInput(String stdinText) {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null) return;
        List<String> jdbcJars = getSelectedMsSqlDriverPaths(MSSQL_JAVA, "Java Run");
        if (jdbcJars == null) return;

        String className = removeExtension(tab.file.getName());
        Charset javaOutputCharset = normalizedJavaOutputCharset(tab.charset);
        File classPathDir = tab.file.getParentFile();
        String classPath = javaClassPathWithMsSqlDriver(classPathDir, jdbcJars);
        executeCommand(
                List.of(getResolvedLanguageToolCommand(TOOL_JAVA_RUNTIME),
                        "-Dfile.encoding=" + javaOutputCharset.name(),
                        "-Dsun.stdout.encoding=" + javaOutputCharset.name(),
                        "-Dsun.stderr.encoding=" + javaOutputCharset.name(),
                        "-cp", classPath,
                        className),
                classPathDir,
                "Java Run",
                javaOutputCharset,
                stdinText
        );
    }

    private boolean sourceLikelyNeedsInput(String sourceText) {
        if (sourceText == null) return false;
        return sourceText.contains("System.in")
                || sourceText.contains("new Scanner")
                || sourceText.contains("BufferedReader")
                || sourceText.contains("InputStreamReader")
                || sourceText.contains("readLine(")
                || sourceText.contains("nextInt(")
                || sourceText.contains("nextLine(")
                || sourceText.contains("nextDouble(")
                || sourceText.contains("nextFloat(")
                || sourceText.contains("nextLong(");
    }

