    /**
     * Builds a native Windows executable in a background worker. On success it
     * launches the executable as an interactive Embedded Console process.
     */
    private void compileThenRunNativeExecutable(List<String> compileCommand,
                                                File workingDirectory,
                                                File executable,
                                                String languageLabel,
                                                Charset outputCharset,
                                                Map<String, String> environmentOverrides) {
        setEmbeddedConsoleVisible(true);
        appendConsoleText(embeddedConsoleArea,
                "\n=== " + languageLabel + " Build & Run ===\n"
                        + "Build command: " + commandForDisplay(compileCommand) + "\n"
                        + "Working directory: " + (workingDirectory == null ? System.getProperty("user.dir") : workingDirectory.getAbsolutePath())
                        + "\n------------------------------------------------------------\n");

        Thread worker = new Thread(() -> {
            try {
                ProcessBuilder builder = new ProcessBuilder(compileCommand);
                if (workingDirectory != null) builder.directory(workingDirectory);
                builder.redirectErrorStream(true);
                builder.environment().put("PYTHONIOENCODING", "utf-8");
                if (environmentOverrides != null) {
                    for (Map.Entry<String, String> entry : environmentOverrides.entrySet()) {
                        if (entry.getKey() != null && entry.getValue() != null) {
                            builder.environment().put(entry.getKey(), entry.getValue());
                        }
                    }
                }

                Process process = builder.start();
                byte[] rawOutput = process.getInputStream().readAllBytes();
                int exitCode = process.waitFor();
                DecodeResult decoded = decodeProcessOutput(rawOutput, outputCharset == null ? StandardCharsets.UTF_8 : outputCharset);
                String buildOutput = decoded.text();

                if (exitCode != 0) {
                    appendConsoleText(embeddedConsoleArea,
                            (buildOutput.isBlank() ? "Build failed without compiler output." : buildOutput)
                                    + "\nBuild failed. Exit code: " + exitCode + "\n");
                    SwingUtilities.invokeLater(() -> JOptionPane.showMessageDialog(this,
                            languageLabel + " 編譯失敗。請查看 Embedded Console 的錯誤訊息。",
                            languageLabel + " Build & Run", JOptionPane.ERROR_MESSAGE));
                    return;
                }

                if (!executable.isFile()) {
                    appendConsoleText(embeddedConsoleArea,
                            "Build returned exit code 0, but executable was not created:\n"
                                    + executable.getAbsolutePath() + "\n");
                    SwingUtilities.invokeLater(() -> JOptionPane.showMessageDialog(this,
                            "編譯完成後找不到執行檔：\n" + executable.getAbsolutePath(),
                            languageLabel + " Build & Run", JOptionPane.ERROR_MESSAGE));
                    return;
                }

                SwingUtilities.invokeLater(() -> {
                    startInteractiveConsole(
                            List.of(executable.getAbsolutePath()),
                            workingDirectory,
                            languageLabel + " Run - " + executable.getName(),
                            StandardCharsets.UTF_8,
                            environmentOverrides == null ? Collections.emptyMap() : environmentOverrides
                    );
                    appendConsoleText(embeddedConsoleArea,
                            "Build succeeded: " + executable.getAbsolutePath() + "\n"
                                    + "Use the lower Program stdin input box when the program asks for data.\n\n");
                });
            } catch (IOException ex) {
                appendConsoleText(embeddedConsoleArea, "\n[build start failed] " + ex.getMessage() + "\n");
                SwingUtilities.invokeLater(() -> JOptionPane.showMessageDialog(this,
                        "無法啟動 " + languageLabel + " 編譯器：\n" + ex.getMessage(),
                        languageLabel + " Build & Run", JOptionPane.ERROR_MESSAGE));
            } catch (InterruptedException ex) {
                Thread.currentThread().interrupt();
                appendConsoleText(embeddedConsoleArea, "\n[build interrupted]\n");
            }
        }, "workbench-" + languageLabel.toLowerCase(Locale.ROOT) + "-build-run");
        worker.setDaemon(true);
        worker.start();
    }

