    private void compileCurrentRustFile() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !getFileExtension(tab.file.getName()).equalsIgnoreCase("rs")) {
            JOptionPane.showMessageDialog(this, "請先開啟並儲存 Rust 檔案 (.rs)。", "Rust Compile", JOptionPane.WARNING_MESSAGE);
            return;
        }
        if (!ensureCurrentFileSaved()) return;
        List<String> cargoHomes = getSelectedMsSqlDriverPaths(MSSQL_RUST, "Rust Compile");
        if (cargoHomes == null) return;
        if (!cargoHomes.isEmpty()) {
            File manifest = findCargoManifest(tab.file.getParentFile());
            if (manifest == null) {
                JOptionPane.showMessageDialog(this,
                        "Rust MS SQL support uses the tiberius Cargo crate.\n" +
                                "A Cargo.toml project file is required when Rust MS SQL Auto Link is selected.\n\n" +
                                "Create a Cargo project, add tiberius to Cargo.toml, then run Compile Current again.",
                        "Rust Compile", JOptionPane.WARNING_MESSAGE);
                return;
            }
            executeCommand(List.of("cargo", "build", "--manifest-path", manifest.getAbsolutePath()),
                    manifest.getParentFile(), "Rust Cargo Build (MS SQL)", StandardCharsets.UTF_8, "",
                    createRuntimePathEnvironment("CARGO_HOME", cargoHomes));
            return;
        }
        executeCommand(List.of(getLanguageToolCommand(TOOL_RUST_COMPILER), tab.file.getName(),
                        "-o", removeExtension(tab.file.getName()) + ".exe"),
                tab.file.getParentFile(), "Rust Compile", StandardCharsets.UTF_8);
    }

    /**
     * Compile the current Arduino sketch folder through Arduino CLI.
     * Both .ino and legacy .pde are accepted. Arduino CLI compiles the folder,
     * not an isolated source file, so the sketch root folder must contain a
     * primary <folder-name>.ino (recommended) or <folder-name>.pde file.
     */
    private void compileCurrentArduinoSketch() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !isArduinoSketchExtension(getFileExtension(tab.file.getName()))) {
            JOptionPane.showMessageDialog(this,
                    "請先開啟並儲存 Arduino sketch 檔案 (.ino 或 .pde)。\n\n"
                            + ".pde 是舊式 Arduino sketch 格式；新檔案建議使用 .ino。",
                    "Arduino Compile", JOptionPane.WARNING_MESSAGE);
            return;
        }
        if (!ensureCurrentFileSaved()) return;

        File sketchFolder = tab.file.getParentFile();
        if (!hasArduinoPrimarySketchFile(sketchFolder)) {
            String folderName = sketchFolder == null ? "" : sketchFolder.getName();
            JOptionPane.showMessageDialog(this,
                    "Arduino CLI 編譯的是 Sketch 資料夾，而不是單一檔案。\n\n"
                            + "目前檔案：\n" + tab.file.getAbsolutePath() + "\n\n"
                            + "請將檔案放入名稱相同的 Sketch 資料夾，例如：\n"
                            + "D:\\Arduino\\DTMFTest\\DTMFTest.ino\n"
                            + "或（舊式格式）：\n"
                            + "D:\\Arduino\\DTMFTest\\DTMFTest.pde\n\n"
                            + "目前資料夾必須包含：\n"
                            + folderName + ".ino  或  " + folderName + ".pde",
                    "Arduino Sketch Folder Required", JOptionPane.WARNING_MESSAGE);
            return;
        }

        // Normal Arduino libraries use a dedicated user-library root. This must not
        // depend on the optional MS SQL / Arduino tdslite setting.
        File userLibraryRoot = getArduinoLibraryRootDirectory();
        List<String> msSqlLibraryRoots = getSelectedMsSqlDriverPaths(MSSQL_ARDUINO, "Arduino Compile");
        if (msSqlLibraryRoots == null) return;

        List<String> command = new ArrayList<>();
        command.add(resolveLanguageToolCommandForExecution(
                TOOL_ARDUINO_CLI, getLanguageToolCommand(TOOL_ARDUINO_CLI)));
        command.add("compile");
        command.add("--fqbn");
        command.add(arduinoFqbn);

        // --libraries points at the folder containing library folders, e.g.
        // D:\Arduino\libraries\ADCTouch\src\ADCTouch.h.
        if (userLibraryRoot.isDirectory()) {
            command.add("--libraries");
            command.add(userLibraryRoot.getAbsolutePath());

            // Sketches opened from a library's examples folder need a deterministic
            // direct reference to that exact library as well.
            File directLibrary = findContainingArduinoLibrary(sketchFolder, userLibraryRoot);
            if (directLibrary != null) {
                command.add("--library");
                command.add(directLibrary.getAbsolutePath());
            }
        }

        // Preserve optional MS SQL Arduino driver library roots only when explicitly enabled.
        for (String libraryRoot : msSqlLibraryRoots) {
            command.add("--libraries");
            command.add(libraryRoot);
        }
        command.add(sketchFolder.getAbsolutePath());
        executeCommand(command, sketchFolder, "Arduino Compile", StandardCharsets.UTF_8,
                "", createToolchainRuntimeEnvironment(TOOL_ARDUINO_CLI));
    }

    /** Returns a library folder for a sketch below <library-root>\<library>\examples\... */
    private File findContainingArduinoLibrary(File sketchFolder, File userLibraryRoot) {
        if (sketchFolder == null || userLibraryRoot == null || !userLibraryRoot.isDirectory()) return null;
        try {
            Path rootPath = userLibraryRoot.getCanonicalFile().toPath();
            Path sketchPath = sketchFolder.getCanonicalFile().toPath();
            if (!sketchPath.startsWith(rootPath)) return null;
            Path relative = rootPath.relativize(sketchPath);
            if (relative.getNameCount() < 1) return null;
            File candidate = rootPath.resolve(relative.getName(0)).toFile();
            return new File(candidate, "library.properties").isFile() ? candidate : null;
        } catch (IOException ignored) {
            return null;
        }
    }

    private boolean isArduinoSketchExtension(String extension) {
        return "ino".equalsIgnoreCase(extension) || "pde".equalsIgnoreCase(extension);
    }

    private boolean hasArduinoPrimarySketchFile(File sketchFolder) {
        if (sketchFolder == null || !sketchFolder.isDirectory()) return false;
        String name = sketchFolder.getName();
        return new File(sketchFolder, name + ".ino").isFile()
                || new File(sketchFolder, name + ".pde").isFile();
    }

    private void runCurrentSqlFile() {
        if (blockNewBuildOrRunWhileProgramActive("SQL Run")) return;
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null || !getFileExtension(tab.file.getName()).equalsIgnoreCase("sql")) {
            JOptionPane.showMessageDialog(this, "請先開啟並儲存 SQL 檔案 (.sql)。", "SQL Run", JOptionPane.WARNING_MESSAGE);
            return;
        }
        if (!ensureCurrentFileSaved()) return;
        List<String> sqlcmdPaths = getSelectedMsSqlDriverPaths(MSSQL_SQL, "SQL Run");
        if (sqlcmdPaths == null) return;
        if (!sqlcmdPaths.isEmpty()) {
            List<String> command = new ArrayList<>();
            command.add(sqlcmdPaths.get(0));
            command.add("-S"); command.add(msSqlServer);
            command.add("-d"); command.add(msSqlDatabase);
            if (MS_SQL_AUTH_SQL_LOGIN.equals(msSqlAuthMode)) {
                if (msSqlUser == null || msSqlUser.isBlank()) {
                    JOptionPane.showMessageDialog(this, "Enter a SQL Login User under Settings -> Preference -> MS SQL Driver.", "SQL Run", JOptionPane.WARNING_MESSAGE);
                    return;
                }
                JPasswordField passwordField = new JPasswordField(20);
                int result = JOptionPane.showConfirmDialog(this, passwordField,
                        "Password for " + msSqlUser + " (not saved)", JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
                if (result != JOptionPane.OK_OPTION) return;
                command.add("-U"); command.add(msSqlUser);
                command.add("-P"); command.add(new String(passwordField.getPassword()));
            } else {
                command.add("-E");
            }
            if (msSqlTrustServerCertificate) command.add("-C");
            command.add("-i"); command.add(tab.file.getAbsolutePath());
            executeCommand(command, tab.file.getParentFile(), "SQL Run (Microsoft SQL Server / sqlcmd)", StandardCharsets.UTF_8);
            return;
        }
        String sqlCommand = ".read \"" + tab.file.getAbsolutePath() + "\"";
        executeCommand(List.of(getLanguageToolCommand(TOOL_SQL_CLIENT), sqlDatabaseTarget, sqlCommand),
                tab.file.getParentFile(), "SQL Run (SQLite CLI)", StandardCharsets.UTF_8);
    }

    private void runCurrentFileAuto() {
        if (blockNewBuildOrRunWhileProgramActive("Run Current")) return;
        EditorTab tab = currentTab(); if (tab == null || tab.file == null) { JOptionPane.showMessageDialog(this, "請先開啟並儲存檔案。", "Run", JOptionPane.WARNING_MESSAGE); return; }
        String ext = getFileExtension(tab.file.getName()).toLowerCase();
        switch (ext) {
            case "java" -> { compileCurrentJavaFile(); runCurrentJavaClassInteractive(); }
            case "c" -> runCurrentCFileInteractive();
            case "cpp", "cc", "cxx" -> runCurrentCppFileInteractive();
            case "cs" -> compileCurrentCSharpFile();
            case "py" -> runCurrentPythonFile();
            case "ipynb" -> runCurrentJupyterNotebook();
            case "js", "mjs", "cjs" -> runCurrentJavaScriptFile();
            case "php" -> runCurrentPhpFile();
            case "rs" -> compileCurrentRustFile();
            case "ino", "pde" -> compileCurrentArduinoSketch();
            case "sql" -> runCurrentSqlFile();
            default -> JOptionPane.showMessageDialog(this, "目前副檔名尚未設定自動執行：" + ext, "Run", JOptionPane.INFORMATION_MESSAGE);
        }
    }

    private String removeExtension(String fileName) { int idx = fileName.lastIndexOf('.'); return idx < 0 ? fileName : fileName.substring(0, idx); }

    /**
     * 內嵌 Console：直接顯示在主視窗下方，像 IDE / Notepad++ 外掛 Console 一樣。
     * 不再開啟獨立 JDialog。
     */
    private void startInteractiveConsole(List<String> command, File workingDirectory, String title, Charset ioCharset) {
        startInteractiveConsole(command, workingDirectory, title, ioCharset, Collections.emptyMap());
    }

    /**
     * Starts a process in the Embedded Console. Environment overrides are used by
     * active uv Python projects to provide VIRTUAL_ENV, local PATH and KERAS_BACKEND.
     */
    private void startInteractiveConsole(List<String> command, File workingDirectory, String title,
                                         Charset ioCharset, Map<String, String> environmentOverrides) {
        startInteractiveConsole(command, workingDirectory, title, ioCharset, environmentOverrides, null, null, null);
    }

    /**
     * Variant with lifecycle callbacks.  V0.1.30 uses this for automatic
     * Streamlit dependency setup: only a successful installer exit starts the
     * server; completion always re-enables the IDE controls.
     */
    private void startInteractiveConsole(List<String> command, File workingDirectory, String title,
                                         Charset ioCharset, Map<String, String> environmentOverrides,
                                         Runnable afterSuccessfulExit, Runnable afterCompletion) {
        startInteractiveConsole(command, workingDirectory, title, ioCharset, environmentOverrides,
                afterSuccessfulExit, afterCompletion, null);
    }

    /** V0.1.33 variant: exposes the completed combined output to Python recovery logic. */
    private void startInteractiveConsole(List<String> command, File workingDirectory, String title,
                                         Charset ioCharset, Map<String, String> environmentOverrides,
                                         Runnable afterSuccessfulExit, Runnable afterCompletion,
                                         EmbeddedProcessExitHandler processExitHandler) {
        if (!requireTrialWriteBuildAccess(title)) {
            if (afterCompletion != null) SwingUtilities.invokeLater(afterCompletion);
            return;
        }
        if (isEmbeddedProgramRunning()) {
            appendConsoleText(embeddedConsoleArea,
                    "\n[run blocked] A program is already running. Use Pause / Resume or Stop first.\n");
            Toolkit.getDefaultToolkit().beep();
            return;
        }
        RunCaptureSession captureSession = null;
        try {
            captureSession = createRunCaptureSessionIfSupported(title, command, workingDirectory);
            ProcessBuilder pb = new ProcessBuilder(command);
            if (workingDirectory != null) pb.directory(workingDirectory);
            pb.redirectErrorStream(true);
            Map<String, String> effectiveEnvironment = withAICodingEditorRuntimePath(environmentOverrides);
            applyAICodingEditorRuntimeEnvironment(pb, environmentOverrides);

            final Process process = pb.start();
            final long runToken = ++embeddedRunToken;
            embeddedProcess = process;
            embeddedProcessInput = process.getOutputStream();
            embeddedConsoleCharset = ioCharset == null ? StandardCharsets.UTF_8 : ioCharset;
            embeddedStdinClosed = false;
            embeddedExecutionState = EmbeddedExecutionState.RUNNING;
            activeRunCapture = captureSession;
            if (variableMonitorEnabled) {
                prepareVariableMonitorForRun();
                showVariableMonitorPanel();
            }

            setEmbeddedConsoleVisible(true);
            embeddedConsoleArea.setText("Command: " + commandForDisplay(command)
                    + "\nWorking directory: " + (workingDirectory == null ? System.getProperty("user.dir") : workingDirectory.getAbsolutePath())
                    + "\nInteractive I/O charset: " + embeddedConsoleCharset.name()
                    + (effectiveEnvironment.isEmpty()
                            ? "" : "\nEnvironment overrides: " + effectiveEnvironment.keySet())
                    + "\nBundled toolchain PATH: " + bundledToolchainPathSummary()
                    + "\n------------------------------------------------------------\n"
                    + "Embedded Console started.\n"
                    + "Use Program stdin for input. During execution: Play is red, Pause || is green, Stop ■ is green.\n"
                    + "Pause || suspends the current process; click it again to resume. Stop ■ force-stops the process tree.\n"
                    + (captureSession == null ? "" : "[Data Capture] I/O, recognised variables, table files and figures will be saved after exit: \n"
                            + captureSession.reportDirectory.toAbsolutePath() + "\n")
                    + "\n");

            embeddedConsoleInputLabel.setText(tr("程式標準輸入:", "Program stdin:"));
            embeddedConsoleInput.setEnabled(true);
            embeddedConsoleSendButton.setEnabled(true);
            embeddedConsoleCloseInputButton.setEnabled(true);
            updateEmbeddedExecutionControls();
            if (variableMonitorEnabled) {
                executionBottomTabs.setSelectedComponent(variableMonitorPanel);
            }
            embeddedConsoleInput.requestFocusInWindow();

            final RunCaptureSession runCaptureSession = captureSession;
            Thread outputThread = new Thread(() -> {
                try (java.io.Reader reader = new java.io.InputStreamReader(process.getInputStream(), embeddedConsoleCharset)) {
                    char[] buffer = new char[1024];
                    int n;
                    while ((n = reader.read(buffer)) != -1) {
                        String outputChunk = new String(buffer, 0, n);
                        if (runCaptureSession != null) {
                            java.util.List<CaptureEntry> detected = runCaptureSession.recordOutputChunkAndExtractVariables(outputChunk);
                            handleLiveVariableTelemetry(detected);
                        }
                        appendConsoleText(embeddedConsoleArea, outputChunk);
                    }
                } catch (IOException ex) {
                    if (process.isAlive()) {
                        appendConsoleText(embeddedConsoleArea, "\n[output read failed] " + ex.getMessage() + "\n");
                    }
                }
            }, "embedded-console-output-reader");
            outputThread.setDaemon(true);
            outputThread.start();

            Thread waitThread = new Thread(() -> {
                try {
                    int exitCode = process.waitFor();
                    // Wait briefly for the redirected output reader to drain the closed pipe.
                    // This makes ModuleNotFoundError diagnostics available to V0.1.33 recovery.
                    try { outputThread.join(1500L); }
                    catch (InterruptedException joinInterrupted) { Thread.currentThread().interrupt(); }
                    File captureReport = null;
                    String captureError = null;
                    if (runCaptureSession != null) {
                        try {
                            captureReport = runCaptureSession.finish(exitCode);
                        } catch (Exception reportEx) {
                            captureError = reportEx.getMessage();
                        }
                    }
                    final File finalCaptureReport = captureReport;
                    final String finalCaptureError = captureError;
                    final String finalCombinedOutput = runCaptureSession == null
                            ? "" : runCaptureSession.getCapturedOutputSnapshot();
                    SwingUtilities.invokeLater(() -> {
                        if (runToken != embeddedRunToken) return;
                        closeEmbeddedStdinSilently();
                        if (activeRunCapture == runCaptureSession) activeRunCapture = null;
                        embeddedProcess = null;
                        embeddedProcessInput = null;
                        embeddedExecutionState = EmbeddedExecutionState.IDLE;
                        embeddedConsoleInputLabel.setText(tr("命令 / 標準輸入:", "Command / stdin:"));
                        embeddedConsoleInput.setEnabled(true);
                        embeddedConsoleSendButton.setEnabled(true);
                        embeddedConsoleCloseInputButton.setEnabled(false);
                        updateEmbeddedExecutionControls();
                        appendConsoleText(embeddedConsoleArea,
                                "\n\nExit code: " + exitCode
                                        + (finalCaptureReport == null ? "" : "\n[Data Capture] Excel report: " + finalCaptureReport.getAbsolutePath())
                                        + (finalCaptureError == null ? "" : "\n[Data Capture warning] " + finalCaptureError)
                                        + "\n[Command mode ready. Type help for Workbench console commands.]\n");
                        if (processExitHandler != null) {
                            try { processExitHandler.onProcessExit(exitCode, finalCombinedOutput); }
                            catch (RuntimeException callbackError) {
                                appendConsoleText(embeddedConsoleArea,
                                        "[process completion handler failed] " + callbackError.getMessage() + "\n");
                            }
                        }
                        if (afterCompletion != null) {
                            try { afterCompletion.run(); }
                            catch (RuntimeException callbackError) {
                                appendConsoleText(embeddedConsoleArea,
                                        "[completion callback failed] " + callbackError.getMessage() + "\n");
                            }
                        }
                        if (exitCode == 0 && afterSuccessfulExit != null) {
                            try { afterSuccessfulExit.run(); }
                            catch (RuntimeException callbackError) {
                                appendConsoleText(embeddedConsoleArea,
                                        "[success callback failed] " + callbackError.getMessage() + "\n");
                            }
                        }
                    });
                } catch (InterruptedException ex) {
                    Thread.currentThread().interrupt();
                    appendConsoleText(embeddedConsoleArea, "\n[console wait interrupted]\n");
                }
            }, "embedded-console-process-waiter");
            waitThread.setDaemon(true);
            waitThread.start();
        } catch (IOException ex) {
            if (activeRunCapture == captureSession) activeRunCapture = null;
            embeddedExecutionState = EmbeddedExecutionState.IDLE;
            updateEmbeddedExecutionControls();
            if (afterCompletion != null) {
                SwingUtilities.invokeLater(() -> {
                    try { afterCompletion.run(); } catch (RuntimeException ignored) {}
                });
            }
            JOptionPane.showMessageDialog(this, "Unable to start Embedded Console:\n" + commandForDisplay(command)
                            + "\n\nPossible causes: tool is missing, PATH is not set, or the class has not been compiled.\n" + ex.getMessage(),
                    title, JOptionPane.ERROR_MESSAGE);
        }
    }

    private void createAdditionalEmbeddedConsole() {
        if (!requireTrialWriteBuildAccess("New Embedded Console")) return;
        int number = ++extraEmbeddedConsoleCounter;
        ExtraEmbeddedConsole console = new ExtraEmbeddedConsole(number);
        extraEmbeddedConsoles.add(console);
        addExecutionBottomTab(console.panel,
                tr("嵌入式控制台 ", "Embedded Console ") + number,
                tr("額外嵌入式控制台，可執行獨立命令", "Additional embedded console for independent commands"));
        expandExecutionBottomArea(console.panel);
        console.input.requestFocusInWindow();
    }

    private final class ExtraEmbeddedConsole {
        final int number;
        final JPanel panel = new JPanel(new BorderLayout(6, 6));
        final JTextArea output = new JTextArea();
        final JTextField input = new JTextField();
        final JButton send = new JButton();
        final JButton clear = new JButton();
        final JButton stop = new JButton();
        volatile Process process;

        ExtraEmbeddedConsole(int number) {
            this.number = number;
            panel.setOpaque(true);
            panel.setBackground(APP_MENU_BACKGROUND);
            panel.setBorder(BorderFactory.createMatteBorder(1, 0, 0, 0, APP_BORDER_COLOR));
            JLabel title = new JLabel(" " + tr("嵌入式控制台 ", "Embedded Console ") + number);
            title.setOpaque(true); title.setBackground(APP_MENU_BACKGROUND); title.setForeground(APP_MENU_FOREGROUND);
            title.setBorder(BorderFactory.createEmptyBorder(4, 6, 4, 6));
            panel.add(title, BorderLayout.NORTH);

            output.setEditable(false);
            output.setFont(new Font("Monospaced", Font.PLAIN, 13));
            output.setLineWrap(true);
            output.setWrapStyleWord(false);
            output.setBackground(editorBackgroundColor);
            output.setForeground(editorTextColor);
            output.setCaretColor(editorTextColor);
            output.setBorder(BorderFactory.createEmptyBorder(6, 6, 6, 6));
            output.setText(tr("額外嵌入式控制台已建立。輸入命令後按 Enter 或送出。\n",
                    "Additional embedded console created. Type a command and press Enter or Send.\n"));
            JScrollPane scroll = new JScrollPane(output);
            scroll.getViewport().setBackground(editorBackgroundColor);
            scroll.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
            panel.add(scroll, BorderLayout.CENTER);

            input.setFont(new Font("Monospaced", Font.PLAIN, 13));
            input.setUI(new BasicTextFieldUI());
            input.setOpaque(true); input.setBackground(Color.BLACK); input.setForeground(Color.WHITE); input.setCaretColor(Color.WHITE);
            input.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
            input.addActionListener(e -> runCommand());

            send.setText(tr("送出 / Enter", "Send / Enter"));
            clear.setText(tr("清除", "Clear"));
            stop.setText(tr("停止", "Stop"));
            for (JButton b : new JButton[]{send, clear, stop}) { styleDarkButton(b); b.setFocusable(false); }
            send.addActionListener(e -> runCommand());
            clear.addActionListener(e -> output.setText(""));
            stop.addActionListener(e -> {
                Process p = process;
                if (p != null && p.isAlive()) {
                    output.append("\n[stop requested]\n");
                    try { p.destroyForcibly(); } catch (Exception ignored) {}
                } else {
                    closeExecutionBottomTab(panel);
                }
            });

            JPanel bottom = new JPanel(new BorderLayout(6, 6));
            bottom.setOpaque(true); bottom.setBackground(APP_MENU_BACKGROUND);
            bottom.setBorder(BorderFactory.createEmptyBorder(6, 6, 6, 6));
            JLabel label = new JLabel(tr("命令:", "Command:"));
            label.setForeground(APP_MENU_FOREGROUND);
            bottom.add(label, BorderLayout.WEST);
            bottom.add(input, BorderLayout.CENTER);
            JPanel buttons = new JPanel(new FlowLayout(FlowLayout.RIGHT, 6, 0));
            buttons.setOpaque(true); buttons.setBackground(APP_MENU_BACKGROUND);
            buttons.add(send); buttons.add(clear); buttons.add(stop);
            bottom.add(buttons, BorderLayout.EAST);
            panel.add(bottom, BorderLayout.SOUTH);
        }

        void runCommand() {
            String command = input.getText() == null ? "" : input.getText().trim();
            if (command.isEmpty()) return;
            if (process != null && process.isAlive()) {
                output.append("\n[a command is still running]\n");
                return;
            }
            input.setText("");
            output.append("\n> " + command + "\n");
            UvPythonProject project = activeUvPythonProject;
            File workingDirectory = project != null ? project.rootDirectory : getPythonWorkingDirectory();
            Map<String, String> environment = createUvProjectEnvironment(project);
            java.util.List<String> cmd;
            try {
                if (isWindowsPlatform()) {
                    // V0.2.37-24: match the primary console behavior.  Running through
                    // a temporary UTF-8 .cmd file avoids mojibake for Chinese file names
                    // and command output in console 2, 3, ...
                    File script = Files.createTempFile("AICodingEditor_ExtraConsole_", ".cmd").toFile();
                    script.deleteOnExit();
                    Files.writeString(script.toPath(),
                            "@echo off\r\n"
                                    + "chcp 65001>nul\r\n"
                                    + command + "\r\n",
                            StandardCharsets.UTF_8, StandardOpenOption.TRUNCATE_EXISTING);
                    cmd = java.util.List.of("cmd.exe", "/d", "/s", "/c",
                            "call \"" + script.getAbsolutePath() + "\"");
                } else {
                    cmd = java.util.List.of("/bin/sh", "-lc", command);
                }
            } catch (IOException ex) {
                output.append("\n[command script failed] " + ex.getMessage() + "\n");
                return;
            }
            Thread t = new Thread(() -> {
                try {
                    ProcessBuilder pb = new ProcessBuilder(cmd);
                    if (workingDirectory != null) pb.directory(workingDirectory);
                    pb.redirectErrorStream(true);
                    applyAICodingEditorRuntimeEnvironment(pb, environment);
                    process = pb.start();
                    try (java.io.Reader reader = new java.io.InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8)) {
                        char[] buf = new char[1024]; int n;
                        while ((n = reader.read(buf)) != -1) {
                            String chunk = new String(buf, 0, n);
                            SwingUtilities.invokeLater(() -> { output.append(chunk); output.setCaretPosition(output.getDocument().getLength()); });
                        }
                    }
                    int exit = process.waitFor();
                    SwingUtilities.invokeLater(() -> output.append("\n[Exit code: " + exit + "]\n"));
                } catch (Exception ex) {
                    SwingUtilities.invokeLater(() -> output.append("\n[command failed] " + ex.getMessage() + "\n"));
                } finally {
                    process = null;
                }
            }, "extra-embedded-console-" + number);
            t.setDaemon(true);
            t.start();
        }
    }

