        embeddedConsoleArea.setEditable(false);
        embeddedConsoleArea.setFont(new Font("Monospaced", Font.PLAIN, 13));
        embeddedConsoleArea.setLineWrap(true);
        embeddedConsoleArea.setWrapStyleWord(false);
        embeddedConsoleArea.setBackground(editorBackgroundColor);
        embeddedConsoleArea.setForeground(editorTextColor);
