    private void loadVariableMonitorPreferences() {
        // V0.2.37-20: do not auto-enable or auto-open live telemetry at startup.
        // Users must explicitly enable it in the current session before the Variable Monitor tab appears.
        variableMonitorEnabled = false;
        preferences.putBoolean(VARIABLE_MONITOR_ENABLED_PREFERENCE_KEY, false);
        String saved = preferences.get(VARIABLE_MONITOR_SELECTION_PREFERENCE_KEY, "");
        if (saved != null && !saved.isBlank()) {
            for (String part : saved.split(",")) {
                String name = part.trim();
                if (!name.isEmpty()) variableMonitorSelectedNames.add(name);
            }
        }
    }

    private void setVariableMonitorEnabled(boolean enabled) {
        variableMonitorEnabled = enabled;
        preferences.putBoolean(VARIABLE_MONITOR_ENABLED_PREFERENCE_KEY, enabled);
        if (variableMonitorEnableCheckBox != null) {
            variableMonitorEnableCheckBox.setSelected(enabled);
            variableMonitorEnableCheckBox.setBackground(enabled ? new Color(0, 91, 150) : APP_MENU_ITEM_BACKGROUND);
        }
        variableMonitorStatusLabel.setText(enabled
                ? tr("已啟用：執行時會即時擷取所選變數。", "Enabled: selected variables are captured during execution.")
                : tr("未啟用：仍會在程式結束後產生 I/O 與資料報表。", "Disabled: I/O and data reports are still generated after a program ends."));
        if (enabled) showVariableMonitorPanel();
    }

    private void saveVariableMonitorSelection() {
        preferences.put(VARIABLE_MONITOR_SELECTION_PREFERENCE_KEY,
                String.join(",", variableMonitorSelectedNames));
    }

