    private void showVariableMonitorPanel() {
        if (!variableMonitorEnabled) {
            setVariableMonitorEnabled(true);
            return;
        }
        reopenVariableMonitorPanel();
    }

    private void chooseVariableMonitorVariables() {
        LinkedHashSet<String> candidates = new LinkedHashSet<>();
        candidates.addAll(detectVariableNamesFromCurrentSource());
        candidates.addAll(variableMonitorLatest.keySet());
        candidates.addAll(variableMonitorSamples.keySet());
        candidates.addAll(variableMonitorSelectedNames);
        java.util.List<String> ordered = new ArrayList<>(candidates);
        ordered.sort(String.CASE_INSENSITIVE_ORDER);

        JList<String> list = new JList<>(ordered.toArray(new String[0]));
        list.setSelectionMode(ListSelectionModel.MULTIPLE_INTERVAL_SELECTION);
        java.util.List<Integer> selectedIndices = new ArrayList<>();
        for (int i = 0; i < ordered.size(); i++) if (variableMonitorSelectedNames.contains(ordered.get(i))) selectedIndices.add(i);
        list.setSelectedIndices(selectedIndices.stream().mapToInt(Integer::intValue).toArray());
        list.setBackground(Color.BLACK); list.setForeground(Color.WHITE);
        list.setSelectionBackground(FILE_TREE_SELECTION_BACKGROUND); list.setSelectionForeground(Color.WHITE);

        JTextField custom = new JTextField();
        custom.setBackground(new Color(28, 28, 28)); custom.setForeground(Color.WHITE); custom.setCaretColor(Color.WHITE);
        custom.setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        JLabel hint = new JLabel(tr(
                "從清單選取，或輸入其他變數名稱（以逗號分隔）。空白代表監測所有可辨識輸出變數。\n"
                        + "即時監測要求程式輸出 AICE_VAR name=value、name=value，或單行 JSON。",
                "Select names from the list or enter extra names separated by commas. Empty means monitor every recognised output variable.\n"
                        + "Live monitoring requires AICE_VAR name=value, name=value, or one-line JSON output."));
        hint.setForeground(new Color(230, 230, 230));
        JPanel content = new JPanel(new BorderLayout(6, 6));
        content.setBackground(APP_MENU_BACKGROUND);
        content.setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10));
        content.add(hint, BorderLayout.NORTH);
        JScrollPane scroll = new JScrollPane(list);
        scroll.setPreferredSize(new Dimension(500, 190));
        content.add(scroll, BorderLayout.CENTER);
        JPanel customPanel = new JPanel(new BorderLayout(6, 4));
        customPanel.setBackground(APP_MENU_BACKGROUND);
        JLabel customLabel = new JLabel(tr("其他變數：", "Additional variables:"));
        customLabel.setForeground(APP_MENU_FOREGROUND);
        customPanel.add(customLabel, BorderLayout.WEST); customPanel.add(custom, BorderLayout.CENTER);
        content.add(customPanel, BorderLayout.SOUTH);
        int result = JOptionPane.showConfirmDialog(this, content,
                tr("選擇即時監測變數", "Select Live Monitor Variables"),
                JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
        if (result != JOptionPane.OK_OPTION) return;
        variableMonitorSelectedNames.clear();
        variableMonitorSelectedNames.addAll(list.getSelectedValuesList());
        String extra = custom.getText();
        if (extra != null) {
            for (String token : extra.split(",")) {
                String name = token.trim();
                if (!name.isEmpty()) variableMonitorSelectedNames.add(name);
            }
        }
        saveVariableMonitorSelection();
        refreshVariableMonitorTable();
        variableMonitorStatusLabel.setText(variableMonitorSelectedNames.isEmpty()
                ? tr("已選擇：所有可辨識輸出變數。", "Selected: all recognised output variables.")
                : tr("已選擇變數：", "Selected variables: ") + String.join(", ", variableMonitorSelectedNames));
    }

    private java.util.List<String> detectVariableNamesFromCurrentSource() {
        LinkedHashSet<String> values = new LinkedHashSet<>();
        EditorTab tab = currentTab();
        if (tab == null) return new ArrayList<>();
        String source = tab.textPane.getText();
        Pattern assigned = Pattern.compile("(?m)^\\s*(?:final\\s+|const\\s+|let\\s+|var\\s+)?(?:int|long|double|float|boolean|String|char|auto|var|def)?\\s*([A-Za-z_][A-Za-z0-9_]*)\\s*=");
        Matcher matcher = assigned.matcher(source);
        while (matcher.find()) values.add(matcher.group(1));
        Pattern explicit = Pattern.compile("AICE_VAR\\s+([A-Za-z_][A-Za-z0-9_.-]{0,120})\\s*=");
        matcher = explicit.matcher(source);
        while (matcher.find()) values.add(matcher.group(1));
        return new ArrayList<>(values);
    }

    private void prepareVariableMonitorForRun() {
        clearVariableMonitorData();
        variableMonitorStatusLabel.setText(variableMonitorSelectedNames.isEmpty()
                ? tr("監測中：所有可辨識輸出變數。", "Monitoring: all recognised output variables.")
                : tr("監測中：", "Monitoring: ") + String.join(", ", variableMonitorSelectedNames));
    }

    private void clearVariableMonitorData() {
        variableMonitorLatest.clear();
        variableMonitorSamples.clear();
        variableMonitorChartSelector.removeAllItems();
        refreshVariableMonitorTable();
        variableMonitorWavePanel.repaint();
    }

    private void handleLiveVariableTelemetry(java.util.List<CaptureEntry> entries) {
        if (!variableMonitorEnabled || entries == null || entries.isEmpty()) return;
        boolean changed = false;
        for (CaptureEntry entry : entries) {
            if (entry == null || entry.name == null || entry.name.isBlank()) continue;
            if (!variableMonitorSelectedNames.isEmpty() && !variableMonitorSelectedNames.contains(entry.name)) continue;
            variableMonitorLatest.put(entry.name, entry);
            Double numeric = parseNumericTelemetry(entry.value);
            if (numeric != null) {
                java.util.List<LiveVariableSample> samples = variableMonitorSamples.computeIfAbsent(entry.name, k -> new ArrayList<>());
                samples.add(new LiveVariableSample(System.currentTimeMillis(), numeric));
                if (VARIABLE_MONITOR_MAX_SAMPLES_PER_VARIABLE > 0
                        && samples.size() > VARIABLE_MONITOR_MAX_SAMPLES_PER_VARIABLE) {
                    samples.remove(0);
                }
            }
            changed = true;
        }
        if (!changed) return;
        SwingUtilities.invokeLater(() -> {
            refreshVariableMonitorTable();
            String current = (String) variableMonitorChartSelector.getSelectedItem();
            if (current == null || !variableMonitorSamples.containsKey(current)) {
                for (String name : variableMonitorSamples.keySet()) {
                    variableMonitorChartSelector.setSelectedItem(name);
                    break;
                }
            }
            variableMonitorWavePanel.repaint();
        });
    }

    private Double parseNumericTelemetry(String raw) {
        if (raw == null) return null;
        String value = raw.trim().replace(",", "");
        if (value.endsWith("%")) value = value.substring(0, value.length() - 1).trim();
        try { return Double.valueOf(value); } catch (Exception ignored) { return null; }
    }

    private void refreshVariableMonitorTable() {
        if (!SwingUtilities.isEventDispatchThread()) {
            SwingUtilities.invokeLater(this::refreshVariableMonitorTable);
            return;
        }
        variableMonitorTableModel.setRowCount(0);
        LinkedHashSet<String> names = new LinkedHashSet<>();
        if (!variableMonitorSelectedNames.isEmpty()) names.addAll(variableMonitorSelectedNames);
        names.addAll(variableMonitorLatest.keySet());
        names.addAll(variableMonitorSamples.keySet());
        for (String name : names) {
            CaptureEntry latest = variableMonitorLatest.get(name);
            java.util.List<LiveVariableSample> samples = variableMonitorSamples.get(name);
            variableMonitorTableModel.addRow(new Object[]{
                    name,
                    latest == null ? "" : latest.value,
                    samples == null ? 0 : samples.size(),
                    latest == null ? "" : latest.timestamp,
                    latest == null ? "" : latest.source
            });
            boolean found = false;
            for (int i = 0; i < variableMonitorChartSelector.getItemCount(); i++) {
                if (name.equals(variableMonitorChartSelector.getItemAt(i))) { found = true; break; }
            }
            if (!found && samples != null && !samples.isEmpty()) variableMonitorChartSelector.addItem(name);
        }
    }

    private void setVariableMonitorChartSelection(String name) {
        if (name == null || name.isBlank()) return;
        variableMonitorChartSelector.setSelectedItem(name);
        variableMonitorWavePanel.repaint();
    }

    private static final class LiveVariableSample {
        final long timestampMillis;
        final double value;
        LiveVariableSample(long timestampMillis, double value) {
            this.timestampMillis = timestampMillis;
            this.value = value;
        }
    }

    private final class LiveWavePanel extends JPanel {
        LiveWavePanel() {
            setOpaque(true);
            setBackground(Color.BLACK);
            setBorder(BorderFactory.createLineBorder(APP_BORDER_COLOR));
        }
        @Override protected void paintComponent(Graphics graphics) {
            super.paintComponent(graphics);
            Graphics2D g = (Graphics2D) graphics.create();
            try {
                int w = getWidth(), h = getHeight();
                g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
                String selected = (String) variableMonitorChartSelector.getSelectedItem();
                java.util.List<LiveVariableSample> samples = selected == null ? null : variableMonitorSamples.get(selected);
                g.setColor(new Color(170, 180, 190));
                g.setFont(new Font("SansSerif", Font.PLAIN, 12));
                if (samples == null || samples.isEmpty()) {
                    g.drawString(tr("尚無數值樣本。啟用監測後，讓程式輸出 AICE_VAR name=value。", "No numeric samples yet. Enable monitoring and print AICE_VAR name=value."), 16, 28);
                    return;
                }
                int left = 58, right = 18, top = 22, bottom = 39;
                int plotW = Math.max(1, w - left - right), plotH = Math.max(1, h - top - bottom);
                double min = Double.POSITIVE_INFINITY, max = Double.NEGATIVE_INFINITY;
                long firstTime = samples.get(0).timestampMillis;
                long lastTime = samples.get(samples.size() - 1).timestampMillis;
                for (LiveVariableSample sample : samples) { min = Math.min(min, sample.value); max = Math.max(max, sample.value); }
                if (Math.abs(max - min) < 1e-12) { min -= 1.0; max += 1.0; }
                double pad = (max - min) * 0.08; min -= pad; max += pad;
                g.setColor(new Color(50, 55, 62));
                for (int i = 0; i <= 4; i++) {
                    int y = top + (int) Math.round(i * (double) plotH / 4.0);
                    g.drawLine(left, y, left + plotW, y);
                    g.setColor(new Color(180, 185, 190));
                    double label = max - i * (max - min) / 4.0;
                    g.drawString(String.format(Locale.ROOT, "%.5g", label), 4, y + 4);
                    g.setColor(new Color(50, 55, 62));
                }
                g.setColor(new Color(165, 230, 180));
                g.setFont(new Font("SansSerif", Font.BOLD, 13));
                double elapsedSeconds = Math.max(0.0, (lastTime - firstTime) / 1000.0);
                g.drawString(selected + "  (" + samples.size() + " samples, " + String.format(Locale.ROOT, "%.1f s", elapsedSeconds) + ")", left, 16);
                g.setStroke(new BasicStroke(2.0f));
                int px = -1, py = -1;
                int stride = Math.max(1, samples.size() / 5_000);
                long durationMillis = Math.max(1L, lastTime - firstTime);
                for (int i = 0; i < samples.size(); i += stride) {
                    LiveVariableSample sample = samples.get(i);
                    int x = left + (int) Math.round((sample.timestampMillis - firstTime) * (double) plotW / durationMillis);
                    int y = top + (int) Math.round((max - sample.value) * plotH / (max - min));
                    if (px >= 0) g.drawLine(px, py, x, y);
                    px = x; py = y;
                }
                if (samples.size() > 1 && (samples.size() - 1) % stride != 0) {
                    LiveVariableSample sample = samples.get(samples.size() - 1);
                    int x = left + (int) Math.round((sample.timestampMillis - firstTime) * (double) plotW / durationMillis);
                    int y = top + (int) Math.round((max - sample.value) * plotH / (max - min));
                    if (px >= 0) g.drawLine(px, py, x, y);
                }
                g.setColor(new Color(180, 185, 190));
                g.setFont(new Font("SansSerif", Font.PLAIN, 11));
                String startLabel = "0 s";
                String endLabel = String.format(Locale.ROOT, "%.1f s", elapsedSeconds);
                g.drawString(startLabel, left, h - 10);
                FontMetrics fm = g.getFontMetrics();
                g.drawString(endLabel, left + plotW - fm.stringWidth(endLabel), h - 10);
                String label = tr("連續執行時間 →", "Elapsed run time →");
                g.drawString(label, left + Math.max(0, (plotW - fm.stringWidth(label)) / 2), h - 10);
            } finally { g.dispose(); }
        }
    }

