    /** Opens the variable/report folder for the active saved source file. */
    private void openCurrentVariableReportFolder() {
        EditorTab tab = currentTab();
        if (tab == null || tab.file == null) {
            JOptionPane.showMessageDialog(this,
                    tr("請先開啟並儲存一個程式檔案。", "Open and save a program file first."),
                    tr("資料擷取與報表", "Data Capture & Reports"), JOptionPane.INFORMATION_MESSAGE);
            return;
        }
        File folder = new File(tab.file.getParentFile(), DATA_CAPTURE_ROOT_FOLDER);
        if (!folder.isDirectory() && !folder.mkdirs()) {
            JOptionPane.showMessageDialog(this,
                    tr("無法建立 variable 資料夾：\n", "Unable to create variable folder:\n") + folder.getAbsolutePath(),
                    tr("資料擷取與報表", "Data Capture & Reports"), JOptionPane.ERROR_MESSAGE);
            return;
        }
        try {
            if (Desktop.isDesktopSupported() && Desktop.getDesktop().isSupported(Desktop.Action.OPEN)) {
                Desktop.getDesktop().open(folder);
            } else {
                JOptionPane.showMessageDialog(this, folder.getAbsolutePath(),
                        tr("variable 資料夾", "variable Folder"), JOptionPane.INFORMATION_MESSAGE);
            }
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                    tr("無法開啟資料夾：\n", "Unable to open folder:\n") + folder.getAbsolutePath() + "\n\n" + ex.getMessage(),
                    tr("資料擷取與報表", "Data Capture & Reports"), JOptionPane.WARNING_MESSAGE);
        }
    }

